window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["nicet-water-based"] = [
  {id:1, block:1, sec:"Symbols & Drawing Conventions", q:"On fire sprinkler shop drawings, what does a circle with the deflector shown pointing downward typically represent?", opts:["An upright sprinkler","A pendent sprinkler","A flow switch","A check valve"], correct:1, re:"A pendent sprinkler discharges downward and hangs below the branch line, so its symbol shows the deflector oriented down. Ref: NFPA 170 fire-protection symbols; NFPA 13 sprinkler-orientation definitions."},
  {id:2, block:1, sec:"Symbols & Drawing Conventions", q:"Which standard establishes the standardized graphic symbols used for fire safety and fire protection drawings in the United States?", opts:["NFPA 25","NFPA 170","NFPA 72","NFPA 20"], correct:1, re:"NFPA 170, Standard for Fire Safety and Emergency Symbols, defines the standardized symbols used on fire protection plans. Ref: NFPA 170."},
  {id:3, block:1, sec:"Symbols & Drawing Conventions", q:"An upright sprinkler is installed so that water sprays:", opts:["Downward from below the branch line","Upward and is deflected back down by the deflector","Horizontally only","Directly against a wall"], correct:1, re:"An upright sprinkler sits above the branch line; water shoots up and the deflector redirects it down and out in a hemispherical pattern. Ref: NFPA 13, sprinkler-type definitions."},
  {id:4, block:1, sec:"Symbols & Drawing Conventions", q:"On a sprinkler plan, the abbreviation 'FDC' marks which component?", opts:["Fire department connection","Flexible drop coupling","Floor drain cleanout","Fixed deluge controller"], correct:0, re:"FDC stands for fire department connection, the exterior inlet through which the fire department pumps water into the system. Ref: NFPA 13; NFPA 170 abbreviations."},
  {id:5, block:1, sec:"Symbols & Drawing Conventions", q:"A sidewall sprinkler is selected on a plan primarily when:", opts:["The ceiling is more than 30 ft high","Mounting in the ceiling is impractical and the sprinkler must throw water from a wall","The area is a freezer","Only upright heads are available"], correct:1, re:"Sidewall sprinklers mount on a wall and project water across a room, used where ceiling piping is impractical such as small rooms and corridors. Ref: NFPA 13, sidewall sprinkler use."},
  {id:6, block:1, sec:"Symbols & Drawing Conventions", q:"On shop drawings, a line crossed by a short perpendicular tick with a circle commonly denotes:", opts:["A pipe size change","A control valve","A sprinkler head only","A wall penetration"], correct:1, re:"Valve symbols are placed inline on the pipe run on shop drawings; the legend defines each valve type. Ref: NFPA 170 symbol legend; project drawing legend."},
  {id:7, block:1, sec:"Symbols & Drawing Conventions", q:"Every set of sprinkler shop drawings should include which item to define the meaning of each symbol used?", opts:["A symbol legend","A soils report","A fire alarm matrix","An OSHA log"], correct:0, re:"A legend (symbol list) on the drawings identifies what each symbol and abbreviation means so reviewers and installers interpret the plan consistently. Ref: NFPA 13 working-plan requirements."},
  {id:8, block:1, sec:"Symbols & Drawing Conventions", q:"A dashed (hidden) line on a sprinkler plan most commonly indicates:", opts:["An object above or below the plane of the drawing / hidden from view","An electrical circuit","A property line","A required note"], correct:0, re:"Hidden/dashed lines represent edges or piping not directly visible in the current view, such as items above the ceiling or below the floor. Ref: standard drafting convention; ASME/architectural line conventions."},
  {id:9, block:1, sec:"Symbols & Drawing Conventions", q:"On a plan, 'ITC' or 'inspector's test' identifies the connection used to:", opts:["Refill the system with antifreeze","Simulate the flow of one sprinkler to test the waterflow alarm","Connect the city main","Vent trapped air automatically"], correct:1, re:"The inspector's test connection has an orifice matching one sprinkler and is used to verify waterflow alarm operation. Ref: NFPA 13; NFPA 25 testing."},
  {id:10, block:1, sec:"Symbols & Drawing Conventions", q:"A concealed sprinkler is shown on plans with a notation indicating it is:", opts:["Installed above the ceiling and hidden by a cover plate","Always an extra-large orifice","Only for outdoor use","Painted red"], correct:0, re:"Concealed sprinklers sit recessed above the ceiling line behind a flush cover plate that drops away in a fire. Ref: NFPA 13, concealed sprinkler definition."},
  {id:11, block:1, sec:"Symbols & Drawing Conventions", q:"On sprinkler plans, the term 'riser' refers to:", opts:["The vertical supply pipe with associated valves serving the system","A diagonal brace","The branch line nearest the wall","The roof drain"], correct:0, re:"The riser is the vertical pipe (with control valve, gauges, alarm device, and main drain) that supplies the system from the source. Ref: NFPA 13, system riser definition."},
  {id:12, block:1, sec:"Symbols & Drawing Conventions", q:"A north arrow is placed on a sprinkler floor plan primarily to:", opts:["Indicate the system's design density","Establish drawing orientation relative to the building","Show pipe slope direction","Mark the FDC location"], correct:1, re:"The north arrow orients the plan so the reader can relate the drawing to the actual building and other sheets. Ref: standard drafting/working-plan convention."},
  {id:13, block:1, sec:"Symbols & Drawing Conventions", q:"On a plan, pipe sizes are most commonly indicated by:", opts:["Color only","A numeric callout next to the pipe (e.g., 2\")","The line weight alone","A north arrow"], correct:1, re:"Pipe diameters are labeled with numeric callouts along each run so the installer knows the size of each segment. Ref: NFPA 13 working plans; drawing conventions."},
  {id:14, block:1, sec:"Symbols & Drawing Conventions", q:"The symbol for a check valve on a sprinkler plan represents a device that:", opts:["Allows flow in one direction only","Reduces pressure","Measures temperature","Drains the system"], correct:0, re:"A check valve permits water to flow one direction and prevents reverse flow, protecting the supply from contamination. Ref: NFPA 13 valve requirements; NFPA 170."},
  {id:15, block:1, sec:"Symbols & Drawing Conventions", q:"On hydraulic plans, a small flag or reference node number at a fitting is used to:", opts:["Identify a calculation reference point along the flow path","Mark a sprinkler temperature rating","Indicate paint color","Show the property boundary"], correct:0, re:"Hydraulic reference (node) points are numbered so each junction can be tied to the hydraulic calculation sheet. Ref: NFPA 13 hydraulic calculation procedures."},
  {id:16, block:1, sec:"Symbols & Drawing Conventions", q:"A 'sprig' shown on a plan or riser detail is:", opts:["A short vertical pipe rising to an upright sprinkler above a main","A horizontal cross main","A type of hanger","A drain fitting"], correct:0, re:"A sprig-up is a short pipe nipple that rises from a branch line to feed an upright sprinkler positioned above. Ref: NFPA 13, sprig definition."},
  {id:17, block:1, sec:"Symbols & Drawing Conventions", q:"When a sprinkler plan shows a 'tamper switch' symbol on a valve, it monitors:", opts:["Water temperature","Whether the valve is open or closed (supervisory)","The pipe wall thickness","Antifreeze concentration"], correct:1, re:"A valve tamper (supervisory) switch signals if a control valve is moved from its normal open position. Ref: NFPA 13; NFPA 72 supervisory signaling."},
  {id:18, block:1, sec:"Plan Views & Scales", q:"A plan view of a building is best described as a view:", opts:["Looking straight down from above on a horizontal cut","Looking horizontally at one exterior face","Sliced vertically through the building","From a 45-degree angle"], correct:0, re:"A plan is a horizontal-cut view seen from above, showing the layout of walls, rooms, and piping at one level. Ref: architectural drawing conventions."},
  {id:19, block:1, sec:"Plan Views & Scales", q:"An elevation view shows:", opts:["A top-down layout","A flat view of one vertical face of the building","A cut slicing through the interior","A schematic with no scale"], correct:1, re:"An elevation is a straight-on view of one vertical side (facade or interior surface), drawn to scale. Ref: architectural drawing conventions."},
  {id:20, block:1, sec:"Plan Views & Scales", q:"A section view is created by:", opts:["Looking down from the roof","Slicing through the building on a vertical plane and viewing the cut","Photographing the exterior","Rotating the plan 90 degrees"], correct:1, re:"A section drawing cuts vertically through the structure to reveal interior relationships such as ceiling heights and pipe routing. Ref: architectural drawing conventions."},
  {id:21, block:1, sec:"Plan Views & Scales", q:"On an architect's scale, '1/8\" = 1'-0\"' means each 1/8 inch on paper equals:", opts:["1 inch in the building","1 foot in the building","8 feet in the building","1 yard in the building"], correct:1, re:"At 1/8\" = 1'-0\", one-eighth inch on the drawing represents one foot of actual length (a 1:96 ratio). Ref: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:22, block:1, sec:"Plan Views & Scales", q:"The architect's scale uses a fractional system, whereas the engineer's scale uses:", opts:["A decimal system (e.g., 1\" = 20')","Only metric units","No defined ratio","The same fractions as the architect scale"], correct:0, re:"Engineer scales are decimal (1\" = 10', 20', 30', etc.); architect scales use fractions of an inch per foot. Ref: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:23, block:1, sec:"Plan Views & Scales", q:"At a scale of 1/4\" = 1'-0\", a wall drawn 3 inches long on paper represents an actual length of:", opts:["3 feet","6 feet","12 feet","48 feet"], correct:2, re:"At 1/4\" = 1', each inch equals 4 feet; 3 inches x 4 ft = 12 feet. Ref: architect-scale conversion (USFA/FEMA)."},
  {id:24, block:1, sec:"Plan Views & Scales", q:"Why should a designer avoid scaling dimensions directly off a printed sheet when a written dimension is provided?", opts:["Printing/reproduction can distort the scale; written dimensions govern","Scales are illegal to use","Paper is always accurate","Written dimensions are only suggestions"], correct:0, re:"Reproduction and plotting can stretch a drawing, so noted (written) dimensions take precedence over scaled measurements. Ref: standard drafting practice."},
  {id:25, block:1, sec:"Plan Views & Scales", q:"A reflected ceiling plan (RCP) is most useful to a sprinkler designer for:", opts:["Locating ceiling features like tiles, lights, and diffusers that affect head placement","Sizing the underground main","Determining soil bearing","Selecting the fire pump"], correct:0, re:"An RCP shows the ceiling as if mirrored on the floor, helping coordinate sprinkler locations with lights, grids, and diffusers. Ref: architectural/MEP coordination practice."},
  {id:26, block:1, sec:"Plan Views & Scales", q:"On a drawing, the abbreviation 'AFF' typically means:", opts:["Above finished floor","Approved fire flow","Automatic flow fitting","Annual fire form"], correct:0, re:"AFF (above finished floor) references a height measured up from the completed floor surface, used for ceiling and head elevations. Ref: standard drafting abbreviations."},
  {id:27, block:1, sec:"Plan Views & Scales", q:"A larger-scale 'detail' drawing (e.g., a riser detail) is provided to:", opts:["Hide information from the AHJ","Show a small area at greater size and clarity than the overall plan","Replace the cover sheet","Reduce the number of pipe sizes"], correct:1, re:"Details enlarge a specific assembly so connections and components are clearly shown that would be too small on the main plan. Ref: drafting/working-plan practice."},
  {id:28, block:1, sec:"Plan Views & Scales", q:"On a sprinkler plan, the ceiling height directly affects which design parameter most directly?", opts:["The color of the drawing border","Sprinkler clearance to the deflector and obstruction/coverage rules","The title block font","The north arrow direction"], correct:1, re:"Ceiling height and construction govern deflector distance below the ceiling and obstruction rules that determine spacing. Ref: NFPA 13 obstruction and clearance rules."},
  {id:29, block:1, sec:"Plan Views & Scales", q:"A graphic (bar) scale printed on a drawing is helpful because it:", opts:["Remains proportionally correct even if the sheet is enlarged or reduced","Indicates the design density","Shows the legal property line","Replaces the need for dimensions entirely"], correct:0, re:"A bar/graphic scale scales with the drawing, so it stays accurate after reproduction even when the numeric ratio would not. Ref: drafting practice (USFA/FEMA scale guidance)."},
  {id:30, block:1, sec:"Plan Views & Scales", q:"When a plan note says 'NTS,' it means the detail is:", opts:["Not to scale","Near the south stair","New tank system","Noted technical standard"], correct:0, re:"NTS (not to scale) tells the reader the figure is schematic and should not be measured for dimensions. Ref: standard drafting abbreviations."},
  {id:31, block:1, sec:"Plan Views & Scales", q:"To find a ceiling height for sprinkler clearance, a designer most reliably consults the:", opts:["Cover sheet only","Building section or wall section views","Title block","Symbol legend"], correct:1, re:"Section views reveal vertical dimensions such as floor-to-ceiling and floor-to-deck heights needed for head clearance. Ref: architectural section drawings."},
  {id:32, block:1, sec:"Plan Views & Scales", q:"On a site (civil) plan, the underground fire service main location and the FDC are coordinated using which scale type?", opts:["Architect (fractional) scale","Engineer (decimal) scale","No scale","Metric only"], correct:1, re:"Site/civil drawings are typically drawn at engineer (decimal) scales such as 1\" = 20'. Ref: USFA/FEMA, Using Engineer and Architect Scales."},
  {id:33, block:1, sec:"Plan Views & Scales", q:"The 'finished floor elevation' on a drawing is used by the sprinkler designer mainly to:", opts:["Establish a reference datum for heights of pipe, ceilings, and heads","Choose the sprinkler color","Set the system density","Determine the commodity class"], correct:0, re:"Floor elevation provides the baseline datum from which ceiling and head heights are measured for layout and hydraulics. Ref: drafting/coordination practice."},
  {id:34, block:1, sec:"Plan Views & Scales", q:"Coordinating sprinkler layout with HVAC ductwork shown on plans is important because:", opts:["Ducts are wider than 4 ft and can obstruct sprinkler discharge","Ducts change the architect scale","Ducts set the hazard class","Ducts are never shown on plans"], correct:0, re:"Wide ducts (and other obstructions) block spray and may require sprinklers below them or adjusted spacing per the obstruction rules. Ref: NFPA 13 obstruction provisions."},
  {id:35, block:1, sec:"System Components on Plans", q:"The main drain on a sprinkler riser is provided to:", opts:["Drain the system and perform a main drain (flow) test","Supply the FDC","Add antifreeze","Boost pressure"], correct:0, re:"The main drain empties the riser and supports the main drain test that checks water supply availability. Ref: NFPA 13; NFPA 25 main drain test."},
  {id:36, block:1, sec:"System Components on Plans", q:"A waterflow alarm switch (or alarm check valve) on a wet system functions to:", opts:["Signal an alarm when water flows due to an operating sprinkler","Reduce city pressure","Filter sediment","Mark the property line"], correct:0, re:"Waterflow detection initiates the alarm when a sprinkler opens and water moves through the riser. Ref: NFPA 13; NFPA 72."},
  {id:37, block:1, sec:"System Components on Plans", q:"On a dry pipe system plan, the dry pipe valve holds back water using:", opts:["Pressurized air or nitrogen in the piping above the valve","A spring only","Gravity alone","A heating element"], correct:0, re:"In a dry system, pressurized air/nitrogen above the clapper keeps the dry pipe valve closed until a sprinkler opens and air escapes. Ref: NFPA 13 dry pipe systems."},
  {id:38, block:1, sec:"System Components on Plans", q:"A fire department connection (FDC) allows the fire department to:", opts:["Pump supplemental water/pressure into the sprinkler system","Drain the system","Shut off the city water","Test sprinkler temperature ratings"], correct:0, re:"The FDC is an inlet for fire-department pumpers to augment the system's flow and pressure during a fire. Ref: NFPA 13 FDC requirements."},
  {id:39, block:1, sec:"System Components on Plans", q:"The system control valve (e.g., OS&Y or butterfly) shown at the riser is normally kept:", opts:["Open and supervised","Closed","Half open","Removed during operation"], correct:0, re:"Control valves must be normally open and supervised so water is always available to the system. Ref: NFPA 13; NFPA 25 valve supervision."},
  {id:40, block:1, sec:"System Components on Plans", q:"On plans, a 'cross main' is the pipe that:", opts:["Feeds the branch lines","Holds the sprinklers directly","Connects to the FDC only","Drains the system"], correct:0, re:"Cross mains distribute water to the branch lines, which in turn carry the sprinklers. Ref: NFPA 13 pipe definitions."},
  {id:41, block:1, sec:"System Components on Plans", q:"A 'branch line' on a sprinkler plan is the pipe that:", opts:["Directly supplies the sprinklers","Is the vertical riser","Connects two buildings","Carries only drain water"], correct:0, re:"Branch lines are the pipes to which sprinklers are directly attached. Ref: NFPA 13 pipe definitions."},
  {id:42, block:1, sec:"System Components on Plans", q:"A fire pump is shown on plans when:", opts:["The available water supply pressure/flow is insufficient for the design demand","Every building has one by law","The system is wet only","Antifreeze is used"], correct:0, re:"A fire pump boosts pressure/flow when the supply cannot meet the hydraulic demand. Ref: NFPA 13; NFPA 20 fire pumps."},
  {id:43, block:1, sec:"System Components on Plans", q:"On a riser detail, pressure gauges are installed to:", opts:["Set the architect scale","Drain the riser","Trip the dry pipe valve","Indicate system and supply pressures for monitoring and testing"], correct:3, re:"Gauges display supply and system pressures so the system can be monitored and main drain tests evaluated. Ref: NFPA 13; NFPA 25."},
  {id:44, block:1, sec:"System Components on Plans", q:"A backflow prevention assembly may be shown on the incoming supply primarily to:", opts:["Heat the water","Increase sprinkler density","Replace the FDC","Protect the potable water supply from contamination"], correct:3, re:"Backflow preventers stop possibly contaminated system water from flowing back into the public supply. Ref: NFPA 13; local plumbing/cross-connection code."},
  {id:45, block:1, sec:"System Components on Plans", q:"In a double-interlock preaction system, water enters the piping only when:", opts:["The main drain is opened","A sprinkler opens alone","Detection operates alone","Both detection operates AND a sprinkler opens"], correct:3, re:"Double-interlock preaction requires both an independent detection signal and an open sprinkler before water is admitted, minimizing accidental water release. Ref: NFPA 13 preaction systems."},
  {id:46, block:1, sec:"System Components on Plans", q:"An auxiliary drain (drum drip) on a dry system is provided at:", opts:["The fire pump suction","The highest point only","The FDC","Low points/trapped sections to remove condensate"], correct:3, re:"Low-point auxiliary drains (drum drips) collect and remove condensation that accumulates in dry-system piping. Ref: NFPA 13 dry system drainage."},
  {id:47, block:1, sec:"System Components on Plans", q:"A deluge valve on a plan is associated with:", opts:["Antifreeze loops","Closed pendent heads only","A pressure-reducing function","Open sprinklers/nozzles that all flow when the valve trips"], correct:3, re:"Deluge systems use open nozzles; when the deluge valve trips on detection, water flows from all of them simultaneously. Ref: NFPA 13 deluge systems."},
  {id:48, block:1, sec:"System Components on Plans", q:"On plans, hangers and seismic bracing are shown to:", opts:["Identify the commodity class","Increase water density","Mark the FDC","Support and restrain the piping"], correct:3, re:"Hangers support pipe weight and bracing restrains movement (including seismic), per NFPA 13 hanging and bracing rules. Ref: NFPA 13 Ch. on hanging/bracing."},
  {id:49, block:1, sec:"System Components on Plans", q:"A 'standpipe' shown alongside sprinkler piping is intended to:", opts:["Supply the city main","Replace sprinklers","Drain condensate","Provide hose connections for manual firefighting"], correct:3, re:"Standpipes deliver water to hose valves on each floor for fire-department or occupant hose streams (NFPA 14). Ref: NFPA 14; coordination with NFPA 13."},
  {id:50, block:1, sec:"System Components on Plans", q:"A pressure-reducing valve (PRV) may appear on a high-rise riser to:", opts:["Provide the FDC","Add air to the system","Increase flow above the supply","Limit excessive pressure to acceptable levels for the components downstream"], correct:3, re:"PRVs reduce high static pressure (common at lower floors of tall buildings) to protect piping and devices. Ref: NFPA 13 / NFPA 14 pressure limits."},
  {id:51, block:1, sec:"System Components on Plans", q:"On the plan, the 'point of connection' to the water supply is important because it:", opts:["Selects the commodity class","Sets the sprinkler color","Determines the architect scale","Defines where the system ties into the source used for hydraulic calculations"], correct:3, re:"The supply point of connection establishes the source pressure/flow basis for the hydraulic design. Ref: NFPA 13 water supply and hydraulic calculation requirements."},
  {id:52, block:1, sec:"Occupancy & Commodity Classification", q:"Under NFPA 13, which occupancy is classified as Light Hazard?", opts:["Auto repair garage","Library reading room","Paper manufacturing","Aircraft hangar"], correct:1, re:"Light Hazard covers low quantity/combustibility contents such as offices, churches, and library reading rooms. Ref: NFPA 13 occupancy classification (Light Hazard)."},
  {id:53, block:1, sec:"Occupancy & Commodity Classification", q:"A bakery or laundry is typically classified by NFPA 13 as:", opts:["Light Hazard","Ordinary Hazard Group 1","Extra Hazard Group 1","Extra Hazard Group 2"], correct:1, re:"Bakeries and laundries are example Ordinary Hazard Group 1 occupancies (moderate quantity, low combustibility). Ref: NFPA 13 occupancy classification (OH1)."},
  {id:54, block:1, sec:"Occupancy & Commodity Classification", q:"Which of the following is an example of an Ordinary Hazard Group 2 occupancy?", opts:["Church sanctuary","Library reading room","Machine shop / metalworking","Office"], correct:2, re:"Ordinary Hazard Group 2 includes machine shops, mercantile, and similar moderate-to-higher combustible occupancies. Ref: NFPA 13 occupancy classification (OH2)."},
  {id:55, block:1, sec:"Occupancy & Commodity Classification", q:"Aircraft hangars and similar high-combustible operations are generally classified as:", opts:["Light Hazard","Ordinary Hazard Group 1","Extra Hazard Group 1","Light Hazard with exceptions"], correct:2, re:"Extra Hazard Group 1 covers high combustibility with rapid fire development such as aircraft hangars and printing operations. Ref: NFPA 13 occupancy classification (EH1)."},
  {id:56, block:1, sec:"Occupancy & Commodity Classification", q:"An automobile paint spray booth (substantial flammable liquids) is best classified as:", opts:["Light Hazard","Ordinary Hazard Group 1","Ordinary Hazard Group 2","Extra Hazard Group 2"], correct:3, re:"Extra Hazard Group 2 covers occupancies with substantial flammable/combustible liquids such as paint spray applications. Ref: NFPA 13 occupancy classification (EH2)."},
  {id:57, block:1, sec:"Occupancy & Commodity Classification", q:"In NFPA 13, the occupancy hazard classification is used mainly to determine:", opts:["The wall paint color","The water-supply design density and area criteria","The architect scale","The drawing title block"], correct:1, re:"Hazard classification sets the design density and operating area used to size the system. Ref: NFPA 13 design approaches by hazard class."},
  {id:58, block:1, sec:"Occupancy & Commodity Classification", q:"A Class I commodity under NFPA 13 is best described as:", opts:["Rubber tires","High-heat-release plastic","Flammable liquid in drums","Essentially noncombustible product, may be on combustible pallets / in cartons"], correct:3, re:"Class I is essentially noncombustible product, allowing ordinary corrugated cartons and wood pallets. Ref: NFPA 13 commodity classification (Class I)."},
  {id:59, block:1, sec:"Occupancy & Commodity Classification", q:"Group A plastics differ from Group B and C plastics because they have:", opts:["The lowest heat of combustion","A heat of combustion and burning rate much higher than ordinary combustibles","No effect on sprinkler design","The same burning rate as wood"], correct:1, re:"Group A plastics have the highest heat of combustion and fastest burning rate of the three groups, driving the most demanding storage criteria. Ref: NFPA 13 plastics classification."},
  {id:60, block:1, sec:"Occupancy & Commodity Classification", q:"Which material is an example of a Group A plastic?", opts:["Nylon","Polystyrene (e.g., expanded)","Phenolic","Rigid PVC (under 5% plasticized)"], correct:1, re:"Polystyrene (expanded/unexpanded), polyethylene, polypropylene, ABS, and PET are Group A plastics. Ref: NFPA 13 plastics classification (Group A)."},
  {id:61, block:1, sec:"Occupancy & Commodity Classification", q:"Nylon and unexpanded natural rubber are examples of which plastics group?", opts:["Group A","Group B","Group C","Not a plastic"], correct:1, re:"Group B plastics include nylon, cellulosics, and unexpanded natural rubber (between Group A and C in severity). Ref: NFPA 13 plastics classification (Group B)."},
  {id:62, block:1, sec:"Occupancy & Commodity Classification", q:"Which of the following is a Group C plastic?", opts:["Polyethylene","Polypropylene","Phenolic (or PTFE)","ABS"], correct:2, re:"Group C plastics (e.g., phenolic, melamine, PTFE, rigid PVC) burn similarly to ordinary combustibles. Ref: NFPA 13 plastics classification (Group C)."},
  {id:63, block:1, sec:"Occupancy & Commodity Classification", q:"NFPA 13 treats the fire risk of Group C plastics as roughly equivalent to which commodity class?", opts:["Class I","Class II","Class III","Class IV"], correct:2, re:"Group C plastics are considered equivalent to Class III commodities (ordinary-combustible-like behavior). Ref: NFPA 13 commodity/plastics equivalency."},
  {id:64, block:1, sec:"Occupancy & Commodity Classification", q:"A Class IV commodity contains:", opts:["No plastics at all","Appreciable amounts of Group A plastics (within defined limits) added to lower-class product","Only noncombustible items","Pure flammable liquid"], correct:1, re:"Class IV is a product containing an appreciable but limited amount of Group A plastics (e.g., 5-15% by weight). Ref: NFPA 13 commodity classification (Class IV)."},
  {id:65, block:1, sec:"Occupancy & Commodity Classification", q:"Commodity classification (Class I-IV, plastics) is the starting point for designing protection in:", opts:["Light hazard offices","Storage / warehouse occupancies","Open parking decks only","Residential bedrooms"], correct:1, re:"Storage occupancies are protected based on commodity class, storage height, and arrangement rather than the basic occupancy hazard alone. Ref: NFPA 13 storage protection."},
  {id:66, block:1, sec:"Occupancy & Commodity Classification", q:"Class III commodities are generally described as:", opts:["Noncombustible products only","Wood, paper, natural fibers, or Group C plastics (with limited Group A/B)","Pure Group A plastics","Flammable gases"], correct:1, re:"Class III is wood, paper, natural-fiber cloth, or Group C plastics, with only a small allowance of Group A/B plastics. Ref: NFPA 13 commodity classification (Class III)."},
  {id:67, block:1, sec:"Occupancy & Commodity Classification", q:"When the contents combine multiple hazards in one space, the designer generally protects to:", opts:["The lowest hazard present","Light hazard by default","The most demanding (highest) hazard present, or designs by area","Whatever is cheapest"], correct:2, re:"Mixed commodities/occupancies are generally protected to the highest hazard present unless areas are separated and designed individually. Ref: NFPA 13 mixed-commodity/occupancy guidance."},
  {id:68, block:1, sec:"Occupancy & Commodity Classification", q:"Encapsulation of a stored commodity (e.g., plastic wrap over the top) matters because it:", opts:["Has no effect on fire behavior","Lowers the commodity class","Can trap heat/limit water penetration, increasing the protection demand","Eliminates the need for sprinklers"], correct:2, re:"Encapsulation can shield the commodity from water and intensify fire behavior, often requiring increased protection. Ref: NFPA 13 storage (encapsulation provisions)."},
  {id:69, block:1, sec:"System Type Selection", q:"A wet pipe sprinkler system is appropriate where:", opts:["Temperatures may drop below freezing","Accidental water cannot be tolerated at all","The area is heated and stays above 40 F (4 C)","Only open nozzles are used"], correct:2, re:"Wet systems keep water in the pipe and are used in heated areas maintained at or above 40 F (4 C). Ref: NFPA 13 wet pipe system use."},
  {id:70, block:1, sec:"System Type Selection", q:"A dry pipe system is selected primarily for:", opts:["Heated office space","Areas needing the fastest possible water delivery","Unheated/freezing areas such as cold warehouses or parking garages","Locations with no water supply"], correct:2, re:"Dry systems use pressurized air to keep water out of pipe exposed to freezing, common in unheated spaces. Ref: NFPA 13 dry pipe system use."},
  {id:71, block:1, sec:"System Type Selection", q:"Compared to a wet system, a dry pipe system has:", opts:["Faster water delivery to an open sprinkler","No need for a control valve","A delay because air must vent before water reaches the sprinkler","No need for a water supply"], correct:2, re:"Dry systems have an inherent delay because trapped air must exhaust before water flows from an open head. Ref: NFPA 13 dry system characteristics."},
  {id:72, block:1, sec:"System Type Selection", q:"A single-interlock preaction system admits water to the piping when:", opts:["A sprinkler fuses only","The main drain opens","A separate detection system operates","The FDC is connected"], correct:2, re:"Single-interlock preaction fills the pipe upon a detection signal; water then flows when a sprinkler opens. Ref: NFPA 13 preaction system types."},
  {id:73, block:1, sec:"System Type Selection", q:"A preaction system is commonly chosen to protect:", opts:["Open parking lots","Outdoor loading docks","Water-sensitive areas like data centers or archives","Boiler rooms only"], correct:2, re:"Preaction systems reduce the chance of accidental water discharge, making them suitable for water-sensitive spaces such as data centers and museums. Ref: NFPA 13 preaction applications."},
  {id:74, block:1, sec:"System Type Selection", q:"A deluge system is most appropriate for:", opts:["A typical office","Cold storage with no hazard","High-hazard areas requiring simultaneous water from all heads (e.g., aircraft hangars)","A small residential unit"], correct:2, re:"Deluge systems use open heads and apply water everywhere at once for fast-spreading high-hazard fires. Ref: NFPA 13 deluge applications."},
  {id:75, block:1, sec:"System Type Selection", q:"A double-interlock preaction system is well suited to:", opts:["A heated lobby","Open carports","Freezer warehouses where accidental water is costly and freezing is a concern","A standard sprinklered office"], correct:2, re:"Double-interlock preaction prevents water entry unless both detection and a sprinkler operate, ideal for freezers. Ref: NFPA 13 double-interlock preaction."},
  {id:76, block:1, sec:"System Type Selection", q:"Below approximately what temperature does NFPA 13 generally steer designers away from wet systems toward dry or preaction?", opts:["120 F (49 C)","70 F (21 C)","90 F (32 C)","40 F (4 C)"], correct:3, re:"Where temperatures can fall below 40 F (4 C), a wet system risks freezing, so dry/preaction or freeze protection is used. Ref: NFPA 13 freeze-protection threshold."},
  {id:77, block:1, sec:"System Type Selection", q:"Open sprinklers (no heat-responsive element) are used in which system?", opts:["Wet pipe","Dry pipe","Deluge","Single-interlock preaction"], correct:2, re:"Deluge systems use open sprinklers/nozzles so all flow at once when the deluge valve trips. Ref: NFPA 13 deluge system definition."},
  {id:78, block:1, sec:"System Type Selection", q:"Which system keeps the piping dry until detection operates AND is intended to limit accidental water release?", opts:["Wet pipe","Conventional deluge","Preaction","Antifreeze loop"], correct:2, re:"Preaction systems hold the pipe dry until detection (and, for interlock types, a sprinkler) operates, limiting inadvertent discharge. Ref: NFPA 13 preaction systems."},
  {id:79, block:1, sec:"System Type Selection", q:"An antifreeze sprinkler system is a variation typically used to:", opts:["Increase pressure","Replace the fire pump","Protect small unheated areas of an otherwise wet system without a separate dry valve","Eliminate the riser"], correct:2, re:"Antifreeze loops protect limited unheated portions by filling that section with an approved antifreeze solution. Ref: NFPA 13 antifreeze system provisions."},
  {id:80, block:1, sec:"System Type Selection", q:"For a typical heated office building, the most common and economical system type is:", opts:["Deluge","Double-interlock preaction","Wet pipe","Dry pipe"], correct:2, re:"Wet pipe systems are the most common and simplest for heated occupancies, giving the fastest response. Ref: NFPA 13; common design practice."},
  {id:81, block:1, sec:"System Type Selection", q:"A key disadvantage of dry pipe systems compared with wet is:", opts:["They cannot be used in warehouses","They require no maintenance","Increased complexity, corrosion potential, and delayed water delivery","They cannot detect fire"], correct:2, re:"Dry systems add air-supply equipment, are prone to internal corrosion/condensation, and delay water delivery. Ref: NFPA 13 dry system considerations."},
  {id:82, block:1, sec:"System Type Selection", q:"When selecting a system type, the FIRST consideration the designer evaluates is usually:", opts:["The color of the pipe","The brand of sprinkler","The building's environment/hazard (e.g., freezing, water sensitivity, hazard level)","The font on the title block"], correct:2, re:"System type follows from the environment and hazard: heated vs freezing, water-sensitive contents, and severity of hazard. Ref: NFPA 13 system selection rationale."},
  {id:83, block:1, sec:"System Type Selection", q:"A combined dry pipe-preaction system might be specified for:", opts:["A small office","A residential bedroom","Very long piping in cold areas needing the benefits of both approaches","An open parking lot"], correct:2, re:"Combined dry pipe-preaction arrangements address large/long cold systems where both freeze protection and supervision are desired. Ref: NFPA 13 combined system provisions."},
  {id:84, block:1, sec:"System Type Selection", q:"For a freezer storage warehouse where any water in idle piping causes ice damage, the preferred choice is:", opts:["Wet pipe","Single-interlock preaction","Double-interlock preaction","Antifreeze loop on the whole system"], correct:2, re:"Double-interlock preaction keeps piping dry until both detection and sprinkler activation, best for freezers. Ref: NFPA 13 double-interlock preaction use."},
  {id:85, block:1, sec:"Codes & Standards Overview", q:"NFPA 13 is the standard for the:", opts:["Installation of fire pumps","Inspection, testing, and maintenance of water-based systems","Installation of fire alarm systems","Installation of sprinkler systems"], correct:3, re:"NFPA 13 is the Standard for the Installation of Sprinkler Systems. Ref: NFPA 13 (title/scope)."},
  {id:86, block:1, sec:"Codes & Standards Overview", q:"Which document defines the Authority Having Jurisdiction (AHJ)?", opts:["The building owner only","The general contractor","The sprinkler manufacturer","NFPA, as the office/individual responsible for enforcing a code or approving equipment"], correct:3, re:"NFPA defines the AHJ as the organization, office, or individual responsible for enforcing a code/standard or approving equipment and installations. Ref: NFPA definitions (AHJ)."},
  {id:87, block:1, sec:"Codes & Standards Overview", q:"How does NFPA 13 become legally enforceable in a jurisdiction?", opts:["It is automatically law everywhere","Manufacturers vote on it","It is adopted by reference through a building/fire code or local ordinance","It applies only if printed in color"], correct:2, re:"NFPA 13 gains the force of law when adopted by reference in an applicable building or fire code or ordinance. Ref: code-adoption process; NFPA."},
  {id:88, block:1, sec:"Codes & Standards Overview", q:"Which standard most commonly references NFPA 13 to require sprinkler installation in buildings?", opts:["NFPA 25","NFPA 170","The International Building Code (IBC) / International Fire Code (IFC)","NFPA 20"], correct:2, re:"Model codes like the IBC and IFC reference NFPA 13 for the installation of required sprinkler systems. Ref: IBC/IFC referenced standards."},
  {id:89, block:1, sec:"Codes & Standards Overview", q:"NFPA 25 covers the:", opts:["Installation of new sprinkler systems","Design of fire alarm systems","Inspection, testing, and maintenance of water-based fire protection systems","Manufacture of pipe"], correct:2, re:"NFPA 25 is the Standard for the Inspection, Testing, and Maintenance of Water-Based Fire Protection Systems. Ref: NFPA 25 (title/scope)."},
  {id:90, block:1, sec:"Codes & Standards Overview", q:"NFPA 20 is the standard for the:", opts:["Standpipe and hose systems","Symbols on drawings","Sprinkler maintenance","Installation of stationary fire pumps for fire protection"], correct:3, re:"NFPA 20 is the Standard for the Installation of Stationary Pumps for Fire Protection. Ref: NFPA 20 (title/scope)."},
  {id:91, block:1, sec:"Codes & Standards Overview", q:"NFPA 14 is the standard for:", opts:["Sprinkler installation","Water-based ITM","Fire alarm systems","Standpipe and hose systems"], correct:3, re:"NFPA 14 is the Standard for the Installation of Standpipe and Hose Systems. Ref: NFPA 14 (title/scope)."},
  {id:92, block:1, sec:"Codes & Standards Overview", q:"When the AHJ and NFPA 13 differ, in an adopting jurisdiction the designer must generally:", opts:["Ignore the AHJ","Pick whichever is cheaper","Use only the manufacturer's catalog","Comply with the enforceable code/AHJ requirements, which may be more stringent"], correct:3, re:"The adopted code and the AHJ's enforcement govern; local amendments may be more restrictive than the base standard. Ref: code-adoption/AHJ authority."},
  {id:93, block:1, sec:"Codes & Standards Overview", q:"NFPA 13R is intended for sprinkler systems in:", opts:["High-hazard warehouses","Refineries","Aircraft hangars","Low-rise residential occupancies up to four stories (as defined)"], correct:3, re:"NFPA 13R addresses residential occupancies up to and including four stories within its scope. Ref: NFPA 13R (scope)."},
  {id:94, block:1, sec:"Codes & Standards Overview", q:"NFPA 13D applies to sprinkler systems in:", opts:["High-rise offices","Hospitals","Storage warehouses","One- and two-family dwellings and manufactured homes"], correct:3, re:"NFPA 13D is the standard for sprinkler systems in one- and two-family dwellings and manufactured homes. Ref: NFPA 13D (scope)."},
  {id:95, block:1, sec:"Codes & Standards Overview", q:"Working (shop) drawings are submitted to the AHJ primarily to:", opts:["Set the architect scale","Sell the building","Replace the hydraulic calculations","Obtain review and approval/permit before installation"], correct:3, re:"Shop drawings are submitted for AHJ review, approval, and permitting prior to installation. Ref: NFPA 13 working-plan/approval requirements."},
  {id:96, block:1, sec:"Codes & Standards Overview", q:"The edition of NFPA 13 a designer must follow is determined by:", opts:["The newest edition always","The pipe manufacturer","The designer's personal preference","The edition referenced/adopted by the governing code in that jurisdiction"], correct:3, re:"The applicable edition is the one adopted by the jurisdiction's governing code, which may not be the latest. Ref: code-adoption practice."},
  {id:97, block:1, sec:"Codes & Standards Overview", q:"A 'listed' component referenced in NFPA 13 means the product is:", opts:["Painted red","Exempt from inspection","Cheaper than alternatives","Evaluated by a recognized testing laboratory and published on a list for its intended use"], correct:3, re:"'Listed' indicates equipment evaluated by a recognized lab (e.g., UL/FM) and published as suitable for a specific use. Ref: NFPA definitions (listed)."},
  {id:98, block:1, sec:"Codes & Standards Overview", q:"NFPA 170 supports plan reading by providing:", opts:["Hydraulic calculation methods","Commodity classes","Pump curves","Standardized fire safety and emergency symbols"], correct:3, re:"NFPA 170 standardizes the fire safety/emergency symbols used on drawings and signage. Ref: NFPA 170 (scope)."},
  {id:99, block:1, sec:"Codes & Standards Overview", q:"The maximum floor area protected by a single sprinkler system for Light or Ordinary Hazard is traditionally limited to:", opts:["25,000 sq ft","No limit","100,000 sq ft","52,000 sq ft"], correct:3, re:"NFPA 13 traditionally limits a single Light/Ordinary Hazard system to 52,000 sq ft (Extra Hazard/high-piled to 40,000 sq ft). Ref: NFPA 13 system protection area limitations."},
  {id:100, block:1, sec:"Codes & Standards Overview", q:"Within the design hierarchy, the role of NFPA 13 relative to the adopting building code is to:", opts:["Override the building code in all cases","Define occupant load","Replace the AHJ","Serve as the referenced installation standard the code points to for sprinkler systems"], correct:3, re:"The building/fire code references NFPA 13 as the installation standard; the code and AHJ remain the legal authority. Ref: model-code referenced-standard structure."},
  {id:101, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"What does a sprinkler's nominal K-factor represent in design?", opts:["The thermal sensitivity (response time index) of the operating element","The temperature at which the operating element releases","The maximum coverage area the sprinkler may protect","The discharge coefficient relating flow to the square root of pressure (Q = K√P)"], correct:3, re:"The K-factor is the discharge coefficient in Q = K√P, where Q is flow (gpm) and P is pressure (psi). NFPA 13 specifies use of the nominal K-factor for hydraulic calculations."},
  {id:102, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"A standard-spray sprinkler with a nominal K-factor of 5.6 flowing at 7 psi discharges approximately how many gpm? (Q = K√P)", opts:["About 14.8 gpm","About 5.6 gpm","About 39 gpm","About 25 gpm"], correct:0, re:"Q = K√P = 5.6 × √7 = 5.6 × 2.646 ≈ 14.8 gpm. The K-factor times the square root of pressure gives the discharge."},
  {id:103, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"The most common nominal K-factor historically used for standard-spray light- and ordinary-hazard sprinklers is:", opts:["K-2.8","K-5.6","K-11.2","K-25.2"], correct:1, re:"K-5.6 (1/2 in. orifice) is the traditional standard-spray K-factor for light and ordinary hazard. NFPA 13 lists nominal K-factors; K-5.6 is the long-standing baseline."},
  {id:104, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"Compared with a K-5.6 sprinkler at the same pressure, a K-11.2 sprinkler discharges approximately:", opts:["Half the flow","The same flow","Four times the flow","Twice the flow"], correct:3, re:"Because flow is proportional to K, doubling K from 5.6 to 11.2 doubles the discharge at a given pressure (Q = K√P)."},
  {id:105, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"When a water supply provides limited pressure but adequate volume, selecting a larger K-factor sprinkler is advantageous because it:", opts:["Allows wider sprinkler spacing automatically","Reduces the required design density","Delivers the required flow at a lower operating pressure","Lowers the temperature rating needed"], correct:2, re:"A larger K-factor delivers the same flow at lower pressure (Q = K√P), so it is favored where supply pressure is limited. Spacing and density limits are set independently."},
  {id:106, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"For storage applications, NFPA 13 generally requires a minimum nominal K-factor of at least:", opts:["K-2.8","K-8.0","K-4.2","K-25.2"], correct:1, re:"Storage protection requires larger orifices to deliver higher densities; NFPA 13 storage criteria generally call for K-8.0 (and larger) sprinklers. K-2.8 and K-4.2 are limited to light hazard/residential uses."},
  {id:107, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"An upright spray sprinkler is selected over a pendent primarily when:", opts:["The branch line runs exposed below the ceiling/structure","A finished ceiling conceals the piping","Sidewall coverage is required from one wall","ESFR storage protection is needed"], correct:0, re:"Uprights are used on exposed branch lines (e.g., under exposed structure) so the deflector throws water down/out correctly. Pendents drop below finished ceilings."},
  {id:108, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"A standard sidewall spray sprinkler is most appropriate where:", opts:["High-piled storage must be protected","Extra-hazard process areas require 12 ft spacing","ESFR ceiling-only protection is used","Branch piping cannot be run across the ceiling and coverage must come from a wall"], correct:3, re:"Sidewall sprinklers discharge a half-paraboloid from a wall and are used where overhead piping is impractical. NFPA 13 limits sidewalls mainly to light and ordinary hazard (Group 1) rooms."},
  {id:109, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"Standard sidewall spray sprinklers are generally limited by NFPA 13 to which occupancies?", opts:["Extra hazard Group 2 only","Light hazard and ordinary hazard (Group 1) only","High-piled storage only","All occupancies without restriction"], correct:1, re:"NFPA 13 restricts standard sidewall spray sprinklers to light hazard and ordinary hazard Group 1; other hazards require overhead spray or special sprinklers."},
  {id:110, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"A dry-pendent sprinkler is selected primarily to:", opts:["Increase the K-factor of a wet system","Allow a pendent to drop from a wet system into an unheated/freezing space without trapped water at the head","Provide quick-response operation","Protect against high ceiling temperatures"], correct:1, re:"A dry pendent/dry sidewall keeps water back at the heated portion of the system, letting a single head extend into a freezer or unheated area without freezing. It does not change K-factor or response class."},
  {id:111, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"Concealed pendent sprinklers with a cover plate are chosen mainly for:", opts:["Higher discharge density","Wider maximum spacing than standard pendents","Storage occupancies","Aesthetics in finished ceilings, with the cover plate dropping at a set temperature"], correct:3, re:"Concealed sprinklers hide the head behind a cover plate that releases at a rated temperature (commonly 135 F) before the sprinkler operates; they are an aesthetic choice for finished ceilings and follow standard-spray spacing."},
  {id:112, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"Which sprinkler type is specifically listed and intended for the protection of high-piled and rack storage from ceiling level, often eliminating in-rack sprinklers?", opts:["ESFR (Early Suppression Fast Response)","Standard sidewall spray","Residential sprinkler","Open deluge sprinkler"], correct:0, re:"ESFR sprinklers are designed to suppress (not merely control) storage fires from the ceiling, frequently removing the need for in-rack sprinklers within their listed limits."},
  {id:113, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"Residential sprinklers (per NFPA 13's residential provisions) are listed primarily to:", opts:["Maximize control density in warehouses","Protect extra-hazard chemical processes","Provide tenability for occupant escape in dwelling units using fast-response elements","Replace ESFR in rack storage"], correct:2, re:"Residential sprinklers use fast-response elements and wall-wetting patterns to improve life safety/tenability in dwelling units; they are not control/suppression heads for industrial storage."},
  {id:114, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"A Control Mode Specific Application (CMSA, formerly 'large drop') sprinkler is characterized by:", opts:["Large water droplets and high momentum to penetrate the fire plume in storage","A small orifice and quick-response element for offices","A cover plate for concealed installation","Sidewall-only discharge"], correct:0, re:"CMSA sprinklers produce large, high-momentum droplets that penetrate the fire plume for storage protection; they are a control-mode option distinct from ESFR suppression sprinklers."},
  {id:115, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"For a hydraulically calculated light-hazard system, NFPA 13 generally requires sprinklers with a nominal K-factor of at least:", opts:["K-1.4","K-2.8","K-5.6","K-14.0"], correct:2, re:"Hydraulically calculated light- and ordinary-hazard systems generally use K-5.6 or larger; smaller orifices (K-2.8/K-4.2) are limited to specific listed light-hazard uses."},
  {id:116, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"An open sprinkler (no heat-responsive element) is used in:", opts:["Deluge systems where all heads flow simultaneously on system actuation","Standard wet-pipe light-hazard systems","Quick-response ordinary-hazard rooms","ESFR storage ceilings"], correct:0, re:"Open sprinklers have no fusible/bulb element and are used in deluge systems, where a separate detection system opens the deluge valve and water flows from every head at once."},
  {id:117, block:2, sec:"Sprinkler Type & K-Factor Selection", q:"Selecting an extended-coverage (EC) sprinkler instead of a standard-spray sprinkler primarily allows the designer to:", opts:["Reduce the design density required","Eliminate hydraulic calculations","Lower the temperature rating needed","Cover a larger floor area per sprinkler within its specific listing"], correct:3, re:"EC sprinklers are listed for larger protection areas and wider spacings than standard spray, reducing the number of heads. They must be used strictly within their listing and still require hydraulic calculation."},
  {id:118, block:2, sec:"Coverage Area & Spacing Rules", q:"For standard-spray sprinklers in LIGHT hazard (unobstructed construction), the maximum protection area per sprinkler is:", opts:["130 ft²","196 ft²","400 ft²","225 ft²"], correct:3, re:"NFPA 13 Table for standard spray: light hazard maximum protection area is 225 ft² per sprinkler (e.g., 15 ft × 15 ft)."},
  {id:119, block:2, sec:"Coverage Area & Spacing Rules", q:"For standard-spray sprinklers in ORDINARY hazard (unobstructed construction), the maximum protection area per sprinkler is:", opts:["225 ft²","130 ft²","100 ft²","400 ft²"], correct:1, re:"NFPA 13: ordinary hazard maximum protection area for standard spray is 130 ft² per sprinkler."},
  {id:120, block:2, sec:"Coverage Area & Spacing Rules", q:"For standard-spray sprinklers in LIGHT or ORDINARY hazard, the maximum distance between sprinklers on a branch line is:", opts:["10 ft","15 ft","12 ft","20 ft"], correct:1, re:"NFPA 13 sets 15 ft maximum spacing between standard-spray sprinklers for both light and ordinary hazard."},
  {id:121, block:2, sec:"Coverage Area & Spacing Rules", q:"For standard-spray sprinklers in EXTRA hazard, the maximum distance between sprinklers is:", opts:["15 ft","8 ft","20 ft","12 ft"], correct:3, re:"NFPA 13 limits extra-hazard standard-spray spacing to 12 ft (pipe-schedule and hydraulically calculated systems at densities of 0.25 gpm/ft² or greater)."},
  {id:122, block:2, sec:"Coverage Area & Spacing Rules", q:"For standard-spray EXTRA-hazard sprinklers, the maximum protection area per sprinkler (hydraulically calculated, density less than 0.25 gpm/ft²) is:", opts:["400 ft²","100 ft²","225 ft²","130 ft²"], correct:3, re:"For extra hazard, hydraulically calculated systems below 0.25 gpm/ft² may use up to 130 ft²; at 0.25 gpm/ft² and above (and pipe-schedule) the maximum is 100 ft²."},
  {id:123, block:2, sec:"Coverage Area & Spacing Rules", q:"The protection area per sprinkler (A_s) is determined by which relationship?", opts:["A_s = S − L","A_s = K × √P","A_s = S × L, where S is the along-branch dimension and L is the between-branch dimension","A_s = density × pressure"], correct:2, re:"NFPA 13 computes the protection area per sprinkler as A_s = S × L, where S is the distance along the branch line (greater of twice the wall distance or the spacing) and L is the distance between branch lines, both taken as the larger applicable value."},
  {id:124, block:2, sec:"Coverage Area & Spacing Rules", q:"When computing S (along the branch line) for a sprinkler adjacent to a wall, the dimension used is:", opts:["The actual distance to the wall only","Always 15 ft","Half the distance to the wall","Twice the distance to the wall, or the spacing to the next sprinkler — whichever is greater"], correct:3, re:"NFPA 13 takes S as the greater of: twice the distance to the wall (end sprinkler) or the distance to the adjacent sprinkler. This ensures the area is not understated for end heads."},
  {id:125, block:2, sec:"Coverage Area & Spacing Rules", q:"The maximum distance from a standard-spray sprinkler to a wall is:", opts:["Equal to the maximum sprinkler-to-sprinkler spacing","One-half of the maximum allowable distance permitted between sprinklers","One-quarter of the room width","Always 4 in"], correct:1, re:"NFPA 13: the distance to a wall may not exceed one-half of the allowable spacing between sprinklers (e.g., 7.5 ft for a 15 ft layout)."},
  {id:126, block:2, sec:"Coverage Area & Spacing Rules", q:"The minimum distance a standard-spray sprinkler deflector may be placed from a wall is:", opts:["4 in","12 in","18 in","2 in"], correct:0, re:"NFPA 13 requires sprinklers to be at least 4 in from a wall to keep the wall from obstructing the developing discharge pattern."},
  {id:127, block:2, sec:"Coverage Area & Spacing Rules", q:"The minimum distance permitted between two standard-spray sprinklers (without a baffle) is:", opts:["4 ft","6 ft","8 ft","10 ft"], correct:1, re:"NFPA 13 requires at least 6 ft between sprinklers (measured along the slope of the ceiling) to prevent cold-soldering, unless a listed baffle is installed between them."},
  {id:128, block:2, sec:"Coverage Area & Spacing Rules", q:"Two sprinklers may be spaced closer than 6 ft on center only when:", opts:["The ceiling is sloped","The hazard is light","They are quick-response","A baffle is installed between them to shield the operating elements"], correct:3, re:"A listed baffle between closely spaced heads shields each operating element from the other's discharge (preventing cold-soldering), which is the condition NFPA 13 allows for less than 6 ft spacing."},
  {id:129, block:2, sec:"Coverage Area & Spacing Rules", q:"The NFPA 13 'small room rule' applies to a light-hazard room that is:", opts:["Any room with a sloped ceiling","Any room under 1,500 ft²","Any ordinary-hazard room","Unobstructed, of light-hazard occupancy, and 800 ft² or less in area"], correct:3, re:"The small room rule applies to an unobstructed light-hazard compartment of 800 ft² or less, permitting a sprinkler up to 9 ft from any single wall."},
  {id:130, block:2, sec:"Coverage Area & Spacing Rules", q:"Under the small room rule, a sprinkler may be located a maximum of how far from any single wall?", opts:["7.5 ft","12 ft","9 ft","15 ft"], correct:2, re:"The small room rule allows a sprinkler to be placed up to 9 ft from any single wall (instead of the usual one-half-spacing wall limit), within an 800 ft² light-hazard room."},
  {id:131, block:2, sec:"Coverage Area & Spacing Rules", q:"Extended-coverage sprinklers in light hazard may be listed for a maximum protection area of up to:", opts:["225 ft²","130 ft²","400 ft²","100 ft²"], correct:2, re:"EC sprinklers can be listed for coverage up to 400 ft² (e.g., 20 ft × 20 ft) in light hazard, well beyond the 225 ft² limit for standard spray, but only within their specific listing."},
  {id:132, block:2, sec:"Coverage Area & Spacing Rules", q:"Extended-coverage sprinklers must be installed:", opts:["At any spacing the designer chooses","Without hydraulic calculation","Only in extra-hazard occupancies","Strictly within the protection area and spacing limits stated in their individual listing"], correct:3, re:"EC sprinkler spacing/area limits come from the manufacturer's listing rather than the generic standard-spray tables, so they must be applied exactly as listed."},
  {id:133, block:2, sec:"Coverage Area & Spacing Rules", q:"A sprinkler is located 7 ft from one wall and 6 ft from the next sprinkler along the branch line. The value of S used for the protection-area calculation is:", opts:["6 ft","7 ft","13 ft","14 ft"], correct:3, re:"S is the greater of twice the wall distance (2 × 7 = 14 ft) or the sprinkler spacing (6 ft); therefore S = 14 ft."},
  {id:134, block:2, sec:"Coverage Area & Spacing Rules", q:"If sprinklers are 12 ft apart along the branch (S = 12 ft) and branch lines are 10 ft apart (L = 10 ft), the protection area per sprinkler is:", opts:["120 ft²","22 ft²","144 ft²","100 ft²"], correct:0, re:"A_s = S × L = 12 ft × 10 ft = 120 ft², which must not exceed the hazard's maximum allowable protection area."},
  {id:135, block:2, sec:"Obstruction & Clearance Design", q:"NFPA 13's 'three-times rule' for standard-spray sprinklers requires that a sprinkler be positioned away from an obstruction a horizontal distance of at least:", opts:["Three times the maximum dimension of the obstruction (e.g., width of a duct), up to 24 in maximum","Three times the sprinkler spacing","Three feet in all cases","One-half the obstruction height"], correct:0, re:"The three-times rule: keep the sprinkler at least three times the obstruction's maximum dimension away (max 24 in) so spray can pass on both sides. (For extended-coverage sprinklers a four-times rule applies, max 36 in.)"},
  {id:136, block:2, sec:"Obstruction & Clearance Design", q:"The three-times rule caps the required horizontal clearance from an obstruction at a maximum of:", opts:["12 in","18 in","24 in","36 in"], correct:2, re:"Even for very large obstructions, the three-times rule for standard-spray sprinklers caps the required horizontal distance at 24 in."},
  {id:137, block:2, sec:"Obstruction & Clearance Design", q:"For extended-coverage sprinklers, the analogous obstruction rule is the 'four-times rule,' with a maximum clearance of:", opts:["24 in","36 in","48 in","12 in"], correct:1, re:"EC sprinklers follow a four-times rule (four times the obstruction dimension), capped at 36 in, reflecting their larger throw."},
  {id:138, block:2, sec:"Obstruction & Clearance Design", q:"Under the 'beam rule,' a sprinkler deflector positioned at or above the bottom of a beam/obstruction must be separated horizontally from that obstruction by at least:", opts:["12 in (1 ft)","6 in","24 in","36 in"], correct:0, re:"The beam rule requires at least 1 ft (12 in) of horizontal separation when the deflector is any distance above the bottom of the obstruction, increasing as the deflector rises (per the standard's deflector-above-bottom-of-obstruction table)."},
  {id:139, block:2, sec:"Obstruction & Clearance Design", q:"Continuous obstructions wider than what dimension generally require sprinklers to be installed beneath them?", opts:["More than 2 ft","More than 4 ft","More than 6 ft","More than 8 ft"], correct:1, re:"NFPA 13 generally requires sprinklers under fixed obstructions more than 4 ft wide (e.g., wide ducts, decks, tables) because the obstruction shields the floor below."},
  {id:140, block:2, sec:"Obstruction & Clearance Design", q:"When a sprinkler must be installed beneath a wide obstruction, its deflector should be located within what distance of the bottom of the obstruction?", opts:["Within 18 in","Within 12 in","Within 24 in","Within 36 in"], correct:1, re:"NFPA 13 requires the deflector of a sprinkler under a wide obstruction to be no more than 12 in below the bottom of that obstruction so the pattern develops properly underneath."},
  {id:141, block:2, sec:"Obstruction & Clearance Design", q:"The minimum vertical clearance from a standard-spray sprinkler deflector to the TOP OF STORAGE must be at least:", opts:["12 in","24 in","18 in","36 in"], correct:2, re:"NFPA 13 requires a minimum 18 in clearance between the deflector and the top of storage so the discharge pattern can fully develop before reaching the commodity."},
  {id:142, block:2, sec:"Obstruction & Clearance Design", q:"For ESFR sprinklers, the minimum clearance from the deflector to the top of storage is:", opts:["18 in","24 in","36 in","12 in"], correct:2, re:"ESFR storage protection requires a minimum 36 in clearance from deflector to top of storage — greater than the 18 in used for standard spray — to allow the suppression-mode discharge to develop."},
  {id:143, block:2, sec:"Obstruction & Clearance Design", q:"For unobstructed construction, the deflector of a standard-spray pendent or upright sprinkler must be positioned how far below the ceiling?", opts:["A maximum of 36 in below the ceiling","Exactly 6 in below the ceiling","A minimum of 4 in below the ceiling","A minimum of 1 in and a maximum of 12 in below the ceiling"], correct:3, re:"NFPA 13: under unobstructed (smooth) ceilings, standard-spray pendent/upright deflectors are placed 1 in to 12 in below the ceiling to balance heat collection against pattern development."},
  {id:144, block:2, sec:"Obstruction & Clearance Design", q:"For standard sidewall spray sprinklers, the deflector is generally located how far below the ceiling?", opts:["1 in to 6 in","12 in to 18 in","4 in to 6 in","18 in to 24 in"], correct:2, re:"NFPA 13 generally requires sidewall sprinkler deflectors 4 in to 6 in below the ceiling (special listings may permit 6 in to 18 in)."},
  {id:145, block:2, sec:"Obstruction & Clearance Design", q:"The purpose of obstruction rules in sprinkler layout is fundamentally to:", opts:["Increase the sprinkler's K-factor","Reduce the temperature rating required","Ensure the discharge pattern reaches the floor/hazard without being blocked or shadowed","Allow wider maximum spacing"], correct:2, re:"Obstruction rules protect the developed water distribution pattern from being blocked or 'shadowed,' which would leave unprotected areas — the core reason for the three-times/beam/under-obstruction rules."},
  {id:146, block:2, sec:"Obstruction & Clearance Design", q:"A 24-in-wide duct runs below the ceiling. Applying the three-times rule, the sprinkler should be located at least how far horizontally from the near edge of the duct?", opts:["72 in","24 in (capped by the 24 in maximum)","12 in","48 in"], correct:1, re:"Three times the 24 in dimension is 72 in, but the rule caps the required horizontal distance at 24 in maximum; therefore 24 in is required."},
  {id:147, block:2, sec:"Obstruction & Clearance Design", q:"Sprinklers below an open grate or grid-type obstruction:", opts:["Are never required regardless of size","May not be required if the obstruction is open enough to pass water/heat, per the standard's provisions","Always require ESFR heads","Must be spaced at 4 ft maximum"], correct:1, re:"Open grating that allows heat and water to pass can be treated differently from solid obstructions; NFPA 13 has specific provisions for open/grate construction rather than blanket under-sprinkler requirements."},
  {id:148, block:2, sec:"Obstruction & Clearance Design", q:"When sprinklers are spaced closer than 6 ft, the baffle between them must:", opts:["Be combustible to burn away early","Be installed only on sidewall sprinklers","Be at least 24 in tall","Be solid and rigid, sized to shield the operating elements, and remain in place during operation"], correct:3, re:"NFPA 13 requires a solid, rigid baffle (roughly 8 in long, 6 in high, set between the deflectors) that stays in place before and during operation to shield adjacent operating elements."},
  {id:149, block:2, sec:"Obstruction & Clearance Design", q:"A pendant light fixture 10 in across hangs below a standard-spray ceiling sprinkler. Under the three-times rule, the minimum required horizontal clearance to the sprinkler is:", opts:["24 in (the rule's cap, since 3 × 10 in = 30 in exceeds 24 in)","5 in","10 in","30 in"], correct:0, re:"Three times the 10 in dimension is 30 in, but the three-times rule caps the required horizontal clearance at 24 in maximum; therefore only 24 in is required, not the 30 in arithmetic value."},
  {id:150, block:2, sec:"Obstruction & Clearance Design", q:"For obstructions against a wall (such as a soffit) that a sidewall sprinkler must throw over, the designer must verify:", opts:["The K-factor is at least 11.2","The obstruction does not interrupt the sprinkler's listed horizontal throw and the deflector clears it per the standard","The temperature rating is high","The minimum spacing is 4 ft"], correct:1, re:"Sidewall layout must keep soffits, light coves, and similar wall obstructions out of the listed discharge path so the pattern is not blocked, consistent with NFPA 13 obstruction provisions."},
  {id:151, block:2, sec:"Obstruction & Clearance Design", q:"The minimum 18-in clearance to storage is increased to 36 in for which stored commodity?", opts:["Rubber tires","Paper records","Canned food","Empty pallets"], correct:0, re:"NFPA 13 requires at least 36 in clearance from standard-spray deflectors when rubber tires are stored, reflecting the severe fire challenge of tire storage."},
  {id:152, block:2, sec:"Special Applications (ESFR/Storage)", q:"The maximum protection area per ESFR sprinkler is:", opts:["130 ft²","144 ft²","225 ft²","100 ft²"], correct:3, re:"NFPA 13 limits ESFR sprinkler coverage to a maximum of 100 ft² per sprinkler."},
  {id:153, block:2, sec:"Special Applications (ESFR/Storage)", q:"The maximum distance between ESFR sprinklers is:", opts:["12 ft","15 ft","20 ft","8 ft"], correct:0, re:"ESFR sprinklers have a maximum spacing of 12 ft between heads (with additional limits at high ceiling heights)."},
  {id:154, block:2, sec:"Special Applications (ESFR/Storage)", q:"The minimum spacing between ESFR sprinklers is:", opts:["8 ft","6 ft","4 ft","10 ft"], correct:0, re:"NFPA 13 sets an 8 ft minimum spacing between ESFR sprinklers (greater than the 6 ft minimum for standard spray) to avoid cold-soldering of the fast-response elements."},
  {id:155, block:2, sec:"Special Applications (ESFR/Storage)", q:"ESFR stands for:", opts:["Extended Spray Fire Resistant","Enhanced Storage Flow Regulator","Extra Spacing Flow Rated","Early Suppression Fast Response"], correct:3, re:"ESFR = Early Suppression Fast Response, a fast-response sprinkler designed to suppress storage fires from the ceiling rather than merely control them."},
  {id:156, block:2, sec:"Special Applications (ESFR/Storage)", q:"The fundamental difference between a 'suppression-mode' ESFR sprinkler and a 'control-mode' sprinkler is that ESFR aims to:", opts:["Pre-wet adjacent commodities only","Actually extinguish/suppress the fire by delivering a large volume quickly to the seat of the fire","Operate at a higher temperature","Reduce the number of in-rack levels by one"], correct:1, re:"ESFR delivers a high, fast discharge intended to suppress (knock down) the fire, whereas control-mode sprinklers aim to control fire spread and pre-wet surroundings until manual extinguishment."},
  {id:157, block:2, sec:"Special Applications (ESFR/Storage)", q:"ESFR ceiling protection is hydraulically designed on the basis of:", opts:["A density over an area","Pipe schedule only","A fixed 0.20 gpm/ft² density","A minimum operating PRESSURE for a specified number of sprinklers (e.g., the most remote 12)"], correct:3, re:"ESFR design is pressure-based: the listing specifies a minimum operating pressure for a set number of design sprinklers (commonly the hydraulically most demanding 12, four on each of three lines), not a density/area."},
  {id:158, block:2, sec:"Special Applications (ESFR/Storage)", q:"Typical nominal K-factors for ESFR sprinklers include:", opts:["K-2.8 and K-4.2","K-14.0, K-16.8, K-22.4 and K-25.2","K-5.6 only","K-1.4"], correct:1, re:"ESFR sprinklers use large orifices — common nominal K-factors are K-14.0, K-16.8, K-22.4, and K-25.2 — to deliver the high flows needed for suppression."},
  {id:159, block:2, sec:"Special Applications (ESFR/Storage)", q:"ESFR systems are generally NOT permitted on which pipe system type because a delay in water delivery undermines suppression?", opts:["Wet-pipe systems","Dry-pipe systems (except where specifically listed/permitted)","Gridded systems","Looped systems"], correct:1, re:"Because suppression depends on immediate, full-flow delivery, ESFR is generally applied on wet-pipe systems; dry systems delay water and are restricted to specifically listed arrangements."},
  {id:160, block:2, sec:"Special Applications (ESFR/Storage)", q:"In-rack sprinklers are added to a storage design primarily to:", opts:["Replace the ceiling sprinklers","Lower the storage clearance requirement","Increase ceiling spacing","Provide protection within the rack where ceiling discharge cannot reach the fire"], correct:3, re:"In-rack sprinklers protect inside the storage array where ceiling discharge is blocked by upper loads; they supplement (not replace) ceiling protection when the ceiling-only option is inadequate."},
  {id:161, block:2, sec:"Special Applications (ESFR/Storage)", q:"A key advantage of selecting ESFR ceiling protection for rack storage is that, within its listing, it can:", opts:["Reduce the required clearance to 6 in","Remove the need for a water supply","Allow unlimited storage height","Eliminate the need for in-rack sprinklers"], correct:3, re:"A primary design benefit of ESFR is that, within listed ceiling height and storage height limits, it can protect rack storage from the ceiling alone, eliminating in-rack sprinklers."},
  {id:162, block:2, sec:"Special Applications (ESFR/Storage)", q:"The clearance from ESFR deflectors to the top of storage must be a minimum of:", opts:["18 in","24 in","36 in","12 in"], correct:2, re:"ESFR requires a minimum 36 in clearance from deflector to top of storage, double the 18 in used for standard spray, so the suppression discharge can develop."},
  {id:163, block:2, sec:"Special Applications (ESFR/Storage)", q:"Storage occupancy protection criteria depend most directly on which set of variables?", opts:["Only the building's total floor area","Only the sprinkler color","Commodity class, storage method/height, and ceiling height","The number of exits"], correct:2, re:"Storage design (densities, ESFR pressures, in-rack needs) is driven by commodity classification, storage arrangement and height, and ceiling height — the core variables in NFPA 13 storage chapters."},
  {id:164, block:2, sec:"Special Applications (ESFR/Storage)", q:"CMSA (Control Mode Specific Application) sprinklers differ from ESFR in that CMSA sprinklers are intended to:", opts:["Control the fire (limit growth and pre-wet) rather than suppress it","Suppress the fire fully","Operate only as open deluge heads","Provide residential life-safety coverage"], correct:0, re:"CMSA is a control-mode technology (large droplets, high momentum) intended to control storage fires, whereas ESFR is a suppression-mode technology aiming to extinguish the fire."},
  {id:165, block:2, sec:"Special Applications (ESFR/Storage)", q:"For storage protection, NFPA 13 generally requires a sprinkler nominal K-factor of at least:", opts:["K-8.0","K-4.2","K-2.8","K-1.4"], correct:0, re:"Storage densities require larger orifices; NFPA 13 storage criteria generally require K-8.0 or larger (CMSA and ESFR use even larger K-factors)."},
  {id:166, block:2, sec:"Special Applications (ESFR/Storage)", q:"When ESFR cannot be used (for example because storage or ceiling height exceeds its listing), a common alternative ceiling design approach for storage is:", opts:["Residential sprinklers","Open deluge with no detection","CMSA or control-mode density/area protection, possibly with in-rack sprinklers","Sidewall sprinklers only"], correct:2, re:"Where ESFR limits are exceeded, designers fall back to control-mode (CMSA or standard control-mode density/area) ceiling protection, often combined with in-rack sprinklers."},
  {id:167, block:2, sec:"Special Applications (ESFR/Storage)", q:"A primary reason in-rack sprinklers may be required even with control-mode ceiling sprinklers is that:", opts:["The ceiling sprinklers are too cold","In-rack sprinklers replace the fire pump","Ceiling sprinklers cannot reach a fire deep within tall racks","The commodity is non-combustible"], correct:2, re:"Tall, dense rack storage blocks ceiling discharge from reaching lower-level fires; in-rack sprinklers place water within the array to address this shielding."},
  {id:168, block:2, sec:"Special Applications (ESFR/Storage)", q:"ESFR protection effectiveness is most sensitive to obstructions because:", opts:["Obstructions can deflect the high-momentum discharge and prevent it from reaching the fire's seat","Its droplets are very small and easily blocked","It uses a low operating pressure","It operates as a control-mode head"], correct:0, re:"ESFR relies on a high-momentum stream penetrating the plume to the fire; obstructions near the heads can divert that discharge, so ESFR has stringent obstruction (and clearance) rules."},
  {id:169, block:2, sec:"Temperature & Response Selection", q:"The temperature-classification range for an ORDINARY-temperature sprinkler is:", opts:["135–170°F","100–134°F","175–225°F","250–300°F"], correct:0, re:"NFPA 13: ordinary-temperature sprinklers carry a temperature rating of 135–170°F (commonly 135°F or 155°F)."},
  {id:170, block:2, sec:"Temperature & Response Selection", q:"The temperature-classification range for an INTERMEDIATE-temperature sprinkler is:", opts:["135–170°F","250–300°F","175–225°F","325–375°F"], correct:2, re:"NFPA 13: intermediate-temperature sprinklers are rated 175–225°F (e.g., 200°F)."},
  {id:171, block:2, sec:"Temperature & Response Selection", q:"The temperature-classification range for a HIGH-temperature sprinkler is:", opts:["250–300°F","175–225°F","135–170°F","100–134°F"], correct:0, re:"NFPA 13: high-temperature sprinklers are rated 250–300°F, used where elevated ambient temperatures are expected."},
  {id:172, block:2, sec:"Temperature & Response Selection", q:"Sprinklers near a unit heater, skylight, or other heat source generally require:", opts:["A lower (ordinary) temperature rating","Quick-response only","A higher temperature rating to avoid premature/nuisance operation","A larger K-factor"], correct:2, re:"NFPA 13 requires intermediate- or high-temperature sprinklers near heat sources (unit heaters, skylights, mechanical equipment) so normal ambient heat does not cause unintended operation."},
  {id:173, block:2, sec:"Temperature & Response Selection", q:"The standardized glass-bulb liquid color for an ORDINARY-temperature (135°F) sprinkler is:", opts:["Orange (or red for 155°F)","Green","Blue","Mauve"], correct:0, re:"Glass-bulb color codes: 135°F is orange and 155°F is red (both ordinary class). The color indicates the operating temperature, independent of response speed."},
  {id:174, block:2, sec:"Temperature & Response Selection", q:"For a glass-bulb sprinkler, a YELLOW or GREEN bulb indicates which temperature class?", opts:["Intermediate","Ordinary","High","Extra high"], correct:0, re:"Yellow (175°F) and green (200°F) glass bulbs denote the intermediate temperature class per NFPA 13's color code."},
  {id:175, block:2, sec:"Temperature & Response Selection", q:"The maximum expected ambient ceiling temperature drives the selection of the sprinkler's:", opts:["K-factor","Deflector style","Response class (QR/SR)","Temperature rating"], correct:3, re:"Temperature rating is selected so the sprinkler will not operate from normal ambient heat; NFPA 13 ties the rating to the maximum expected ambient temperature at the ceiling."},
  {id:176, block:2, sec:"Temperature & Response Selection", q:"A quick-response (QR) sprinkler is defined by a Response Time Index (RTI) of:", opts:["80 (m·s)^1/2 or more","50 (m·s)^1/2 or less","Exactly 100 (m·s)^1/2","Greater than 350 (m·s)^1/2"], correct:1, re:"Fast/quick-response elements have an RTI of 50 (m·s)^1/2 or less; standard-response elements have an RTI of 80 (m·s)^1/2 or more."},
  {id:177, block:2, sec:"Temperature & Response Selection", q:"A standard-response (SR) sprinkler has a Response Time Index (RTI) of approximately:", opts:["50 or less","Always 250","Always 100","80 or more"], correct:3, re:"Standard-response sprinklers have an RTI of about 80 (m·s)^1/2 or greater, meaning a thicker thermal element that responds more slowly than quick-response (RTI ≤ 50)."},
  {id:178, block:2, sec:"Temperature & Response Selection", q:"In a wet-pipe LIGHT-hazard occupancy, NFPA 13 generally requires which response class?", opts:["Standard-response","Quick-response","High-temperature only","Open sprinklers"], correct:1, re:"NFPA 13 generally requires quick-response sprinklers throughout wet-pipe light-hazard occupancies to improve life safety, with limited exceptions."},
  {id:179, block:2, sec:"Temperature & Response Selection", q:"Quick-response and standard-response sprinklers within the same compartment:", opts:["May be freely mixed","Must use the same K-factor only","Must both be high-temperature","Shall not be intermixed in the same compartment"], correct:3, re:"NFPA 13 prohibits intermixing QR and SR sprinklers in the same compartment because the hydraulic/operating design assumes a consistent response behavior across the design area."},
  {id:180, block:2, sec:"Temperature & Response Selection", q:"Response class (QR vs SR) is governed by the sprinkler's:", opts:["Orifice size (K-factor)","Thermal sensitivity / RTI of the operating element","Temperature rating only","Deflector orientation"], correct:1, re:"Response class is a function of the operating element's thermal sensitivity, expressed as RTI; it is independent of the temperature rating and the K-factor."},
  {id:181, block:2, sec:"Temperature & Response Selection", q:"A residential sprinkler's fast-response element is selected primarily to:", opts:["Operate sooner to improve occupant tenability and escape time","Increase discharge density","Raise the temperature rating","Permit wider spacing in warehouses"], correct:0, re:"Residential sprinklers use fast-response elements so they actuate early, maintaining tenable conditions for occupants to escape — the life-safety basis of the residential listing."},
  {id:182, block:2, sec:"Temperature & Response Selection", q:"Two sprinklers of the same K-factor and temperature rating can still differ in performance because they may have different:", opts:["Response classes (RTI), i.e., quick vs standard response","Pipe thread sizes","Paint colors only","Listing agencies"], correct:0, re:"Temperature rating sets the operating temperature, but RTI (response class) sets how fast the element reaches it; two otherwise-identical sprinklers can be QR or SR."},
  {id:183, block:2, sec:"Temperature & Response Selection", q:"For a frame-style (non-bulb) sprinkler, the temperature class is identified by:", opts:["The thread size","A color applied to the frame arms (or the link color)","The deflector size","The cover plate shape"], correct:1, re:"NFPA 13 specifies frame-arm color coding for solder-type sprinklers (e.g., uncolored/black = ordinary, white = intermediate, blue = high) to indicate the temperature class."},
  {id:184, block:2, sec:"Temperature & Response Selection", q:"ESFR sprinklers are inherently which response class?", opts:["Standard-response","Variable","Fast-response (RTI ≤ 50)","High-temperature only"], correct:2, re:"ESFR means Early Suppression FAST Response; the element is fast-response (RTI ≤ 50) so the sprinkler opens early enough to suppress the storage fire."},
  {id:185, block:2, sec:"Temperature & Response Selection", q:"Where a glass-bulb sprinkler shows a BLUE bulb, the temperature class is:", opts:["Ordinary","High (286°F)","Intermediate","Residential"], correct:1, re:"A blue glass bulb corresponds to 286°F, which falls in the high-temperature class per NFPA 13's bulb color code."},
  {id:186, block:2, sec:"Hazard-Based Design Density", q:"In the density/area method, 'density' is expressed in units of:", opts:["gpm per sprinkler","gpm/ft² (gallons per minute per square foot)","psi per ft²","ft² per sprinkler"], correct:1, re:"Design density is the discharge per unit floor area, gpm/ft², applied over the design area to set the hydraulic demand."},
  {id:187, block:2, sec:"Hazard-Based Design Density", q:"A typical LIGHT-hazard design density used with the density/area method is approximately:", opts:["0.05 gpm/ft²","0.30 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²"], correct:3, re:"Light hazard is commonly designed around 0.10 gpm/ft² over the design area (e.g., 1,500 ft² for the curve method)."},
  {id:188, block:2, sec:"Hazard-Based Design Density", q:"A representative ORDINARY-hazard Group 2 design point is:", opts:["0.10 gpm/ft² over 1,500 ft²","0.20 gpm/ft² over 1,500 ft²","0.05 gpm/ft² over 3,000 ft²","0.60 gpm/ft² over 2,500 ft²"], correct:1, re:"Ordinary Hazard Group 2 is commonly 0.20 gpm/ft² applied over a 1,500 ft² design area in the density/area method."},
  {id:189, block:2, sec:"Hazard-Based Design Density", q:"The minimum discharge required from a single sprinkler equals:", opts:["The design density divided by the area","The K-factor times the area","The design density multiplied by the sprinkler's protection area (A_s)","The pressure times the K-factor"], correct:2, re:"Minimum flow from a sprinkler = density (gpm/ft²) × protection area A_s (ft²). This sets the minimum pressure via Q = K√P."},
  {id:190, block:2, sec:"Hazard-Based Design Density", q:"A sprinkler protecting 130 ft² at an ordinary-hazard density of 0.20 gpm/ft² must discharge at least:", opts:["13 gpm","26 gpm","6.5 gpm","65 gpm"], correct:1, re:"Required flow = density × area = 0.20 gpm/ft² × 130 ft² = 26 gpm minimum from that sprinkler."},
  {id:191, block:2, sec:"Hazard-Based Design Density", q:"In the density/area approach, increasing the assumed design AREA generally:", opts:["Raises the required density along the curve (more area at a slightly lower density, or vice versa) per the design curve","Lowers the required density","Has no effect on demand","Eliminates hydraulic calculation"], correct:0, re:"The classic density/area curves trade density against area: selecting a larger area changes the density per the curve. (NFPA 13's 2022 edition limited and the 2025 edition removed these curves in favor of a single design point.)"},
  {id:192, block:2, sec:"Hazard-Based Design Density", q:"The hazard classification of an occupancy is selected based primarily on:", opts:["The quantity and combustibility of contents and the expected fire challenge","The building's height only","The sprinkler color","The number of stories"], correct:0, re:"NFPA 13 classifies occupancies (light, ordinary 1/2, extra 1/2) by the combustibility and quantity of contents and the rate of heat release expected — the basis for density and area selection."},
  {id:193, block:2, sec:"Hazard-Based Design Density", q:"Which occupancy example is typically classified as LIGHT hazard?", opts:["Auto repair garage","Paint-spray operation","Office, church, or school classroom","Flammable-liquids warehouse"], correct:2, re:"Offices, churches, and schools are classic light-hazard occupancies (low combustible loading). Repair garages are ordinary; spray and flammable-liquid storage are extra hazard."},
  {id:194, block:2, sec:"Hazard-Based Design Density", q:"Which example is typically classified as ORDINARY hazard (Group 2)?", opts:["A private office","A library reading room","A machine shop or auto repair area","A residential bedroom"], correct:2, re:"Machine shops and repair garages are representative Ordinary Hazard Group 2 occupancies, with moderate-to-high combustible content and heat-release rate."},
  {id:195, block:2, sec:"Hazard-Based Design Density", q:"Which example is typically classified as EXTRA hazard?", opts:["A classroom","A retail dry-goods sales area","A hotel guest room","A flammable-liquid spray or hydraulic-fluid process area"], correct:3, re:"Flammable-liquid spraying and combustible-hydraulic-fluid processes are extra-hazard occupancies, requiring the highest densities and tightest spacing."},
  {id:196, block:2, sec:"Hazard-Based Design Density", q:"Extra-hazard occupancies require higher density AND tighter spacing primarily because:", opts:["The ceilings are always higher","The sprinklers must be a specific color","The fires develop and spread faster and release more heat, demanding more water sooner over the area","The buildings are larger"], correct:2, re:"Extra hazard involves rapid fire growth and high heat-release rates, so NFPA 13 mandates greater densities and closer spacing (12 ft / ≤130 ft²) to apply more water quickly across the design area."},
  {id:197, block:2, sec:"Hazard-Based Design Density", q:"For storage occupancies, the ceiling design demand is most commonly expressed as:", opts:["Pressure only, with no flow","A single fixed flow regardless of commodity","A density (gpm/ft²) over a design area, or as an ESFR operating pressure for a set number of heads","The K-factor alone"], correct:2, re:"Storage ceiling protection is specified either as a density/area (control mode) or, for ESFR, as a minimum operating pressure for a defined number of design sprinklers."},
  {id:198, block:2, sec:"Hazard-Based Design Density", q:"The 'design area' (or remote area) in the density/area method represents:", opts:["The hydraulically most demanding area assumed to be operating in a fire","The entire building floor area","Only the area directly under the riser","The area covered by one sprinkler"], correct:0, re:"The design/remote area is the most hydraulically demanding portion of the system assumed to operate; the density is applied across it to size the demand at the base of the riser."},
  {id:199, block:2, sec:"Hazard-Based Design Density", q:"When a system uses quick-response sprinklers in a light- or ordinary-hazard wet-pipe system, NFPA 13 historically permitted a design-area:", opts:["Increase of 30%","Doubling","Reduction (up to 40% under stated conditions), reflecting earlier operation of fewer heads","Elimination of the hose allowance"], correct:2, re:"NFPA 13 historically allowed a design-area reduction (up to 40% under specified ceiling/slope conditions) for quick-response sprinklers in wet light/ordinary-hazard systems, because faster operation limits the number of sprinklers expected to open."},
  {id:200, block:2, sec:"Hazard-Based Design Density", q:"Selecting the correct hazard classification is the foundational design step because it determines:", opts:["Only the paint color of the pipe","The building's occupancy permit","The density, design area, maximum spacing, and maximum protection area used for the entire layout","The fire department response time"], correct:2, re:"Hazard classification sets density, design/remote area, maximum spacing, and maximum protection area per sprinkler — every downstream layout and hydraulic decision flows from it (NFPA 13 occupancy and design chapters)."},
  {id:201, block:3, sec:"Density/Area Method", q:"In the density/area design method, what does the design 'density' express?", opts:["The number of sprinklers per 100 ft² of floor","The friction loss per foot of branch line","The weight of water stored per cubic foot of space","The minimum discharge per unit floor area, in gpm per square foot"], correct:3, re:"Density is the minimum required application rate over the design area, expressed in gpm/ft² (NFPA 13, density/area design method)."},
  {id:202, block:3, sec:"Density/Area Method", q:"For a Light Hazard occupancy, the commonly specified design density is closest to which value?", opts:["0.05 gpm/ft²","0.40 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²"], correct:3, re:"Light Hazard is typically designed at about 0.10 gpm/ft² over the most remote design area (NFPA 13 density/area curves, Light Hazard)."},
  {id:203, block:3, sec:"Density/Area Method", q:"Ordinary Hazard Group 1 is most commonly designed at which density over 1,500 ft²?", opts:["0.15 gpm/ft²","0.12 gpm/ft²","0.10 gpm/ft²","0.30 gpm/ft²"], correct:0, re:"Ordinary Hazard Group 1 single-point design is 0.15 gpm/ft² over 1,500 ft² (NFPA 13 density/area design)."},
  {id:204, block:3, sec:"Density/Area Method", q:"Ordinary Hazard Group 2 is most commonly designed at which density over 1,500 ft²?", opts:["0.40 gpm/ft²","0.15 gpm/ft²","0.10 gpm/ft²","0.20 gpm/ft²"], correct:3, re:"Ordinary Hazard Group 2 single-point design is 0.20 gpm/ft² over 1,500 ft² (NFPA 13 density/area design)."},
  {id:205, block:3, sec:"Density/Area Method", q:"On the NFPA 13 density/area curves, as the selected DESIGN AREA increases for a given hazard, the required density generally does what?", opts:["Increases","Decreases","Stays exactly the same","Doubles"], correct:1, re:"The curves slope so that a larger remote area is paired with a lower density (and a smaller area with a higher density) for the same hazard (NFPA 13 density/area curve concept)."},
  {id:206, block:3, sec:"Density/Area Method", q:"A designer chooses a density of 0.15 gpm/ft² over a 1,500 ft² design area. The theoretical minimum SPRINKLER discharge demanded over that area totals how much (before hose, friction, and overdischarge)?", opts:["150 gpm","1,500 gpm","300 gpm","225 gpm"], correct:3, re:"Density × area = 0.15 × 1,500 = 225 gpm is the minimum sprinkler discharge over the design area (NFPA 13 density/area method)."},
  {id:207, block:3, sec:"Density/Area Method", q:"For an Extra Hazard Group 2 design at 0.40 gpm/ft² over 2,500 ft², the minimum sprinkler discharge over the design area is:", opts:["250 gpm","1,000 gpm","625 gpm","2,500 gpm"], correct:1, re:"0.40 gpm/ft² × 2,500 ft² = 1,000 gpm minimum sprinkler discharge over the area (NFPA 13 density/area method, Extra Hazard)."},
  {id:208, block:3, sec:"Density/Area Method", q:"Within the density/area method, the minimum required discharge from a SINGLE sprinkler equals:", opts:["The K-factor multiplied by the design area","The density multiplied by the floor area that sprinkler protects","The hose allowance divided by the number of heads","The static pressure multiplied by 0.433"], correct:1, re:"Per-sprinkler minimum flow = density × the coverage area assigned to that sprinkler (NFPA 13 density/area design)."},
  {id:209, block:3, sec:"Density/Area Method", q:"A sprinkler covers 130 ft² in a space designed to 0.15 gpm/ft². Its minimum required discharge is:", opts:["13.0 gpm","15.0 gpm","19.5 gpm","26.0 gpm"], correct:2, re:"0.15 gpm/ft² × 130 ft² = 19.5 gpm minimum discharge for that sprinkler (NFPA 13 density/area method)."},
  {id:210, block:3, sec:"Density/Area Method", q:"A Light Hazard sprinkler covers 200 ft² at a design density of 0.10 gpm/ft². Its minimum required discharge is:", opts:["10 gpm","20 gpm","30 gpm","200 gpm"], correct:1, re:"0.10 gpm/ft² × 200 ft² = 20 gpm minimum discharge for that head (NFPA 13 density/area method)."},
  {id:211, block:3, sec:"Density/Area Method", q:"In the density/area method, the design area is intended to represent which portion of the system?", opts:["The area nearest the riser","The entire floor of the building","The most hydraulically remote/demanding area","Only the corridor sprinklers"], correct:2, re:"The design area models the most hydraulically remote (demanding) group of sprinklers; if it is satisfied, closer areas are too (NFPA 13 density/area method)."},
  {id:212, block:3, sec:"Density/Area Method", q:"Which pair of variables defines a point on an NFPA 13 density/area curve?", opts:["Pressure and velocity","Density and design area","K-factor and elevation","C-value and pipe diameter"], correct:1, re:"Each curve is plotted with density (gpm/ft²) on one axis and design area (ft²) on the other (NFPA 13 density/area curves)."},
  {id:213, block:3, sec:"Density/Area Method", q:"If the actual discharge from each sprinkler in the design area exceeds the minimum required by density, the designer should use:", opts:["The minimum density flow only","Half the calculated flow","The actual (higher) calculated flow at each head","The hose stream flow"], correct:2, re:"Sprinklers closer to the source run at higher pressure and discharge MORE than the minimum; the calculation must use each head's actual flow, never less than the density minimum (NFPA 13 hydraulic calc)."},
  {id:214, block:3, sec:"Density/Area Method", q:"The density/area method ensures adequate water by guaranteeing a minimum:", opts:["Application rate over a defined operating area","Pipe wall thickness","Sprinkler temperature rating","Number of zone control valves"], correct:0, re:"It guarantees a minimum application density delivered over the chosen design (operating) area (NFPA 13 density/area method)."},
  {id:215, block:3, sec:"Density/Area Method", q:"For Extra Hazard occupancies, the maximum design area on the curves is generally:", opts:["1,500 ft²","2,500 ft²","5,000 ft²","10,000 ft²"], correct:1, re:"Extra Hazard design areas range up to about 2,500 ft² on the density/area curves (NFPA 13 density/area, Extra Hazard)."},
  {id:216, block:3, sec:"Density/Area Method", q:"Compared with Light Hazard, an Extra Hazard occupancy requires:", opts:["Lower density and smaller area","Higher density and a larger water demand","The same density but lower pressure","No hydraulic calculation"], correct:1, re:"Extra Hazard uses much higher densities (0.30–0.40 gpm/ft²) and larger total demand than Light Hazard (~0.10) (NFPA 13 hazard classifications)."},
  {id:217, block:3, sec:"Density/Area Method", q:"The minimum operating density chosen for a design must be at least the value required for the:", opts:["Color of the building","Occupancy hazard classification","Sprinkler manufacturer's logo","Local water bill rate"], correct:1, re:"Required density is set by the occupancy hazard classification (Light, Ordinary, Extra) (NFPA 13 density/area method)."},
  {id:218, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"The basic sprinkler discharge equation is:", opts:["Q = K × P","Q = K ÷ P","Q = K × √P","Q = P × √K"], correct:2, re:"Sprinkler flow Q (gpm) = K√P, where P is the pressure at the orifice in psi (NFPA 13 hydraulic calculation; K-factor formula)."},
  {id:219, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"In Q = K√P, the units of Q and P are normally:", opts:["Q in cfm and P in inches of water","Q in psi and P in gpm","Q in gpm and P in psi","Q in liters and P in bar"], correct:2, re:"In US sprinkler practice Q is gallons per minute (gpm) and P is pounds per square inch (psi) (NFPA 13 hydraulic calc)."},
  {id:220, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A standard-orifice (1/2 in.) spray sprinkler has a nominal K-factor closest to:", opts:["2.8","5.6","11.2","25.2"], correct:1, re:"The standard 1/2 in. orifice spray sprinkler has a nominal K of 5.6 (NFPA 13; standard spray sprinkler K-factor)."},
  {id:221, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A K=5.6 sprinkler operates at 25 psi. Its discharge is:", opts:["28.0 gpm","14.0 gpm","56.0 gpm","140 gpm"], correct:0, re:"Q = 5.6×√25 = 5.6×5 = 28.0 gpm (Q=K√P, NFPA 13)."},
  {id:222, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A K=8.0 sprinkler operates at 25 psi. Its discharge is:", opts:["40.0 gpm","32.0 gpm","20.0 gpm","64.0 gpm"], correct:0, re:"Q = 8.0×√25 = 8.0×5 = 40.0 gpm (Q=K√P, NFPA 13)."},
  {id:223, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A K=11.2 sprinkler operates at 25 psi. Its discharge is:", opts:["44.8 gpm","50.0 gpm","112 gpm","56.0 gpm"], correct:3, re:"Q = 11.2×√25 = 11.2×5 = 56.0 gpm (Q=K√P, NFPA 13)."},
  {id:224, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"To find pressure when flow and K are known, rearrange to:", opts:["P = (Q/K)²","P = Q×K","P = K/Q²","P = √(Q×K)"], correct:0, re:"Solving Q=K√P for P gives P = (Q/K)² (NFPA 13 hydraulic calc)."},
  {id:225, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A K=5.6 head must discharge 28 gpm. The required pressure is:", opts:["5 psi","25 psi","20 psi","50 psi"], correct:1, re:"P = (Q/K)² = (28/5.6)² = 5² = 25 psi (NFPA 13 hydraulic calc)."},
  {id:226, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A K=8.0 head must discharge 40 gpm. The required pressure is:", opts:["16 psi","20 psi","40 psi","25 psi"], correct:3, re:"P = (Q/K)² = (40/8.0)² = 5² = 25 psi (NFPA 13 hydraulic calc)."},
  {id:227, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"NFPA 13 sets a minimum operating pressure for most standard spray sprinklers of:", opts:["7 psi","3 psi","15 psi","20 psi"], correct:0, re:"The minimum operating pressure for standard spray sprinklers is 7 psi (NFPA 13 minimum operating pressure)."},
  {id:228, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A K=5.6 sprinkler at the NFPA 13 minimum 7 psi discharges approximately:", opts:["11.2 gpm","28.0 gpm","19.6 gpm","14.8 gpm"], correct:3, re:"Q = 5.6×√7 = 5.6×2.646 ≈ 14.8 gpm (Q=K√P, NFPA 13)."},
  {id:229, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"If you know a sprinkler flows 30 gpm at 25 psi, its K-factor is:", opts:["6.0","1.2","7.5","30"], correct:0, re:"K = Q/√P = 30/√25 = 30/5 = 6.0 (NFPA 13 hydraulic calc)."},
  {id:230, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"The K-factor of a sprinkler primarily depends on its:", opts:["Discharge orifice size and geometry","Frame color","Temperature rating only","Distance from the riser"], correct:0, re:"K is fixed by the orifice/nozzle geometry and is a constant for that sprinkler model (NFPA 13; manufacturer listing)."},
  {id:231, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"Doubling the pressure at a sprinkler changes its flow by a factor of about:", opts:["2.0","1.41","4.0","0.5"], correct:1, re:"Because Q∝√P, doubling P multiplies flow by √2 ≈ 1.41, not 2 (Q=K√P relationship)."},
  {id:232, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"To DOUBLE the discharge of a sprinkler, the pressure must be increased by a factor of:", opts:["2","√2","4","8"], correct:2, re:"Q∝√P, so doubling Q requires 2² = 4 times the pressure (Q=K√P relationship)."},
  {id:233, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"A large-orifice K=25.2 ESFR-type sprinkler at 50 psi discharges approximately:", opts:["126 gpm","1,260 gpm","252 gpm","178 gpm"], correct:3, re:"Q = 25.2×√50 = 25.2×7.071 ≈ 178 gpm (Q=K√P; K=25.2 listing)."},
  {id:234, block:3, sec:"K-Factor & Flow (Q=K√P)", q:"Two identical sprinklers on the same branch line discharge different flows because they have different:", opts:["Operating pressures","K-factors","Temperature ratings","Thread sizes"], correct:0, re:"Identical heads share the same K, so differing flow results from differing operating pressure along the pipe (Q=K√P, NFPA 13 hydraulic calc)."},
  {id:235, block:3, sec:"Hazen-Williams Friction Loss", q:"NFPA 13 specifies which equation for pipe friction loss in water-based system calculations?", opts:["Darcy-Weisbach","Bernoulli","Hazen-Williams","Manning"], correct:2, re:"NFPA 13 mandates the Hazen-Williams formula for friction loss in fire sprinkler hydraulic calculations (NFPA 13 hydraulic calc)."},
  {id:236, block:3, sec:"Hazen-Williams Friction Loss", q:"The NFPA 13 Hazen-Williams friction-loss formula is p = 4.52×Q^1.85 / (C^1.85 × d^4.87). The term 'C' represents:", opts:["The pipe circumference","The pipe's interior roughness/friction coefficient","The cost per foot","The chlorine content"], correct:1, re:"C is the Hazen-Williams friction-loss coefficient describing the pipe's interior smoothness (NFPA 13 Hazen-Williams formula)."},
  {id:237, block:3, sec:"Hazen-Williams Friction Loss", q:"In the Hazen-Williams formula p = 4.52 Q^1.85/(C^1.85 d^4.87), 'p' is:", opts:["Total pump pressure","Velocity in ft/s","Friction loss per foot of pipe (psi/ft)","Elevation head"], correct:2, re:"p is the frictional resistance per foot of pipe, in psi per foot (NFPA 13 Hazen-Williams formula)."},
  {id:238, block:3, sec:"Hazen-Williams Friction Loss", q:"In the Hazen-Williams formula, the diameter 'd' to use is the pipe's:", opts:["Nominal diameter","Outside diameter","Thread diameter","Actual internal diameter"], correct:3, re:"d is the actual internal diameter of the pipe in inches, not the nominal size (NFPA 13 Hazen-Williams formula)."},
  {id:239, block:3, sec:"Hazen-Williams Friction Loss", q:"The Hazen-Williams C-value typically used for new (unlined) black or galvanized STEEL pipe in dry/preaction NFPA 13 systems and as the table base is:", opts:["100","150","140","120"], correct:3, re:"C = 120 is the Hazen-Williams value commonly assigned to steel pipe and is the basis of the NFPA 13 equivalent-length table (NFPA 13 C-value table)."},
  {id:240, block:3, sec:"Hazen-Williams Friction Loss", q:"The Hazen-Williams C-value assigned to COPPER tube and to CPVC/plastic pipe is:", opts:["100","120","150","130"], correct:2, re:"Copper tube and CPVC/plastic pipe are assigned C = 150 (smoother interior) (NFPA 13 C-value table)."},
  {id:241, block:3, sec:"Hazen-Williams Friction Loss", q:"A higher Hazen-Williams C-value indicates a pipe that produces:", opts:["More friction loss","Less friction loss","No flow","Higher elevation loss"], correct:1, re:"A higher C means a smoother interior and therefore LESS friction loss for the same flow (Hazen-Williams relationship)."},
  {id:242, block:3, sec:"Hazen-Williams Friction Loss", q:"In the Hazen-Williams formula, friction loss increases with flow Q raised to the power:", opts:["1.0","4.87","2.0","1.85"], correct:3, re:"Friction loss varies with Q^1.85 in the Hazen-Williams equation (NFPA 13 Hazen-Williams formula)."},
  {id:243, block:3, sec:"Hazen-Williams Friction Loss", q:"In the Hazen-Williams formula, friction loss is extremely sensitive to diameter, varying inversely with d raised to about:", opts:["1.85","2.63","0.54","4.87"], correct:3, re:"Friction loss varies as 1/d^4.87, so small diameter changes have a large effect (NFPA 13 Hazen-Williams formula)."},
  {id:244, block:3, sec:"Hazen-Williams Friction Loss", q:"Which choice, by itself, would MOST reduce friction loss for a given flow?", opts:["Using a slightly larger internal diameter pipe","Adding more fittings","Lowering the C-value","Increasing pipe length"], correct:0, re:"Because loss ∝ 1/d^4.87, increasing diameter has the strongest loss-reducing effect (Hazen-Williams formula)."},
  {id:245, block:3, sec:"Hazen-Williams Friction Loss", q:"The total friction loss in a length of pipe equals:", opts:["p multiplied by the C-value","p divided by the pipe length","p (psi/ft) multiplied by the pipe length in feet","p multiplied by the K-factor"], correct:2, re:"Total friction loss = p (psi/ft) × length (ft), where length includes equivalent length of fittings (NFPA 13 hydraulic calc)."},
  {id:246, block:3, sec:"Hazen-Williams Friction Loss", q:"For 100 gpm in 1 in. Schedule 40 steel (d = 1.049 in., C = 120), the friction loss is closest to:", opts:["0.26 psi/ft","25 psi/ft","9.1 psi/ft","2.56 psi/ft"], correct:3, re:"p = 4.52×100^1.85/(120^1.85×1.049^4.87) ≈ 2.56 psi/ft (NFPA 13 Hazen-Williams formula, recomputed)."},
  {id:247, block:3, sec:"Hazen-Williams Friction Loss", q:"Moving the SAME 100 gpm from 1 in. to 2 in. Schedule 40 steel (d ≈ 2.067 in.) changes the friction loss from about 2.56 psi/ft to roughly:", opts:["5.0 psi/ft","1.3 psi/ft","2.5 psi/ft","0.09 psi/ft"], correct:3, re:"p = 4.52×100^1.85/(120^1.85×2.067^4.87) ≈ 0.09 psi/ft — a large drop from the diameter increase (NFPA 13 Hazen-Williams, recomputed)."},
  {id:248, block:3, sec:"Hazen-Williams Friction Loss", q:"Halving the flow Q in a pipe changes the Hazen-Williams friction loss to about:", opts:["Half of the original","One quarter of the original","About 28% of the original","The same as the original"], correct:2, re:"(1/2)^1.85 ≈ 0.277, so loss falls to roughly 28% of the original when flow is halved (Hazen-Williams Q^1.85 term)."},
  {id:249, block:3, sec:"Hazen-Williams Friction Loss", q:"Cement-lined cast/ductile iron pipe is generally assigned a Hazen-Williams C-value of:", opts:["140","120","100","180"], correct:0, re:"Cement-lined cast or ductile iron is commonly assigned C = 140 (NFPA 13 C-value table)."},
  {id:250, block:3, sec:"Hazen-Williams Friction Loss", q:"Unlined cast iron and older/rougher pipe may be assigned a Hazen-Williams C-value as low as:", opts:["150","130","100","180"], correct:2, re:"Unlined/aged ferrous pipe is assigned a lower C such as 100, reflecting greater friction (NFPA 13 C-value table)."},
  {id:251, block:3, sec:"Hazen-Williams Friction Loss", q:"In the Hazen-Williams formula, if the C-value used is too HIGH (pipe assumed smoother than reality), the calculated friction loss will be:", opts:["Too low (non-conservative)","Too high (conservative)","Unaffected","Exactly correct"], correct:0, re:"A C-value higher than the true value understates friction loss, giving a non-conservative (optimistic) result (Hazen-Williams C term)."},
  {id:252, block:3, sec:"Node Analysis & Balancing", q:"In a node-by-node hydraulic calculation, a 'node' is:", opts:["Only the riser base","Any straight length of pipe","A point where pipe size, flow, or direction changes (e.g., a fitting or sprinkler)","The pump only"], correct:2, re:"Nodes are reference points—sprinklers, fittings, tees, size changes—between which friction loss is computed (NFPA 13 hydraulic calc procedure)."},
  {id:253, block:3, sec:"Node Analysis & Balancing", q:"Hydraulic calculations are normally worked starting from:", opts:["The water supply toward the most remote sprinkler","The most remote sprinkler back toward the supply","The middle of the system outward","The pump discharge only"], correct:1, re:"Calculations begin at the most remote (hydraulically least favorable) sprinkler and proceed back to the source, accumulating flow and pressure (NFPA 13 hydraulic calc)."},
  {id:254, block:3, sec:"Node Analysis & Balancing", q:"As you move from the end sprinkler back toward the riser, the accumulated flow in the pipe:", opts:["Decreases","Stays constant","Increases as each sprinkler adds its flow","Drops to zero at each tee"], correct:2, re:"Each downstream sprinkler adds its discharge, so total flow grows toward the supply (NFPA 13 hydraulic calc)."},
  {id:255, block:3, sec:"Node Analysis & Balancing", q:"When two flow paths meet at a common junction node at different calculated pressures, the correct rule is:", opts:["Average the two pressures","Add the two pressures together","Use the lower pressure and ignore the other","Use the higher of the two pressures and rebalance the lower-pressure path's flow"], correct:3, re:"The higher junction pressure governs; the lower-pressure branch must be re-flowed up to that pressure to balance the node (NFPA 13 hydraulic calc; junction balancing)."},
  {id:256, block:3, sec:"Node Analysis & Balancing", q:"To raise a branch's flow from its calculated value Q at pressure P_low up to a higher junction pressure P_high, the balanced flow is:", opts:["Q × (P_high/P_low)","Q × √(P_high/P_low)","Q × (P_low/P_high)","Q ÷ √(P_high/P_low)"], correct:1, re:"Because Q∝√P for that path, the adjusted flow = Q×√(P_high/P_low) (NFPA 13 junction balancing)."},
  {id:257, block:3, sec:"Node Analysis & Balancing", q:"A branch is calculated to deliver 25 gpm at 16 psi, but the junction it meets is at 25 psi. The balanced branch flow becomes:", opts:["20.0 gpm","25.0 gpm","31.25 gpm","40.0 gpm"], correct:2, re:"Q_adj = 25×√(25/16) = 25×1.25 = 31.25 gpm (junction balancing, Q∝√P)."},
  {id:258, block:3, sec:"Node Analysis & Balancing", q:"Balancing flows at a junction enforces which physical principle?", opts:["Conservation of energy only","Conservation of mass/flow — flow in equals flow out","Constant velocity everywhere","Equal pipe length on all paths"], correct:1, re:"At each node the total flow entering must equal the total leaving (continuity / conservation of mass) (hydraulic network analysis)."},
  {id:259, block:3, sec:"Node Analysis & Balancing", q:"At any single node, all pipes connected to that node share the same:", opts:["Flow rate","C-value","Diameter","Pressure"], correct:3, re:"A node has one pressure; every path meeting there must be reconciled to that common pressure (hydraulic node concept)."},
  {id:260, block:3, sec:"Node Analysis & Balancing", q:"The total pressure required at a reference node equals the sum of:", opts:["Friction loss, elevation change, and the starting (downstream) pressure","Only friction loss","Only the K-factor","Velocity times area"], correct:0, re:"P at a node = downstream pressure + friction loss + elevation change between the nodes (NFPA 13 hydraulic calc)."},
  {id:261, block:3, sec:"Node Analysis & Balancing", q:"Elevation change between two nodes is converted to pressure at a rate of about:", opts:["1.0 psi per foot","0.433 psi per foot of elevation","2.31 psi per foot","0.052 psi per foot"], correct:1, re:"Each foot of water column ≈ 0.433 psi; rising pipe adds this, descending pipe recovers it (NFPA 13 elevation pressure)."},
  {id:262, block:3, sec:"Node Analysis & Balancing", q:"A node is 10 ft higher than the one below it. The elevation pressure to add is:", opts:["1.0 psi","4.33 psi","10 psi","23.1 psi"], correct:1, re:"0.433 psi/ft × 10 ft = 4.33 psi added for the rise (NFPA 13 elevation pressure)."},
  {id:263, block:3, sec:"Node Analysis & Balancing", q:"In a gridded system, water can reach a sprinkler by multiple paths, which generally:", opts:["Increases total friction loss","Requires no node analysis","Makes balancing unnecessary","Reduces friction loss versus a tree system of the same demand"], correct:3, re:"Parallel paths in a grid split the flow, lowering velocity and friction loss compared with a single tree path (NFPA 13 gridded systems)."},
  {id:264, block:3, sec:"Node Analysis & Balancing", q:"Velocity pressure (Pv) in NFPA 13 hydraulics is computed as:", opts:["Pv = 0.001123 × Q² / d⁴","Pv = 0.433 × Q","Pv = 4.52 × Q^1.85","Pv = K×√P"], correct:0, re:"NFPA 13 gives velocity pressure Pv = 0.001123×Q²/d⁴ (psi), with Q in gpm and d in inches (NFPA 13 velocity pressure formula)."},
  {id:265, block:3, sec:"Node Analysis & Balancing", q:"In NFPA 13 hydraulics, normal pressure (Pn), total pressure (Pt) and velocity pressure (Pv) are related by:", opts:["Pn = Pt + Pv","Pn = Pt − Pv","Pn = Pt × Pv","Pn = Pv − Pt"], correct:1, re:"Normal pressure Pn = Pt − Pv; velocity pressure is subtracted from total pressure (NFPA 13 velocity-pressure method)."},
  {id:266, block:3, sec:"Node Analysis & Balancing", q:"When the velocity-pressure method is used, the flow from a sprinkler or branch at a node is based on the:", opts:["Total pressure","Elevation pressure","Velocity pressure alone","Normal pressure (Pt minus Pv)"], correct:3, re:"Discharge is driven by normal pressure Pn (Pt − Pv); velocity pressure does not produce orifice flow (NFPA 13 velocity-pressure method)."},
  {id:267, block:3, sec:"Node Analysis & Balancing", q:"Most sprinkler hydraulic calculations are permitted to ignore velocity pressure because:", opts:["It only applies to standpipes","It is always larger than total pressure","NFPA 13 forbids including it","It is usually small and its omission is conservative"], correct:3, re:"Velocity pressure is typically minor and neglecting it is conservative, so NFPA 13 permits omitting it (NFPA 13 velocity pressure is optional)."},
  {id:268, block:3, sec:"Node Analysis & Balancing", q:"After balancing each junction, the cumulative pressure carried back to the source represents the:", opts:["Static pressure of the city main","System demand pressure at the source","Sprinkler temperature rating","Pipe wall thickness"], correct:1, re:"The accumulated, balanced pressure at the base of the riser/source is the total system demand pressure to be matched by the supply (NFPA 13 hydraulic calc)."},
  {id:269, block:3, sec:"Hydraulic Graph & Safety Margin", q:"A water-supply graph for sprinkler design is plotted on special paper scaled so that the supply curve appears as:", opts:["A straight line (flow axis to the 1.85 power)","A vertical line","A perfect circle","A horizontal line"], correct:0, re:"N^1.85 graph paper scales the flow axis to the 1.85 power so the Hazen-Williams supply curve plots as a straight line (NFPA 13 hydraulic graph; N1.85 paper)."},
  {id:270, block:3, sec:"Hydraulic Graph & Safety Margin", q:"On the hydraulic graph, the WATER SUPPLY curve shows that as flow increases, available pressure:", opts:["Decreases","Increases","Stays constant","Becomes negative immediately"], correct:0, re:"More flow draws the supply down: residual pressure falls as flow rises, so the supply curve slopes downward (flow-test based supply curve)."},
  {id:271, block:3, sec:"Hydraulic Graph & Safety Margin", q:"The system is adequate when the demand point falls:", opts:["On or below (within) the supply curve","Above (outside) the supply curve","Exactly at zero flow","At the static pressure only"], correct:0, re:"Demand must lie on or under the available supply curve, meaning the supply can deliver the required flow at the required pressure (NFPA 13 demand vs. supply)."},
  {id:272, block:3, sec:"Hydraulic Graph & Safety Margin", q:"The vertical gap between the available supply curve and the demand point at the design flow is called the:", opts:["Friction loss","Elevation head","Safety margin (cushion)","Velocity pressure"], correct:2, re:"That pressure difference is the safety margin or 'cushion' between supply and demand (NFPA 13 hydraulic graph; safety margin)."},
  {id:273, block:3, sec:"Hydraulic Graph & Safety Margin", q:"A LARGER safety margin between supply and demand generally indicates:", opts:["A water supply that is barely adequate","More reserve capacity and tolerance for supply fluctuation","An undersized water main","A failed calculation"], correct:1, re:"A bigger cushion means the supply comfortably exceeds demand, giving reserve for deterioration or fluctuation (NFPA 13 safety margin concept)."},
  {id:274, block:3, sec:"Hydraulic Graph & Safety Margin", q:"On a flow test, the 'static' pressure is the pressure measured at:", opts:["Maximum flow","Pump churn","20 psi residual","Zero flow (no hydrant flowing)"], correct:3, re:"Static pressure is read with no water flowing (zero flow) (NFPA 291 / flow-test terminology)."},
  {id:275, block:3, sec:"Hydraulic Graph & Safety Margin", q:"On a flow test, the 'residual' pressure is the pressure measured:", opts:["With no flow","After the test ends","While a known quantity of water is flowing","At the pump only"], correct:2, re:"Residual pressure is the pressure remaining in the system while a measured flow is discharging (flow-test terminology)."},
  {id:276, block:3, sec:"Hydraulic Graph & Safety Margin", q:"Plotting the supply curve on N1.85 paper is useful because it lets the designer:", opts:["Read available flow at any pressure as a straight-line interpolation","Avoid measuring pressure","Eliminate the hose allowance","Ignore friction loss"], correct:0, re:"A straight-line supply curve allows simple graphical interpolation of available flow at any pressure (N1.85 graph method)."},
  {id:277, block:3, sec:"Hydraulic Graph & Safety Margin", q:"The total system DEMAND plotted on the graph must include:", opts:["Sprinkler flow only","Static pressure only","Hose allowance only","Sprinkler flow plus the required hose stream allowance"], correct:3, re:"System demand = sprinkler discharge over the design area PLUS the hose stream allowance (NFPA 13 demand calculation)."},
  {id:278, block:3, sec:"Hydraulic Graph & Safety Margin", q:"If the demand point plots ABOVE the supply curve, the designer must:", opts:["Increase supply (e.g., a pump) or reduce demand (larger pipe) until demand fits under the curve","Do nothing; it passes","Lower the density only","Remove the hose allowance"], correct:0, re:"Demand above supply means the supply is inadequate; either boost supply or reduce demand so the point falls within the curve (NFPA 13 demand vs. supply)."},
  {id:279, block:3, sec:"Hydraulic Graph & Safety Margin", q:"A common reason a supply curve is projected down to 20 psi is that:", opts:["20 psi is the maximum allowed pressure","Codes commonly require evaluating available fire flow at a 20 psi residual","Sprinklers cannot flow below 20 psi","20 psi is the static pressure"], correct:1, re:"Fire flow is conventionally reported as the flow available at 20 psi residual, per fire-code practice (NFPA 291 / fire-code fire-flow convention)."},
  {id:280, block:3, sec:"Hydraulic Graph & Safety Margin", q:"On the graph, a steeply sloping (rapidly dropping) supply curve indicates a supply that is:", opts:["Strong with little pressure loss under flow","Independent of flow","Weak — pressure falls quickly as flow increases","Always adequate"], correct:2, re:"A steep downward slope means residual pressure collapses quickly with flow, indicating a comparatively weak supply (supply-curve interpretation)."},
  {id:281, block:3, sec:"Hydraulic Graph & Safety Margin", q:"If a fire pump is added, on the hydraulic graph the effect is to:", opts:["Lower the entire supply curve","Boost the supply curve upward, adding pressure at a given flow","Eliminate the demand curve","Flatten the demand to zero"], correct:1, re:"A pump adds head, shifting the available supply curve upward and increasing the margin over demand (pump/boosted-supply concept)."},
  {id:282, block:3, sec:"Hydraulic Graph & Safety Margin", q:"The point where the system demand and the available supply just meet (no remaining cushion) means the safety margin is:", opts:["Zero","Maximized","Negative","Equal to the static pressure"], correct:0, re:"If demand exactly meets supply, the cushion/safety margin is zero — the minimum acceptable condition (safety-margin definition)."},
  {id:283, block:3, sec:"Hydraulic Graph & Safety Margin", q:"The horizontal axis of the standard sprinkler hydraulic graph represents:", opts:["Time (s)","Pressure (psi)","Flow (gpm)","Elevation (ft)"], correct:2, re:"Flow in gpm is on the horizontal axis (scaled to the 1.85 power); pressure is on the vertical axis (N1.85 graph)."},
  {id:284, block:3, sec:"Hydraulic Graph & Safety Margin", q:"The vertical axis of the standard sprinkler hydraulic graph represents:", opts:["Flow (gpm)","C-value","Pressure (psi)","Pipe diameter"], correct:2, re:"Pressure in psi is plotted on the vertical axis of the hydraulic graph (N1.85 graph)."},
  {id:285, block:3, sec:"Hydraulic Graph & Safety Margin", q:"A practical reason designers prefer a generous safety margin is to account for:", opts:["Lower temperature ratings","Brighter sprinkler colors","Shorter pipe runs","Future pipe roughening, seasonal supply drop, and minor flow-test error"], correct:3, re:"Margin covers supply deterioration over time, seasonal/diurnal pressure variation, and test inaccuracy (engineering rationale for safety margin)."},
  {id:286, block:3, sec:"Water Supply Curve & Demand", q:"The total sprinkler system DEMAND that must be supplied is the sum of:", opts:["Sprinkler discharge over the design area plus hose stream allowance","Static pressure plus residual pressure","K-factor plus C-value","Elevation plus velocity only"], correct:0, re:"Demand = calculated sprinkler flow over the design area + the required inside/outside hose stream allowance (NFPA 13 water demand)."},
  {id:287, block:3, sec:"Water Supply Curve & Demand", q:"The hose stream allowance for a Light Hazard occupancy is typically:", opts:["250 gpm","100 gpm","500 gpm","1,000 gpm"], correct:1, re:"Light Hazard hose stream allowance is 100 gpm (NFPA 13 hose stream/water supply table)."},
  {id:288, block:3, sec:"Water Supply Curve & Demand", q:"The hose stream allowance for an Ordinary Hazard occupancy is typically:", opts:["100 gpm","500 gpm","250 gpm","750 gpm"], correct:2, re:"Ordinary Hazard hose stream allowance is 250 gpm (NFPA 13 hose stream/water supply table)."},
  {id:289, block:3, sec:"Water Supply Curve & Demand", q:"The hose stream allowance for an Extra Hazard occupancy is typically:", opts:["100 gpm","500 gpm","250 gpm","2,000 gpm"], correct:1, re:"Extra Hazard hose stream allowance is 500 gpm (NFPA 13 hose stream/water supply table)."},
  {id:290, block:3, sec:"Water Supply Curve & Demand", q:"In the system demand, the hose stream allowance is generally added to the sprinkler demand at which point?", opts:["At the point of connection to the supply (e.g., base of riser or city main)","At each sprinkler","Only at the most remote head","It is never added"], correct:0, re:"Hose allowance is added where it would be taken — typically the base of riser/supply connection — not at the sprinklers (NFPA 13 hose allowance application)."},
  {id:291, block:3, sec:"Water Supply Curve & Demand", q:"The required water supply DURATION for a Light Hazard occupancy is on the order of:", opts:["90 minutes","60 minutes","30 minutes","8 hours"], correct:2, re:"Light Hazard water supply duration is on the order of 30 minutes (NFPA 13 water supply duration table)."},
  {id:292, block:3, sec:"Water Supply Curve & Demand", q:"The required water supply DURATION for an Extra Hazard occupancy is on the order of:", opts:["90–120 minutes","60 minutes","30 minutes","10 minutes"], correct:0, re:"Extra Hazard water supply duration is on the order of 90–120 minutes — longer than lower hazards (NFPA 13 water supply duration table)."},
  {id:293, block:3, sec:"Water Supply Curve & Demand", q:"A fire-hydrant flow test is used in sprinkler design primarily to:", opts:["Determine the building height","Set the sprinkler temperature rating","Choose the pipe color","Establish the available water supply curve"], correct:3, re:"The flow test defines the available supply (static, residual, and slope) used to build the supply curve (flow-test purpose)."},
  {id:294, block:3, sec:"Water Supply Curve & Demand", q:"'Fire flow available at 20 psi' from a flow test means:", opts:["The pipe is 20 in. diameter","The static pressure is 20 psi","The pump shutoff is 20 psi","The flow when residual pressure has dropped to 20 psi"], correct:3, re:"It is the projected flow the supply can deliver while still maintaining 20 psi residual (fire-flow convention)."},
  {id:295, block:3, sec:"Water Supply Curve & Demand", q:"When comparing system demand to the water supply curve, the demand must be satisfied at:", opts:["The required demand flow rate, not just at zero flow","Only the static (no-flow) pressure","Twice the demand flow","The pump churn pressure only"], correct:0, re:"Adequacy is judged at the demand flow point — the supply must provide the demand pressure AT the demand flow (NFPA 13 demand vs. supply)."},
  {id:296, block:3, sec:"Water Supply Curve & Demand", q:"If a water supply provides ample static pressure but its residual collapses under flow, the system may still fail because:", opts:["The K-factor changes","Static pressure is irrelevant","Static pressure alone does not guarantee enough flow at the demand point","Elevation increases"], correct:2, re:"A high static with poor residual yields a steep, weak curve; demand at the design flow may exceed available residual pressure (supply-curve interpretation)."},
  {id:297, block:3, sec:"Water Supply Curve & Demand", q:"Adding the hose stream allowance to the demand shifts the system demand point on the graph:", opts:["Off the graph entirely","To zero flow","Down to the static pressure","To a higher flow (and thus higher required pressure on the supply curve)"], correct:3, re:"Hose flow increases total demand flow, moving the demand point right/up along the supply curve and reducing the cushion (NFPA 13 demand build-up)."},
  {id:298, block:3, sec:"Water Supply Curve & Demand", q:"Two flow-test points are needed to define the supply curve because:", opts:["The law requires two hydrants","Two pumps are required","One point gives pressure, a second establishes the slope (pressure drop vs. flow)","One point is the temperature"], correct:2, re:"Static fixes the zero-flow pressure; the residual-at-flow point sets the curve's slope, together defining the supply (flow-test / supply-curve construction)."},
  {id:299, block:3, sec:"Water Supply Curve & Demand", q:"If the city water supply alone cannot meet the system demand within the safety margin, a common remedy is to:", opts:["Add a fire pump and/or storage tank to boost the supply","Lower the required density below code","Remove sprinklers from the design area","Delete the hose allowance"], correct:0, re:"A fire pump and/or water-storage tank boosts the available supply curve to meet demand with margin (NFPA 13 / NFPA 20 supply augmentation)."},
  {id:300, block:3, sec:"Water Supply Curve & Demand", q:"The FINAL check of a sprinkler hydraulic design is that:", opts:["All sprinklers have identical pressure","Every pipe is the same diameter","The system demand (including hose) fits within the available water supply with the required safety margin","No fittings are used"], correct:2, re:"Design acceptance requires that total demand plus hose fall within the supply curve, leaving an adequate safety margin (NFPA 13 final demand-vs-supply verification)."},
  {id:301, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"NFPA 13 permits two basic methods for sizing sprinkler system pipe. They are:", opts:["The pipe schedule method and the hydraulically calculated method","The velocity method and the area method","The friction method and the density method","The gravity method and the pressure method"], correct:0, re:"NFPA 13 sizes pipe either by the pipe schedule method (using prescriptive tables of sprinklers permitted per pipe size) or by hydraulic calculation. Ref: NFPA 13, system design chapters on pipe schedule systems and hydraulically calculated systems."},
  {id:302, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"Under the pipe schedule method for a Light Hazard occupancy using Schedule 40 steel, a 1 in. branch line pipe is permitted to supply a maximum of how many sprinklers?", opts:["1 sprinkler","2 sprinklers","4 sprinklers","6 sprinklers"], correct:1, re:"In the NFPA 13 Light Hazard pipe schedule, 1 in. = 2 sprinklers, 1-1/4 in. = 3, 1-1/2 in. = 5, 2 in. = 10. Ref: NFPA 13 Light Hazard pipe schedule table."},
  {id:303, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"Under the Light Hazard pipe schedule (Schedule 40 steel), a 2 in. pipe is permitted to supply a maximum of how many sprinklers?", opts:["5 sprinklers","8 sprinklers","10 sprinklers","30 sprinklers"], correct:2, re:"NFPA 13 Light Hazard pipe schedule: 1-1/2 in. = 5, 2 in. = 10, 2-1/2 in. = 30. Ref: NFPA 13 Light Hazard pipe schedule table."},
  {id:304, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"The pipe schedule method may NOT be used to design a new system in which of the following situations?", opts:["Any system where the calculated demand is below the available supply","A Light Hazard office building","Any wet-pipe system","An Extra Hazard hydraulically designed addition or where NFPA 13 limits its use to existing systems and small additions"], correct:3, re:"NFPA 13 restricts pipe schedule design largely to existing pipe schedule systems and limited additions; new systems are generally required to be hydraulically calculated. Ref: NFPA 13 pipe schedule system limitations."},
  {id:305, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"In a hydraulically calculated system, the friction loss in piping is most commonly determined in NFPA 13 using which formula?", opts:["The Hazen-Williams formula","The Darcy-Weisbach equation","The Bernoulli energy equation","The Manning equation"], correct:0, re:"NFPA 13 hydraulic calculations use the Hazen-Williams formula for pipe friction loss. Ref: NFPA 13 hydraulic calculation procedures (Hazen-Williams)."},
  {id:306, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"In the Hazen-Williams formula as applied by NFPA 13, the variable 'C' represents:", opts:["The cross-sectional area of the pipe","The pipe friction loss coefficient (roughness) of the interior pipe surface","The velocity of the water","The static pressure at the base of riser"], correct:1, re:"'C' is the Hazen-Williams roughness coefficient describing the relative smoothness of the pipe interior; lower C means rougher pipe and higher friction loss. Ref: NFPA 13 Hazen-Williams formula nomenclature."},
  {id:307, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"What Hazen-Williams C value does NFPA 13 assign to new (unlined) black or galvanized steel pipe for fire sprinkler hydraulic calculations?", opts:["100","140","120","150"], correct:2, re:"NFPA 13 assigns C = 120 to black and galvanized steel pipe in its Hazen-Williams C-value table. Ref: NFPA 13 Hazen-Williams C-value table."},
  {id:308, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"Which piping material is assigned the HIGHEST Hazen-Williams C value (smoothest) in NFPA 13?", opts:["Black steel pipe (dry system), C = 100","Galvanized steel pipe, C = 120","Cement-lined cast/ductile iron, C = 140","Plastic (CPVC) / copper tube, C = 150"], correct:3, re:"NFPA 13 assigns C = 150 to plastic (listed CPVC) and copper tube, the smoothest of the common sprinkler materials. Ref: NFPA 13 Hazen-Williams C-value table."},
  {id:309, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"NFPA 13 assigns a lower Hazen-Williams C value to dry-pipe and preaction (black steel) systems. That value is:", opts:["100","120","130","140"], correct:0, re:"Black steel pipe in dry-pipe/preaction service is assigned C = 100 to account for accelerated internal corrosion from intermittent water and air. Ref: NFPA 13 Hazen-Williams C-value table."},
  {id:310, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"In the Hazen-Williams pressure-loss relationship used by NFPA 13, friction loss per unit length is most sensitive to which variable?", opts:["Pipe length only","Flow rate (Q), which is raised to a power of about 1.85","The static elevation","The pipe color"], correct:1, re:"In Hazen-Williams, friction loss varies approximately with Q^1.85 and inversely with C^1.85 and diameter^4.87; flow rate strongly drives loss. Ref: NFPA 13 Hazen-Williams formula."},
  {id:311, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"When converting fitting and valve losses to pipe in a hydraulic calculation, NFPA 13 requires the designer to add the fitting's:", opts:["Actual physical length","Nominal diameter","Equivalent length of pipe","Wall thickness"], correct:2, re:"Fitting and valve friction is accounted for by adding an equivalent length of pipe (from the NFPA 13 equivalent-length table) to the actual pipe length. Ref: NFPA 13 equivalent pipe lengths of fittings and valves."},
  {id:312, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"NFPA 13's equivalent-length fitting table is based on Schedule 40 steel pipe and a C value of 120. If the actual pipe has a different C value, the tabulated equivalent length must be:", opts:["Ignored entirely","Replaced by the nominal diameter","Doubled in every case","Multiplied by an adjustment factor for the actual C value"], correct:3, re:"NFPA 13 requires multiplying the table equivalent length by a C-factor adjustment (the table assumes C = 120, Schedule 40). Ref: NFPA 13 note to the equivalent-length table on C-value adjustment."},
  {id:313, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"A core advantage of the hydraulically calculated method over the pipe schedule method is that it:", opts:["Tailors pipe sizes to the actual demand and available water supply, usually allowing smaller, more economical pipe","Eliminates the need for any hangers","Removes the need for sprinklers","Allows any C value to be assumed"], correct:0, re:"Hydraulic calculation matches pipe sizes to the required density/area and the real supply curve, typically yielding smaller, more efficient pipe than the conservative schedule tables. Ref: NFPA 13 hydraulically calculated system design basis."},
  {id:314, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"In NFPA 13, the velocity of water in the pipe primarily affects the design because higher velocity:", opts:["Reduces friction loss","Increases friction loss per foot of pipe","Has no effect on pressure","Increases the pipe C value"], correct:1, re:"Higher flow velocity increases friction loss; while NFPA 13 does not cap velocity, designers manage it because excessive velocity drives up pressure demand. Ref: NFPA 13 hydraulic calculation principles (Hazen-Williams)."},
  {id:315, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"Under the Ordinary Hazard pipe schedule (Schedule 40 steel), the maximum number of sprinklers permitted on a 1-1/4 in. branch line pipe is:", opts:["2","4","3","5"], correct:2, re:"NFPA 13 Ordinary Hazard pipe schedule: 1 in. = 2, 1-1/4 in. = 3, 1-1/2 in. = 5, 2 in. = 10. Ref: NFPA 13 Ordinary Hazard pipe schedule table."},
  {id:316, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"In a tree-configured hydraulic calculation, friction loss is balanced at common reference points so that:", opts:["Every pipe carries identical flow","Elevation is ignored","All sprinklers flow exactly the minimum","Two paths meeting at a junction are balanced to the same pressure before flows are summed"], correct:3, re:"At each junction the pressures of the converging paths must be balanced (made equal, normally to the higher value) before adding their flows. Ref: NFPA 13 hydraulic calculation procedure (balancing pressures at junctions)."},
  {id:317, block:4, sec:"Pipe Sizing (Schedule & Hydraulic)", q:"Normal pressure (Pn), velocity pressure (Pv), and total pressure (Pt) are related in NFPA 13 hydraulic calculations by:", opts:["Pt = Pn + Pv","Pt = Pn - Pv","Pn = Pt + Pv","Pv = Pt + Pn"], correct:0, re:"Total pressure equals normal (static) pressure plus velocity pressure: Pt = Pn + Pv. NFPA 13 permits, but does not require, velocity-pressure inclusion. Ref: NFPA 13 hydraulic calculation, velocity pressure provisions."},
  {id:318, block:4, sec:"Materials & Listing", q:"Aboveground sprinkler pipe and tube used under NFPA 13 must generally be:", opts:["Any pipe available on site","Of a type specifically permitted by NFPA 13 (e.g., listed or meeting referenced ASTM/ASME standards)","Only stainless steel","Only copper"], correct:1, re:"NFPA 13 limits aboveground pipe/tube to materials that meet the standard's referenced specifications (such as ASTM A53/A795 steel, ASTM B copper) or that are specifically listed. Ref: NFPA 13 aboveground pipe and tube requirements."},
  {id:319, block:4, sec:"Materials & Listing", q:"CPVC pipe and fittings may be used in a fire sprinkler system only when they are:", opts:["Schedule 40 PVC of any manufacturer","Rated for potable water only","Listed for fire sprinkler service and installed per their listing","Painted with intumescent paint"], correct:2, re:"Only CPVC specifically listed for fire sprinkler use may be installed, and it must follow the listing limitations (e.g., concealment, hanger spacing, solvent cement). Ordinary ASTM CPVC is not automatically listed. Ref: NFPA 13 nonmetallic pipe / listing requirements."},
  {id:320, block:4, sec:"Materials & Listing", q:"When steel pipe is joined with threaded fittings, NFPA 13 requires a minimum wall thickness corresponding to:", opts:["Schedule 5","Schedule 10","Schedule 80 only","Schedule 30 (8 in. and larger) or Schedule 40 (smaller than 8 in.)"], correct:3, re:"Threading requires wall thickness of at least Schedule 30 for 8 in. and larger or Schedule 40 for smaller pipe; lighter wall (Schedule 10) cannot be threaded. Ref: NFPA 13 steel pipe joining (threaded) thickness requirements."},
  {id:321, block:4, sec:"Materials & Listing", q:"Thin-wall (Schedule 10) steel sprinkler pipe is permitted by NFPA 13 only when joined by:", opts:["Listed methods such as roll-grooved or welded connections (not threading)","Threaded fittings","Solvent cement","Compression couplings"], correct:0, re:"Schedule 10 lacks the wall thickness for cut threads, so it must be joined by roll-grooved, welded, or other listed methods. Ref: NFPA 13 steel pipe joining methods and minimum wall thickness."},
  {id:322, block:4, sec:"Materials & Listing", q:"Pipe joined by grooved mechanical couplings must use:", opts:["Any gasket on hand","A listed combination of fittings, gaskets, and grooves","Welded joints only","Threaded reducers"], correct:1, re:"NFPA 13 requires grooved joints to be made with a listed combination of fittings, gaskets, and grooves to ensure compatibility and integrity. Ref: NFPA 13 grooved fitting / coupling requirements."},
  {id:323, block:4, sec:"Materials & Listing", q:"Copper tube used in sprinkler systems is typically joined by brazing rather than soft soldering in many applications because:", opts:["Soldered joints cannot hold water","Copper cannot be soldered","Brazed joints have higher temperature/strength capacity required for fire conditions and listings","Brazing is faster only"], correct:2, re:"Brazed joints provide greater strength and fire endurance than 50/50 soft solder; NFPA 13 references the copper joining standards and listings for these joints. Ref: NFPA 13 copper tube joining provisions."},
  {id:324, block:4, sec:"Materials & Listing", q:"Welding of sprinkler pipe under NFPA 13 must be performed:", opts:["By any worker with a torch","Only in the shop, never in the field","Without any documentation","Using qualified welders/procedures with full-penetration welds and openings cut by listed/approved means"], correct:3, re:"NFPA 13 requires qualified welding procedures and welders, full-penetration welds at branch outlets, and that discs/coupons be retrieved so they do not obstruct the pipe. Ref: NFPA 13 welded pipe and fittings provisions."},
  {id:325, block:4, sec:"Materials & Listing", q:"After welding a branch outlet onto a main, NFPA 13 requires that:", opts:["The cut-out coupon (disc) be retrieved and not left inside the piping","The disc be left inside to reinforce the joint","The pipe be galvanized afterward","The outlet be threaded"], correct:0, re:"The coupon removed when cutting the outlet must be retrieved; a disc left in the pipe could obstruct flow to sprinklers. Ref: NFPA 13 welded outlet requirements (retrieval of coupons)."},
  {id:326, block:4, sec:"Materials & Listing", q:"Which standard is commonly referenced by NFPA 13 for ordinary-weight black and hot-dipped galvanized steel sprinkler pipe?", opts:["ASTM D1785","ASTM A53 / ASTM A795","ASME B16.3","AWWA C151"], correct:1, re:"NFPA 13 references ASTM A53 and ASTM A795 (and A135) for steel sprinkler pipe. ASTM D1785 is for PVC plastic. Ref: NFPA 13 referenced steel pipe specifications."},
  {id:327, block:4, sec:"Materials & Listing", q:"Fittings used in sprinkler systems must:", opts:["Always be cast iron","Be of larger pressure rating than 1000 psi","Match the pipe material/joining method and meet NFPA 13's referenced standards or be listed","Be field-fabricated"], correct:2, re:"NFPA 13 requires fittings to comply with referenced standards (e.g., ASME B16 series, UL listings) and to be compatible with the pipe and joining method/pressure. Ref: NFPA 13 fittings requirements."},
  {id:328, block:4, sec:"Materials & Listing", q:"The minimum pressure rating for sprinkler system components (pipe, fittings, valves) under NFPA 13 standard systems is generally:", opts:["50 psi","100 psi","500 psi","175 psi (where maximum system pressure does not exceed it)"], correct:3, re:"NFPA 13 generally rates system components for at least 175 psi where the maximum system working pressure does not exceed 175 psi; higher-pressure systems require components rated accordingly. Ref: NFPA 13 component pressure rating provisions."},
  {id:329, block:4, sec:"Materials & Listing", q:"Nonmetallic (CPVC) pipe listings frequently restrict its use to which arrangement unless otherwise listed?", opts:["Wet-pipe systems and concealed/specific protected installations per the listing","Exposed in any occupancy","Dry-pipe Extra Hazard systems","Underground only"], correct:0, re:"CPVC listings commonly limit use to wet-pipe systems and require concealment or specific protection (membrane, water-filled) except where the listing allows exposed use. Ref: NFPA 13 / CPVC product listing limitations."},
  {id:330, block:4, sec:"Materials & Listing", q:"When dissimilar metals such as copper tube and steel pipe are joined, the designer should address:", opts:["Reduced C value to 50","Galvanic corrosion (use of dielectric/listed transition fittings)","Mandatory welding","Doubling the hanger spacing"], correct:1, re:"Joining copper to steel can cause galvanic corrosion; dielectric unions or listed transition fittings are used to mitigate it. Ref: NFPA 13 / good practice on dissimilar-metal connections."},
  {id:331, block:4, sec:"Materials & Listing", q:"Roll-grooved Schedule 10 steel pipe is permitted by NFPA 13 for pressures up to:", opts:["100 psi","175 psi","300 psi","1000 psi"], correct:2, re:"NFPA 13 permits roll-grooved Schedule 10 steel (in the applicable sizes) for systems with pressures up to 300 psi, with specified minimum wall thickness for larger sizes. Ref: NFPA 13 steel pipe (roll-grooved) wall-thickness/pressure provisions."},
  {id:332, block:4, sec:"Materials & Listing", q:"Galvanized steel pipe is sometimes preferred over black steel in dry and preaction systems because galvanizing:", opts:["Increases the C value to 150","Eliminates the need for hangers","Allows soldered joints","Provides some additional internal corrosion resistance against trapped water/condensate"], correct:3, re:"Galvanizing adds internal corrosion resistance, useful where condensate and intermittent water accelerate corrosion in dry/preaction systems. Ref: NFPA 13 pipe material provisions / corrosion considerations."},
  {id:333, block:4, sec:"Materials & Listing", q:"A pipe or component that is 'listed' under NFPA 13 means it has been:", opts:["Evaluated by a recognized testing laboratory and published as meeting appropriate standards for its intended use","Approved by the installer only","Manufactured overseas","Used previously on another job"], correct:0, re:"'Listed' means a nationally recognized testing lab has evaluated the product and published it as meeting the relevant standard for the intended fire-protection use. Ref: NFPA 13 definitions of listed/approved."},
  {id:334, block:4, sec:"Materials & Listing", q:"Stainless steel and certain other special pipe materials may be used in sprinkler systems when:", opts:["Never permitted","Listed or specifically permitted and joined by methods consistent with NFPA 13 and the listing","Only for underground mains","Painted to look like steel"], correct:1, re:"Special materials (e.g., stainless steel) are acceptable where they meet referenced specs or are listed and are joined by appropriate listed methods. Ref: NFPA 13 aboveground pipe/tube and special materials provisions."},
  {id:335, block:4, sec:"Fittings & Equivalent Length", q:"In NFPA 13 hydraulic calculations, the equivalent length assigned to a fitting represents:", opts:["The physical face-to-face dimension of the fitting","The pipe's nominal size","The length of straight pipe that would produce the same friction loss as the fitting","The pressure rating of the fitting"], correct:2, re:"Equivalent length is the length of straight pipe of the same diameter that yields the same friction loss as the fitting. Ref: NFPA 13 equivalent pipe length of fittings and valves."},
  {id:336, block:4, sec:"Fittings & Equivalent Length", q:"The NFPA 13 equivalent-length table is normalized to which pipe and C value?", opts:["Schedule 80 steel, C = 100","Copper, C = 150","Cast iron, C = 140","Schedule 40 steel, C = 120"], correct:3, re:"The fitting equivalent-length table is based on Schedule 40 steel pipe and C = 120; adjustments are required for other C values. Ref: NFPA 13 equivalent-length table basis."},
  {id:337, block:4, sec:"Fittings & Equivalent Length", q:"For a 2 in. Schedule 40 standard 90 degree elbow, NFPA 13's table gives an equivalent length of approximately:", opts:["5 ft","1 ft","12 ft","20 ft"], correct:0, re:"NFPA 13 lists a 2 in. standard 90 degree elbow at about 5 ft equivalent length. Ref: NFPA 13 equivalent pipe length of fittings and valves table."},
  {id:338, block:4, sec:"Fittings & Equivalent Length", q:"Compared to a standard 90 degree elbow of the same size, a long-turn (sweep) 90 degree elbow has an equivalent length that is:", opts:["Greater","Smaller","Identical","Always zero"], correct:1, re:"A long-turn/sweep elbow produces less turbulence, so its equivalent length is smaller than a standard 90 degree elbow of the same size. Ref: NFPA 13 equivalent-length table (standard vs. long-turn elbow)."},
  {id:339, block:4, sec:"Fittings & Equivalent Length", q:"When flow goes straight THROUGH the run of a tee or cross (no change of direction), the equivalent length charged in NFPA 13 is:", opts:["The full branch (turn) value","Always 60 ft","Zero or not counted as a turn (only the branch/turned path is charged the tee value)","The same as a gate valve"], correct:2, re:"Flow passing straight through the run of a tee/cross is not charged a fitting loss; only flow turning 90 degrees through the branch is assigned the tee equivalent length. Ref: NFPA 13 equivalent-length table notes on tees and crosses."},
  {id:340, block:4, sec:"Fittings & Equivalent Length", q:"For a 2 in. fully open gate valve, NFPA 13's equivalent length is approximately:", opts:["6 ft","9 ft","15 ft","1 ft"], correct:3, re:"A fully open gate valve has very low loss; NFPA 13 lists about 1 ft equivalent length for 2 in. Ref: NFPA 13 equivalent-length table (gate valve)."},
  {id:341, block:4, sec:"Fittings & Equivalent Length", q:"A 2 in. butterfly valve has an NFPA 13 equivalent length of approximately:", opts:["6 ft","1 ft","20 ft","40 ft"], correct:0, re:"A 2 in. butterfly valve is listed at about 6 ft equivalent length because the disc remains in the flow path. Ref: NFPA 13 equivalent-length table (butterfly valve)."},
  {id:342, block:4, sec:"Fittings & Equivalent Length", q:"A 2 in. swing check valve has an NFPA 13 equivalent length of approximately:", opts:["1 ft","9 ft","3 ft","27 ft"], correct:1, re:"A 2 in. swing check valve is listed at about 9 ft equivalent length. Ref: NFPA 13 equivalent-length table (swing check valve)."},
  {id:343, block:4, sec:"Fittings & Equivalent Length", q:"Among the following 2 in. fittings/valves, which generally has the GREATEST equivalent length (highest friction loss)?", opts:["Fully open gate valve","Standard 90 degree elbow","Swing check valve","45 degree elbow"], correct:2, re:"Of these, the swing check valve (~9 ft for 2 in.) has the highest equivalent length; the gate valve is lowest (~1 ft). Ref: NFPA 13 equivalent-length table."},
  {id:344, block:4, sec:"Fittings & Equivalent Length", q:"As nominal pipe size increases, the equivalent length of a given fitting type (e.g., a 90 degree elbow) generally:", opts:["Decreases","Stays exactly the same","Becomes negative","Increases"], correct:3, re:"Larger fittings have larger equivalent lengths; e.g., a 90 degree elbow grows from ~2 ft at 1 in. to ~14 ft at 6 in. Ref: NFPA 13 equivalent-length table trend across sizes."},
  {id:345, block:4, sec:"Fittings & Equivalent Length", q:"A 45 degree elbow has an equivalent length that, compared to a standard 90 degree elbow of the same size, is:", opts:["Smaller","Larger","Exactly double","Exactly the same"], correct:0, re:"A 45 degree elbow turns the flow less and has a smaller equivalent length than the 90 degree elbow of the same size. Ref: NFPA 13 equivalent-length table (45 vs 90 degree elbow)."},
  {id:346, block:4, sec:"Fittings & Equivalent Length", q:"NFPA 13 generally does NOT require adding fitting equivalent length for which connections?", opts:["The 90 degree elbows at the base of the riser","Direct connections to the sprinkler and the fitting where a branch line connects directly to a sprinkler (per the table notes)","Butterfly valves at the riser","Swing check valves"], correct:1, re:"Per the table notes, friction loss is not normally added for the fitting directly connecting to a sprinkler (the sprinkler's own loss is handled separately); valves and turning fittings still count. Ref: NFPA 13 equivalent-length table application notes."},
  {id:347, block:4, sec:"Fittings & Equivalent Length", q:"For copper tube or plastic pipe, NFPA 13 directs the designer to:", opts:["Use the steel equivalent-length values without change","Ignore fittings entirely","Use the listed fitting data / appropriate equivalent lengths and apply the proper C-value adjustment","Use only the 6 in. column"], correct:2, re:"Because the table is steel/C=120 based, copper and plastic require the manufacturer/listed fitting data or the C-value adjustment factor (e.g., C = 150). Ref: NFPA 13 equivalent-length table C-value adjustment provisions."},
  {id:348, block:4, sec:"Fittings & Equivalent Length", q:"The total equivalent pipe length used to compute friction loss in a segment equals:", opts:["Only the fittings","Only the straight pipe","The largest single fitting value","The actual straight pipe length PLUS the sum of all fitting/valve equivalent lengths in that segment"], correct:3, re:"Friction loss is based on the actual measured pipe length added to the sum of the equivalent lengths of all fittings and valves in the flow path of that segment. Ref: NFPA 13 hydraulic calculation procedure (equivalent length)."},
  {id:349, block:4, sec:"Fittings & Equivalent Length", q:"Specially listed devices (e.g., listed flexible sprinkler drops, backflow preventers, strainers) should have their friction loss determined by:", opts:["The manufacturer's listed friction-loss data for the specific device","The standard fitting table only","Assuming zero loss","Using the gate valve value"], correct:0, re:"Listed special devices carry their own published (listed) friction-loss data, which must be used instead of the generic fitting table. Ref: NFPA 13 provisions for listed device friction loss."},
  {id:350, block:4, sec:"Fittings & Equivalent Length", q:"A reducing fitting or reducer in NFPA 13 hydraulic calculations is typically handled by:", opts:["Charging it as a full 90 degree elbow","Using the equivalent length of the smaller (outlet) pipe size for the fitting, per the table notes","Ignoring it always","Doubling the larger-pipe value"], correct:1, re:"NFPA 13 table notes direct that fitting equivalent length be based on the fitting's smaller (downstream) opening when sizes differ. Ref: NFPA 13 equivalent-length table notes on reducing fittings."},
  {id:351, block:4, sec:"Hangers & Support Spacing", q:"For Schedule 40 steel pipe of 1 in. and smaller nominal size, the maximum distance between hangers permitted by NFPA 13 is:", opts:["8 ft","10 ft","12 ft","15 ft"], correct:2, re:"NFPA 13 Table for maximum distance between hangers gives 12 ft for steel pipe 3/4 in. and 1 in.; 1-1/4 in. and larger steel is 15 ft. Ref: NFPA 13 maximum distance between hangers table."},
  {id:352, block:4, sec:"Hangers & Support Spacing", q:"For Schedule 40 steel pipe 1-1/4 in. and larger, the maximum distance between hangers permitted by NFPA 13 is:", opts:["12 ft","18 ft","20 ft","15 ft"], correct:3, re:"NFPA 13 permits 15 ft maximum hanger spacing for steel pipe 1-1/4 in. and larger (12 ft for 3/4 in. and 1 in.). Ref: NFPA 13 maximum distance between hangers table."},
  {id:353, block:4, sec:"Hangers & Support Spacing", q:"NFPA 13 requires that hanger components in contact with the pipe and the structural attachment be:", opts:["Listed (the hanger assembly components must be listed) except for certain permitted standard attachments","Field-welded","Made of plastic","Painted red"], correct:0, re:"Hangers and their components must be listed, with limited exceptions for certain standard structural attachments (e.g., common fasteners to the building). Ref: NFPA 13 hanger listing requirements."},
  {id:354, block:4, sec:"Hangers & Support Spacing", q:"The minimum hanger rod diameter for sprinkler pipe 4 in. and smaller, per NFPA 13, is:", opts:["1/4 in.","3/8 in.","1/2 in.","5/8 in."], correct:1, re:"NFPA 13 hanger rod size table requires a minimum 3/8 in. rod for pipe up to and including 4 in. Ref: NFPA 13 hanger rod size table."},
  {id:355, block:4, sec:"Hangers & Support Spacing", q:"For 5 in. and 6 in. sprinkler pipe, the minimum hanger rod diameter required by NFPA 13 is:", opts:["3/8 in.","5/8 in.","1/2 in.","3/4 in."], correct:2, re:"NFPA 13 requires a minimum 1/2 in. hanger rod for 5 in. and 6 in. pipe (3/8 in. for 4 in. and smaller). Ref: NFPA 13 hanger rod size table."},
  {id:356, block:4, sec:"Hangers & Support Spacing", q:"For 8 in. sprinkler pipe, the minimum hanger rod diameter required by NFPA 13 is:", opts:["3/8 in.","1/2 in.","1 in.","5/8 in."], correct:3, re:"NFPA 13 requires a minimum 5/8 in. hanger rod for 8 in. (and similar large) pipe. Ref: NFPA 13 hanger rod size table."},
  {id:357, block:4, sec:"Hangers & Support Spacing", q:"On a branch line, NFPA 13 requires at least one hanger between sprinklers when the distance between them exceeds:", opts:["6 ft","3 ft","10 ft","12 ft"], correct:0, re:"NFPA 13 requires a hanger between sprinklers where the spacing exceeds 6 ft on the branch line. Ref: NFPA 13 location of hangers on branch lines."},
  {id:358, block:4, sec:"Hangers & Support Spacing", q:"For steel branch-line pipe, the maximum unsupported length between the end sprinkler and the last hanger on the line is generally limited (by pipe size) to about:", opts:["6 in. regardless of size","36 in. for 1 in. up to 48 in. for larger steel sizes","10 ft for all sizes","No limit"], correct:1, re:"NFPA 13 limits the unsupported arm length from the last hanger to the end sprinkler by pipe size for steel (on the order of 36 in. for 1 in., increasing for larger pipe). Ref: NFPA 13 end-of-line / unsupported length provisions for steel."},
  {id:359, block:4, sec:"Hangers & Support Spacing", q:"For COPPER tube of 1 in. nominal size, NFPA 13 limits the unsupported horizontal length from the last hanger to the end sprinkler to:", opts:["12 in.","24 in.","18 in.","30 in."], correct:2, re:"NFPA 13 limits copper unsupported end length to 18 in. (1 in.), 24 in. (1-1/4 in.), and 30 in. (1-1/2 in. and larger). Ref: NFPA 13 unsupported length for copper tube."},
  {id:360, block:4, sec:"Hangers & Support Spacing", q:"Because copper tube is less rigid than steel, NFPA 13 generally requires hanger spacing for copper that is:", opts:["Greater than for steel","Exactly the same as steel always","Unlimited","Closer (shorter maximum spacing) than for steel of the same size in the smaller sizes"], correct:3, re:"Copper's lower stiffness requires closer support than steel in the small sizes (e.g., copper spacing ranges roughly 8-15 ft by size vs. 12-15 ft for steel). Ref: NFPA 13 maximum distance between hangers (copper tube)."},
  {id:361, block:4, sec:"Hangers & Support Spacing", q:"Listed CPVC sprinkler pipe of 1 in. size typically has a maximum support spacing on the order of:", opts:["Around 5.5 to 6 ft per its listing","15 ft","12 ft","30 ft"], correct:0, re:"CPVC requires much closer support than metal (about 5.5-6 ft for small sizes, up to ~10 ft for larger), as set by its listing and reflected in NFPA 13. Ref: NFPA 13 / CPVC listing hanger spacing."},
  {id:362, block:4, sec:"Hangers & Support Spacing", q:"A trapeze hanger is used when:", opts:["The pipe is plastic only","A structural member is not directly above the pipe and the load must be transferred to two adjacent members","The pipe is underground","No hangers are available"], correct:1, re:"A trapeze hanger spans between two structural members to support pipe where no member lies directly above it; NFPA 13 requires it be sized for the load using the section-modulus tables. Ref: NFPA 13 trapeze hanger provisions."},
  {id:363, block:4, sec:"Hangers & Support Spacing", q:"When sizing a trapeze (support) member, NFPA 13 requires the designer to verify the member's:", opts:["Color","Thread pitch","Section modulus (to ensure adequate strength for the supported pipe and span)","Listing as a sprinkler"], correct:2, re:"The trapeze member must have a section modulus at least equal to the value required by NFPA 13's trapeze tables for the supported pipe size and span. Ref: NFPA 13 trapeze hanger section-modulus tables."},
  {id:364, block:4, sec:"Hangers & Support Spacing", q:"NFPA 13 requires each hanger (and its supporting structure) to be capable of supporting:", opts:["Only the weight of the empty pipe","Twice the empty pipe weight","Only the sprinkler weight","Five times the weight of the water-filled pipe plus 250 lb at each point of piping support"], correct:3, re:"NFPA 13 requires hangers and their fasteners to support five times the weight of the water-filled pipe plus 250 lb at each point of support. Ref: NFPA 13 hanger load (safety factor) requirement."},
  {id:365, block:4, sec:"Hangers & Support Spacing", q:"The first hanger on a branch line, measured from the cross main connection, must generally be located within:", opts:["No more than the maximum spacing distance for that pipe (per the branch-line hanger rules)","Exactly 6 in.","30 ft","No limit"], correct:0, re:"NFPA 13 ties the location of the first/each hanger on a branch line to the maximum spacing for the pipe size, with specific limits at the start of the line near the cross main. Ref: NFPA 13 location of hangers on branch lines."},
  {id:366, block:4, sec:"Hangers & Support Spacing", q:"Where a sprinkler is installed on a riser nipple (sprig-up) longer than a specified length, NFPA 13 requires:", opts:["No support at all","The sprig/riser nipple to be restrained or supported (e.g., when it exceeds the listed unsupported height, commonly 30 in.)","A trapeze hanger only","Welding it shut"], correct:1, re:"A sprig-up exceeding the permitted unsupported length (commonly 30 in.) must be restrained against lateral movement/whip. Ref: NFPA 13 support of riser nipples / sprigs."},
  {id:367, block:4, sec:"Hangers & Support Spacing", q:"Powder-driven studs and welded studs used to attach hangers to the building structure must be:", opts:["Any hardware-store fastener","Plastic anchors","Listed for the service or installed per an approved method and not used to support pipe in tension beyond their rating","Avoided entirely"], correct:2, re:"NFPA 13 limits powder-driven/welded studs and other fasteners to listed/approved types and load ratings, with restrictions on use in certain materials. Ref: NFPA 13 fasteners in concrete/steel provisions."},
  {id:368, block:4, sec:"Sway Bracing Design", q:"The purpose of LATERAL sway bracing is to resist horizontal movement of the piping:", opts:["Parallel to the pipe run","Only vertically","Only torsionally","Perpendicular (at right angles) to the pipe run"], correct:3, re:"Lateral braces resist horizontal seismic loads acting perpendicular to the axis of the braced pipe. Ref: NFPA 13 seismic bracing definitions (lateral brace)."},
  {id:369, block:4, sec:"Sway Bracing Design", q:"The purpose of LONGITUDINAL sway bracing is to resist horizontal movement of the piping:", opts:["Parallel to (along the axis of) the pipe run","Perpendicular to the pipe run","Only vertically downward","Only at the sprinkler"], correct:0, re:"Longitudinal braces resist horizontal seismic loads acting parallel to (along) the axis of the braced pipe. Ref: NFPA 13 seismic bracing definitions (longitudinal brace)."},
  {id:370, block:4, sec:"Sway Bracing Design", q:"The maximum spacing between LATERAL sway braces on feed and cross mains is:", opts:["20 ft","40 ft","80 ft","100 ft"], correct:1, re:"NFPA 13 limits lateral brace spacing to a maximum of 40 ft on center. Ref: NFPA 13 lateral sway bracing maximum spacing."},
  {id:371, block:4, sec:"Sway Bracing Design", q:"The maximum spacing between LONGITUDINAL sway braces is:", opts:["40 ft","60 ft","80 ft","120 ft"], correct:2, re:"NFPA 13 limits longitudinal brace spacing to a maximum of 80 ft on center. Ref: NFPA 13 longitudinal sway bracing maximum spacing."},
  {id:372, block:4, sec:"Sway Bracing Design", q:"The last lateral sway brace on a run of pipe must be located within what distance of the end of the pipe?", opts:["12 ft","24 ft","40 ft","6 ft"], correct:3, re:"NFPA 13 requires the last lateral brace to be within 6 ft of the end of the piping. Ref: NFPA 13 lateral brace distance-to-end requirement."},
  {id:373, block:4, sec:"Sway Bracing Design", q:"The last longitudinal sway brace must be located within what distance of the end of the pipe?", opts:["40 ft","6 ft","12 ft","24 ft"], correct:0, re:"NFPA 13 requires the last longitudinal brace to be within 40 ft of the end of the piping. Ref: NFPA 13 longitudinal brace distance-to-end requirement."},
  {id:374, block:4, sec:"Sway Bracing Design", q:"Lateral sway bracing is required on branch lines (and mains) when the pipe is at least what nominal size?", opts:["1 in.","2-1/2 in.","1-1/2 in.","6 in."], correct:1, re:"NFPA 13 requires bracing of feed/cross mains and of branch lines 2-1/2 in. and larger; smaller branch lines are restrained but not necessarily braced. Ref: NFPA 13 bracing scope (2-1/2 in. and larger)."},
  {id:375, block:4, sec:"Sway Bracing Design", q:"The 'zone of influence' of a sway brace is best described as:", opts:["The area of the building floor it occupies","The pipe's pressure rating","The length/weight of piping that the brace is responsible for restraining until the next brace takes over","The clearance hole around a penetration"], correct:2, re:"The zone of influence is the portion of piping (and contained water) tributary to a given brace, used with the seismic coefficient to compute the brace load. Ref: NFPA 13 seismic load determination (zone of influence)."},
  {id:376, block:4, sec:"Sway Bracing Design", q:"The horizontal seismic load (Fpw) used to size a sway brace is computed as:", opts:["Fpw = pipe diameter / 2","Fpw = length x C value","Fpw = 250 lb fixed","Fpw = Cp x Wp (seismic coefficient times the tributary weight of pipe and water)"], correct:3, re:"NFPA 13 computes the brace load as Fpw = Cp x Wp, where Cp is the seismic coefficient and Wp is the weight of water-filled pipe in the zone of influence. Ref: NFPA 13 seismic brace load formula."},
  {id:377, block:4, sec:"Sway Bracing Design", q:"In NFPA 13's seismic procedure, the coefficient Cp is determined primarily from:", opts:["The mapped short-period spectral response (Ss) at the site","The pipe color","The number of sprinklers","The C value of the pipe"], correct:0, re:"Cp is taken from NFPA 13's table as a function of the site's short-period spectral response acceleration Ss (often defaulting near 0.5 absent site-specific data). Ref: NFPA 13 seismic coefficient (Cp) table and Ss."},
  {id:378, block:4, sec:"Sway Bracing Design", q:"A sway brace must be installed at an angle from the vertical (or as measured per NFPA 13) of at least:", opts:["10 degrees","30 degrees","60 degrees","75 degrees"], correct:1, re:"NFPA 13 requires sway braces to make an angle of at least 30 degrees from the vertical (preferably 45-90 degrees) to be effective; angles below 30 degrees are not credited. Ref: NFPA 13 sway brace angle requirements."},
  {id:379, block:4, sec:"Sway Bracing Design", q:"At the top of a sprinkler riser, NFPA 13 requires:", opts:["No bracing","Only a hanger","Four-way bracing (both lateral and longitudinal restraint)","Only a flexible coupling"], correct:2, re:"Risers must be provided with four-way bracing (resisting movement in both horizontal directions) located near the top of the riser within the required distance. Ref: NFPA 13 four-way bracing of risers."},
  {id:380, block:4, sec:"Sway Bracing Design", q:"A single lateral brace may also serve as a longitudinal brace for an adjacent run when:", opts:["Never; they must always be separate","The pipe is plastic","The brace angle is below 30 degrees","The brace is within the allowed offset (e.g., within 24 in. of the pipe centerline) and the connecting pipe is of equal or greater size"], correct:3, re:"NFPA 13 allows a lateral brace to act longitudinally for a connected line when located within the permitted distance (about 24 in.) of the centerline and the connecting pipe is at least equal in size. Ref: NFPA 13 brace sharing provisions."},
  {id:381, block:4, sec:"Sway Bracing Design", q:"Sway brace assemblies and their fasteners must be sized so that they do not fail before the building loads are imposed; therefore NFPA 13 requires the brace components to be:", opts:["Listed and selected from the brace load tables for the calculated load and brace angle","Unlisted and field-built","Larger than 4 in. pipe","Welded to the sprinkler"], correct:0, re:"NFPA 13 requires listed sway brace components selected from the load tables based on the calculated Fpw and the installed brace angle and length. Ref: NFPA 13 sway brace component listing and load tables."},
  {id:382, block:4, sec:"Sway Bracing Design", q:"The slenderness ratio (l/r) of a sway brace member matters because:", opts:["It sets the pipe C value","It limits the compressive (buckling) capacity of braces that resist load in compression","It determines the sprinkler k-factor","It has no effect"], correct:1, re:"For braces resisting compression, NFPA 13 limits the slenderness ratio (length/radius of gyration) to prevent buckling; cable braces resist tension only. Ref: NFPA 13 sway brace member slenderness limits."},
  {id:383, block:4, sec:"Sway Bracing Design", q:"Cable (wire-rope) sway braces differ from rigid braces in that cable braces:", opts:["Resist both tension and compression","Are used only underground","Resist tension only, so they must be installed in opposing pairs for each direction","Require no listing"], correct:2, re:"Cable braces carry tension only; to brace a direction they are arranged so a cable resists each sense of movement (opposing pairs), unlike rigid braces that take tension or compression. Ref: NFPA 13 cable sway brace provisions."},
  {id:384, block:4, sec:"Seismic Separation & Flexibility", q:"A seismic separation assembly is required wherever sprinkler piping:", opts:["Changes from steel to copper","Connects to a sprinkler","Passes under a door","Crosses a building seismic separation (expansion) joint"], correct:3, re:"NFPA 13 requires a seismic separation assembly with flexible fittings, regardless of pipe size, where piping crosses a building seismic separation joint above ground. Ref: NFPA 13 seismic separation assembly requirement."},
  {id:385, block:4, sec:"Seismic Separation & Flexibility", q:"The function of a seismic separation assembly is to:", opts:["Permit movement in all directions so differential motion of the two building sections does not break the pipe","Increase water pressure","Reduce friction loss","Act as a check valve"], correct:0, re:"The assembly uses flexible couplings/fittings to accommodate multi-directional differential movement across the joint, preventing pipe rupture. Ref: NFPA 13 seismic separation assembly purpose."},
  {id:386, block:4, sec:"Seismic Separation & Flexibility", q:"Flexible couplings are required to be installed within what distance of the top and bottom of each sprinkler riser?", opts:["6 in.","24 in.","12 in.","48 in."], correct:1, re:"NFPA 13 requires a listed flexible coupling within 24 in. of the top and bottom of each riser (with exceptions for short risers). Ref: NFPA 13 flexible coupling location at risers."},
  {id:387, block:4, sec:"Seismic Separation & Flexibility", q:"In a multistory building, NFPA 13 requires flexible couplings on risers at each floor, generally located within:", opts:["No specific distance","10 ft of the floor","12 in. above and 24 in. below the floor/ceiling per the rule","The middle of the story only"], correct:2, re:"NFPA 13 requires flexible couplings near each floor (commonly within 12 in. above and 24 in. below the floor) to accommodate inter-story drift. Ref: NFPA 13 flexible coupling requirements at floors in multistory buildings."},
  {id:388, block:4, sec:"Seismic Separation & Flexibility", q:"Where sprinkler pipe 1 in. through 3-1/2 in. nominal passes through walls or floors, NFPA 13 requires a nominal clearance (gap) around the pipe so the hole diameter is larger than the pipe by:", opts:["No clearance needed","6 in. total","12 in. total","2 in. total (about 1 in. all around)"], correct:3, re:"For pipe 1 in. to 3-1/2 in. nominal, the hole is sized about 2 in. larger than the pipe (roughly 1 in. clearance per side) to allow movement. Ref: NFPA 13 clearance around piping at penetrations."},
  {id:389, block:4, sec:"Seismic Separation & Flexibility", q:"For sprinkler pipe 4 in. nominal and larger passing through walls/floors, the required hole is larger than the pipe by approximately:", opts:["4 in. total (about 2 in. all around)","2 in. total","No clearance","12 in. total"], correct:0, re:"For 4 in. and larger pipe, the hole is sized about 4 in. larger than the pipe (about 2 in. clearance per side). Ref: NFPA 13 clearance around piping at penetrations."},
  {id:390, block:4, sec:"Seismic Separation & Flexibility", q:"The clearance gap around a pipe penetration in a fire-rated assembly must still:", opts:["Be left completely open","Be filled with a listed flexible/yielding firestop (resilient material) that maintains the rating yet allows movement","Be welded shut","Be grouted solid with concrete"], correct:1, re:"Where required clearance penetrates a rated barrier, a listed flexible firestop system is used so the pipe can move while the fire rating is preserved. Ref: NFPA 13 clearance provisions used with listed flexible firestopping."},
  {id:391, block:4, sec:"Seismic Separation & Flexibility", q:"NFPA 13 permits the clearance around a penetration to be omitted (no gap required) when:", opts:["The pipe is 8 in. or larger","The wall is painted","A listed flexible coupling is provided within a specified distance on each side of the penetration","The pipe is copper"], correct:2, re:"The clearance can be omitted where a flexible coupling is installed within the specified distance on both sides of the penetration, since that joint accommodates the movement. Ref: NFPA 13 clearance exception with adjacent flexible couplings."},
  {id:392, block:4, sec:"Seismic Separation & Flexibility", q:"Small branch-line pipe (less than 2-1/2 in.) that is not braced must still be:", opts:["Left free to swing","Welded to the ceiling","Sized as 4 in.","Restrained against excessive lateral movement near the end of the line (e.g., by listed restraints or U-hooks)"], correct:3, re:"NFPA 13 requires end-of-line restraint for unbraced branch lines (using wraparound U-hooks or listed restraint devices) to limit movement, even though full bracing is not required. Ref: NFPA 13 restraint of branch lines."},
  {id:393, block:4, sec:"Seismic Separation & Flexibility", q:"A listed flexible coupling used for seismic purposes provides protection by allowing:", opts:["A small amount of angular/axial movement at the joint so stress is not transmitted as a rigid moment","Higher flow only","Electrical grounding","Pressure reduction"], correct:0, re:"Flexible couplings accommodate limited angular and axial movement, relieving seismic stress that a rigid joint would otherwise transmit to the pipe and fittings. Ref: NFPA 13 flexible coupling function in seismic design."},
  {id:394, block:4, sec:"Seismic Separation & Flexibility", q:"NFPA 13 generally permits OMITTING seismic bracing (and related provisions) where:", opts:["The pipe is plastic","The building is in a region/zone exempted by the standard or the AHJ does not require seismic protection","The system is dry","The ceiling is high"], correct:1, re:"Seismic protection per NFPA 13 applies where required by the AHJ or in defined seismic regions; it may be omitted where seismic design is not required for the site. Ref: NFPA 13 applicability of seismic protection (where required)."},
  {id:395, block:4, sec:"Seismic Separation & Flexibility", q:"Drops to hose lines, rack sprinklers, and mezzanines, and other portions subject to differential movement, should be protected by:", opts:["Rigid welding only","Removing the drop","Flexibility (e.g., flexible couplings or listed flexible connections) to absorb relative movement","Larger C values"], correct:2, re:"Where relative movement is expected (between racks/structure and the system), flexible couplings or listed flexible connections are used so drops are not sheared. Ref: NFPA 13 flexibility provisions for drops subject to differential movement."},
  {id:396, block:4, sec:"Seismic Separation & Flexibility", q:"A primary reason riser flexible couplings are placed close to floor penetrations in tall buildings is to accommodate:", opts:["Thermal expansion only","Pressure surges","Water hammer from sprinklers","Interstory drift (relative horizontal displacement between adjacent floors during an earthquake)"], correct:3, re:"Flexible couplings near floors absorb interstory drift so seismic relative displacement between stories does not fracture the riser. Ref: NFPA 13 flexible coupling rationale at floors."},
  {id:397, block:4, sec:"Seismic Separation & Flexibility", q:"When piping is rigidly attached to two separate structures (or a structure and equipment) that can move independently, NFPA 13 requires:", opts:["Flexibility between the two attachment points so differential movement is not resisted rigidly","A larger pipe size","A swing check valve","A pressure-reducing valve"], correct:0, re:"Flexibility (flexible couplings/separation assembly) must be provided between independently moving supports to prevent the pipe from being torn by differential motion. Ref: NFPA 13 flexibility between independent structures."},
  {id:398, block:4, sec:"Seismic Separation & Flexibility", q:"For NFPA 13 (as opposed to FM Global) seismic protection, the brace and restraint components are required to be:", opts:["FM Approved only","Listed (e.g., UL listed) for the service","Unlisted shop fabrications","Made of cast iron"], correct:1, re:"NFPA 13 requires listed components for sway bracing and restraint; FM Global standards instead require FM Approved components. Ref: NFPA 13 listing requirement for bracing components."},
  {id:399, block:4, sec:"Seismic Separation & Flexibility", q:"The overall goal of NFPA 13's seismic provisions (bracing, flexible couplings, clearances, separation assemblies) is to:", opts:["Increase the system's flow rate","Lower the water pressure","Keep the sprinkler system intact and operational after an earthquake by limiting damaging movement while allowing necessary movement","Reduce the number of sprinklers"], correct:2, re:"The seismic package limits damaging differential movement (bracing) while permitting needed movement (couplings, clearances, separation assemblies) so the system survives and operates post-event. Ref: NFPA 13 purpose of earthquake protection of piping."},
  {id:400, block:4, sec:"Seismic Separation & Flexibility", q:"A short riser is exempt from one or both required flexible couplings when its length is below a threshold; NFPA 13 commonly allows omission of couplings on a riser that is less than:", opts:["1 ft long","12 ft long","20 ft long","3 ft long (with a single coupling permitted for 3 ft to 7 ft risers)"], correct:3, re:"NFPA 13 permits omitting flexible couplings on risers under 3 ft, and a single flexible coupling on risers 3 ft to 7 ft long. Ref: NFPA 13 flexible coupling exceptions for short risers."},
  {id:401, block:5, sec:"Water Supply Analysis", q:"In a fire hydrant flow test, which three pressure/flow values are recorded to define the water supply available to a system?", opts:["Static pressure, residual pressure, and flowing (pitot) discharge","Churn pressure, rated pressure, and overload pressure","Working pressure, hydrostatic pressure, and surge pressure","Net pressure, suction pressure, and discharge pressure"], correct:0, re:"A hydrant flow test records static pressure (no flow), residual pressure at the test hydrant while water flows, and the flowing discharge (computed from pitot pressure at the flowed hydrant). Reference: NFPA 291, Recommended Practice for Fire Flow Testing and Marking of Hydrants."},
  {id:402, block:5, sec:"Water Supply Analysis", q:"On a water supply graph used for hydraulic design, the supply curve is plotted using which exponent on log-log (N^1.85) graph paper?", opts:["1.50","1.85","2.00","2.63"], correct:1, re:"Water supply curves are plotted on N^1.85 graph paper, matching the Hazen-Williams friction exponent (Q^1.85), so the supply line plots as a straight line. Reference: NFPA 291; NFPA 13 hydraulic calculation procedures."},
  {id:403, block:5, sec:"Water Supply Analysis", q:"The flowing discharge (Q, gpm) from a hydrant outlet during a flow test is calculated from which measured quantity?", opts:["The residual pressure at an adjacent hydrant","The static pressure before flow begins","The pitot (velocity) pressure at the flowing outlet","The elevation difference to the highest sprinkler"], correct:2, re:"Discharge is computed as Q = 29.83 x c x d^2 x sqrt(p), where p is the pitot (velocity) pressure read at the flowing outlet, d is outlet diameter, and c is the discharge coefficient. Reference: NFPA 291 flow computation."},
  {id:404, block:5, sec:"Water Supply Analysis", q:"A flow test gives a static of 70 psi and a residual of 50 psi while flowing 1,000 gpm. Compared with a test that drops to 30 psi at 1,000 gpm, the first water supply is:", opts:["Weaker, because the residual dropped less","Identical, because both flowed 1,000 gpm","Indeterminate without the pitot reading","Stronger, because the residual dropped less for the same flow"], correct:3, re:"A smaller pressure drop (70 to 50 psi vs 70 to 30 psi) for the same flow indicates a stronger, stiffer supply with more available pressure at higher flows. Reference: NFPA 291 supply curve interpretation."},
  {id:405, block:5, sec:"Water Supply Analysis", q:"For sprinkler system design, the system demand (flow and pressure) must be compared against the available water supply at what point?", opts:["At a common reference point where both are known, such as the supply source","At the base of the riser only","At the most remote sprinkler","At the fire department connection"], correct:0, re:"Demand and supply are plotted/compared at a common reference point (often the source or a defined node) where the characteristics of both are known. NFPA 13 requires calculations to extend to the effective point of the water supply. Reference: NFPA 13, Plans and Calculations."},
  {id:406, block:5, sec:"Water Supply Analysis", q:"When a hydraulically calculated sprinkler demand is plotted on the water supply graph and falls BELOW the available supply curve, the result indicates:", opts:["The supply is inadequate and a fire pump is required","The supply is adequate to meet the demand","The pipe sizes must all be increased","The test data are invalid"], correct:1, re:"If the demand point lies below (and to the left of) the available supply curve, the supply can deliver the required flow at or above the required pressure, so the supply is adequate. Reference: NFPA 13 hydraulic graph analysis; NFPA 291."},
  {id:407, block:5, sec:"Water Supply Analysis", q:"Friction loss in fire protection piping is most commonly calculated using which formula?", opts:["Bernoulli equation","Darcy-Weisbach equation","Hazen-Williams formula","Manning formula"], correct:2, re:"NFPA 13 specifies pipe friction loss be determined using the Hazen-Williams formula, with a C-factor appropriate to the pipe material. Reference: NFPA 13, hydraulic calculation procedures."},
  {id:408, block:5, sec:"Water Supply Analysis", q:"In the Hazen-Williams formula, a LOWER C-factor value represents:", opts:["Smoother pipe with less friction loss","Larger pipe diameter","Higher water temperature","Rougher pipe with greater friction loss"], correct:3, re:"The Hazen-Williams C-factor describes pipe interior roughness; a lower C means a rougher interior and therefore greater friction loss for a given flow. Reference: NFPA 13 C-factor tables (e.g., C=120 for unlined cast/ductile iron, C=140 for cement-lined)."},
  {id:409, block:5, sec:"Water Supply Analysis", q:"Velocity pressure in a hydraulic calculation is the portion of pressure attributable to:", opts:["The velocity (motion) of the flowing water","Elevation of the water above the gauge","Atmospheric pressure on the surface","Backflow from the public main"], correct:0, re:"Velocity pressure (Pv = 0.001123 Q^2 / d^4) is the pressure due to the kinetic energy of moving water; normal pressure is the difference between total and velocity pressure. Reference: NFPA 13 hydraulic calculation definitions."},
  {id:410, block:5, sec:"Water Supply Analysis", q:"Elevation (pressure) loss in a fire protection system is taken as approximately:", opts:["0.500 psi per foot of elevation","0.433 psi per foot of elevation","1.000 psi per foot of elevation","2.310 psi per foot of elevation"], correct:1, re:"A column of water exerts 0.433 psi per foot of height (equivalently, 1 psi per 2.31 ft). Elevation gains are added to the pressure demand in hydraulic calculations. Reference: NFPA 13 hydraulic calculation procedures."},
  {id:411, block:5, sec:"Water Supply Analysis", q:"A flow test is conducted to size a fire pump. NFPA 20 requires the flow test data used for sizing to have been performed within the prior:", opts:["3 months","6 months","12 months","24 months"], correct:2, re:"NFPA 20 requires that the water flow test used to determine the water supply for fire pump sizing be conducted within 12 months of the design (current edition). Reference: NFPA 20, Standard for the Installation of Stationary Pumps for Fire Protection."},
  {id:412, block:5, sec:"Water Supply Analysis", q:"When projecting a water supply curve, fire flow is commonly evaluated at a residual pressure of:", opts:["40 psi","65 psi","100 psi","20 psi"], correct:3, re:"Available fire flow is typically reported at 20 psi residual, a common minimum operating pressure threshold for public mains and the standard projection point on supply graphs. Reference: NFPA 291; AWWA/ISO fire flow practice."},
  {id:413, block:5, sec:"Water Supply Analysis", q:"To convert a flow Q1 observed at residual P1 to a flow at a different residual, the analyst uses the relationship Q2 = Q1 x (h2/h1)^0.54, where h is:", opts:["The pressure drop (static minus residual)","The pipe diameter","The elevation head only","The pitot pressure"], correct:0, re:"In NFPA 291, h = pressure drop = static minus residual; the rated capacity at a target residual is QR = QF x (hr/hf)^0.54. Reference: NFPA 291 flow projection equation."},
  {id:414, block:5, sec:"Water Supply Analysis", q:"A 'looped' or gridded supply main, compared with a single dead-end main of the same size, generally provides:", opts:["Lower available flow due to added friction","Higher available flow because water reaches a point from multiple paths","No difference in available flow","Higher static but lower residual pressure"], correct:1, re:"Looped/gridded mains feed a demand point from more than one direction, reducing effective friction loss and increasing the flow available at a given residual pressure compared with a dead-end main. Reference: NFPA 24/NFPA 291 supply principles."},
  {id:415, block:5, sec:"Water Supply Analysis", q:"In water supply analysis for design, 'available pressure' at the point of supply connection refers to:", opts:["The pressure the system requires to operate","The maximum pressure the pump can produce at churn","The pressure the public/private supply can deliver at the design flow","The hydrostatic test pressure"], correct:2, re:"Available pressure is what the supply can deliver at the connection point at the required flow; it must equal or exceed the system demand pressure (plus safety margin) for the design to work. Reference: NFPA 13/NFPA 291."},
  {id:416, block:5, sec:"Water Supply Analysis", q:"A design safety cushion is often applied so the demand point does not lie exactly on the supply curve. A common practice is to keep the available supply at least:", opts:["Exactly equal to demand","Triple the demand pressure","Below the demand to allow for surge","About 10 psi (or 10%) above the calculated demand"], correct:3, re:"Designers typically provide a margin (commonly on the order of 10 psi or 10%) between available supply and calculated demand to account for supply fluctuation and deterioration over time. Reference: common NFPA 13 design practice / AHJ requirements."},
  {id:417, block:5, sec:"Water Supply Analysis", q:"If a building's available water supply is adequate in flow but deficient in PRESSURE for the sprinkler demand, the most appropriate remedy is typically to:", opts:["Install a fire pump to boost pressure","Reduce the design area","Add more hydrants to the public main","Lower the C-factor used in calculations"], correct:0, re:"When flow is sufficient but pressure is short of demand, a fire pump is added to boost pressure to the required level. A tank (with pump) addresses flow/volume shortfalls. Reference: NFPA 20; NFPA 13 design."},
  {id:418, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"NFPA 20 limits the maximum churn (no-flow, shutoff) pressure of a centrifugal fire pump to no more than what percentage of its rated pressure?", opts:["100% of rated pressure","140% of rated pressure","120% of rated pressure","150% of rated pressure"], correct:1, re:"NFPA 20 requires the churn (no-flow) pressure not exceed 140% of the pump's rated pressure, limiting maximum system pressure. Reference: NFPA 20, performance requirements for centrifugal fire pumps."},
  {id:419, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"At 150% of its rated capacity (the overload point), a fire pump must deliver a net pressure of at least:", opts:["50% of rated pressure","85% of rated pressure","65% of rated pressure","100% of rated pressure"], correct:2, re:"NFPA 20 requires the pump produce at least 65% of rated pressure at 150% of rated flow, defining the overload end of the performance envelope. Reference: NFPA 20 centrifugal pump performance."},
  {id:420, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"The three defining points of a fire pump performance curve under NFPA 20 are:", opts:["Suction, discharge, and net","Static, residual, and pitot","Low, medium, and high speed","Churn (no-flow), 100% rated flow, and 150% rated flow"], correct:3, re:"A fire pump's curve is defined by churn (0% flow, <=140% pressure), the 100% rated point (rated flow at rated pressure), and the 150% overload point (>=65% pressure). Reference: NFPA 20."},
  {id:421, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"A 'fire pump rating' (e.g., 750 gpm at 100 psi) refers to the pump's net pressure delivered at:", opts:["100% of rated capacity","Churn / no flow","150% of rated capacity","The lowest permissible suction pressure"], correct:0, re:"The pump rating is the net pressure it produces at 100% of its rated capacity. Churn and 150% are evaluated relative to this rated point. Reference: NFPA 20."},
  {id:422, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"Which of the following is a STANDARD rated capacity for a centrifugal fire pump under NFPA 20?", opts:["650 gpm","750 gpm","725 gpm","850 gpm"], correct:1, re:"NFPA 20 lists standard rated capacities including 250, 500, 750, 1000, 1250, 1500 gpm (and others). 750 gpm is standard; 650, 725, and 850 gpm are not listed standard ratings. Reference: NFPA 20 rated capacity table."},
  {id:423, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"The primary function of a jockey (pressure maintenance) pump is to:", opts:["Provide the full fire flow demand","Test the main pump weekly","Maintain system pressure and prevent unnecessary starting of the main fire pump","Boost suction pressure during a fire"], correct:2, re:"A jockey pump maintains pressure within preset limits to compensate for minor leakage, preventing needless main-pump starts. It is not sized to meet fire demand. Reference: NFPA 20, pressure maintenance pumps."},
  {id:424, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"A jockey pump for a sprinkler/standpipe system should generally be sized to deliver a flow that is:", opts:["Equal to the main pump capacity","Equal to 50% of the main pump capacity","Exactly 150% of the main pump capacity","Less than the flow of a single sprinkler, so the main pump starts on any actual waterflow"], correct:3, re:"NFPA 20 guidance sizes the jockey pump to make up allowable leakage and to deliver less than one sprinkler's flow, so any real sprinkler operation drops pressure and starts the main pump. Reference: NFPA 20 pressure maintenance pump sizing."},
  {id:425, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"The minimum rated net pressure for a centrifugal fire pump under NFPA 20 is:", opts:["40 psi","20 psi","65 psi","100 psi"], correct:0, re:"NFPA 20 requires centrifugal fire pumps be rated at net pressures of 40 psi (2.7 bar) or more. Reference: NFPA 20 centrifugal pump rating requirements."},
  {id:426, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"To minimize wasted/excess pressure, NFPA 20 advises selecting a pump whose RATED point places the design demand flow within roughly:", opts:["10% to 50% of rated flow","90% to 140% of rated flow","150% to 200% of rated flow","0% (churn) only"], correct:1, re:"Designers select a pump so the required system flow falls between about 90% and 140% of rated capacity (never above 150%), keeping the operating point on the useful part of the curve. Reference: NFPA 20 selection practice."},
  {id:427, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"During an acceptance/flow test, a fire pump's output is measured at how many flow conditions, at minimum?", opts:["One (rated only)","Two (churn and rated)","Three (churn, 100% rated, and 150% rated)","Five"], correct:2, re:"The fire pump is tested at a minimum of three conditions: no-flow (churn), 100% of rated flow, and 150% of rated flow. Reference: NFPA 20 / NFPA 25 pump test."},
  {id:428, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"'Net pump pressure' for a fire pump is defined as:", opts:["Discharge pressure plus suction pressure","Suction pressure only","Churn pressure minus 140%","Discharge pressure minus suction pressure (with velocity-head correction)"], correct:3, re:"Net pressure is discharge gauge pressure minus suction gauge pressure (adjusted for velocity head and gauge elevation). It represents the pressure the pump itself adds. Reference: NFPA 20 definitions."},
  {id:429, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"For pumps taking suction from a public main, NFPA 20 requires the gauge suction pressure during the maximum (150%) flow test generally not drop below:", opts:["0 psi (gauge), unless a lower value is permitted by the AHJ","20 psi minimum in all cases","40 psi minimum in all cases","65 psi minimum in all cases"], correct:0, re:"NFPA 20 limits suction pressure to not less than 0 psi gauge at 150% flow for pumps on a supply (some AHJs/water purveyors require a higher minimum such as 20 psi). Reference: NFPA 20 suction supply requirements."},
  {id:430, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"A horizontal split-case fire pump, compared with a vertical turbine fire pump, is typically NOT suitable when:", opts:["The supply is a pressurized public main above the pump","The water source is below the pump centerline (e.g., a below-grade tank or well, requiring suction lift)","High flow is required","A diesel driver is used"], correct:1, re:"Horizontal split-case pumps require a positive (flooded) suction and cannot lift water; a vertical turbine pump is used when the source level is below the pump, such as a well or below-grade tank. Reference: NFPA 20 pump types."},
  {id:431, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"The pressure setting at which the main fire pump is set to START is normally:", opts:["Above the jockey pump start and stop pressures","Equal to the jockey pump stop pressure","Below the jockey pump start pressure","At the churn pressure of the main pump"], correct:2, re:"The control sequence sets stop/start so the jockey pump cycles first; the main fire pump start pressure is set below the jockey pump's start pressure, so the main pump starts only when the jockey cannot maintain pressure. Reference: NFPA 20 pressure-setting guidance."},
  {id:432, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"A fire pump driven by a diesel engine (rather than an electric motor) is commonly selected primarily to:", opts:["Reduce the rated pressure required","Eliminate the need for a controller","Allow churn pressure above 140%","Provide a power source independent of the normal electric utility"], correct:3, re:"A diesel driver provides a reliable, independent power source where utility power reliability is in question or a second source is required. The pump performance criteria (churn, 100%, 150%) are unchanged. Reference: NFPA 20 drivers."},
  {id:433, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"When the available suction supply already provides part of the required pressure, the fire pump need only be rated to:", opts:["Make up the DIFFERENCE between the system demand and the available suction pressure (at the design flow)","Produce the full system demand pressure regardless of suction","Produce 150% of system demand","Match the churn pressure of the public main"], correct:0, re:"The pump is sized to boost pressure by the shortfall: required net pressure equals system demand pressure minus available suction pressure at the design flow. Reference: NFPA 20 pump sizing practice."},
  {id:434, block:5, sec:"Fire Pump Selection (NFPA 20)", q:"A fire pump controller's purpose is to:", opts:["Throttle the pump flow to exactly the demand","Automatically start the pump on pressure drop and provide monitoring/control of the pump driver","Replace the jockey pump","Set the hydrostatic test pressure"], correct:1, re:"The listed fire pump controller starts the pump (typically on a pressure-drop signal), supervises the driver, and provides required alarms/monitoring. Reference: NFPA 20 controllers."},
  {id:435, block:5, sec:"Standpipe Design (NFPA 14)", q:"For a hydraulically designed Class I standpipe system, NFPA 14 requires a minimum residual pressure at the hydraulically most remote 2 1/2 in. hose connection of:", opts:["65 psi","125 psi","100 psi","175 psi"], correct:2, re:"NFPA 14 requires 100 psi minimum residual pressure at the hydraulically most remote 2 1/2 in. (Class I/III) outlet while flowing the required demand. Reference: NFPA 14, Standard for the Installation of Standpipe and Hose Systems."},
  {id:436, block:5, sec:"Standpipe Design (NFPA 14)", q:"For a Class II standpipe system, NFPA 14 requires a minimum residual pressure at the hydraulically most remote 1 1/2 in. hose station of:", opts:["50 psi","100 psi","150 psi","65 psi"], correct:3, re:"NFPA 14 requires 65 psi minimum residual pressure at the hydraulically most remote 1 1/2 in. (Class II) hose station. Reference: NFPA 14 minimum design pressures."},
  {id:437, block:5, sec:"Standpipe Design (NFPA 14)", q:"A Class I standpipe system provides which size hose connection, intended for use by the fire department or trained personnel?", opts:["2 1/2 in. connections","1 in. connections","1 1/2 in. connections","4 in. connections"], correct:0, re:"Class I systems provide 2 1/2 in. hose connections for fire department/trained personnel use. Class II provides 1 1/2 in. for occupant use; Class III provides both. Reference: NFPA 14 system classes."},
  {id:438, block:5, sec:"Standpipe Design (NFPA 14)", q:"A Class III standpipe system provides:", opts:["Only 1 1/2 in. hose connections","Both 1 1/2 in. and 2 1/2 in. hose connections","Only 2 1/2 in. hose connections","Only a fire department connection, no hose valves"], correct:1, re:"Class III combines both: 1 1/2 in. for occupant/first-aid use and 2 1/2 in. for fire department use. Its 2 1/2 in. outlets carry the same 100 psi residual requirement as Class I. Reference: NFPA 14 system classes."},
  {id:439, block:5, sec:"Standpipe Design (NFPA 14)", q:"For a Class I system, the minimum flow rate for the hydraulically most remote standpipe is:", opts:["250 gpm","750 gpm","500 gpm","1,000 gpm"], correct:2, re:"NFPA 14 requires 500 gpm for the hydraulically most remote standpipe (the two most remote 2 1/2 in. outlets at 250 gpm each). Reference: NFPA 14 Class I flow requirements."},
  {id:440, block:5, sec:"Standpipe Design (NFPA 14)", q:"After the first (most remote) standpipe, each additional standpipe in a Class I system adds how much to the required flow?", opts:["100 gpm each","500 gpm each","No additional flow","250 gpm each"], correct:3, re:"NFPA 14 adds 250 gpm for each additional standpipe beyond the most remote one, up to the system maximum. Reference: NFPA 14 Class I flow requirements."},
  {id:441, block:5, sec:"Standpipe Design (NFPA 14)", q:"The maximum total required flow for a Class I standpipe system in a building fully protected by an NFPA 13 sprinkler system is capped at:", opts:["1,000 gpm","500 gpm","750 gpm","1,250 gpm"], correct:0, re:"NFPA 14 caps Class I demand at 1,000 gpm for buildings sprinklered throughout per NFPA 13, and 1,250 gpm where not fully sprinklered. Reference: NFPA 14 maximum flow demand."},
  {id:442, block:5, sec:"Standpipe Design (NFPA 14)", q:"The maximum total required flow for a Class I standpipe system in a building that is NOT fully sprinklered is:", opts:["750 gpm","1,250 gpm","1,000 gpm","1,500 gpm"], correct:1, re:"For buildings not protected throughout by NFPA 13 sprinklers, NFPA 14 caps Class I demand at 1,250 gpm. Reference: NFPA 14 maximum flow demand."},
  {id:443, block:5, sec:"Standpipe Design (NFPA 14)", q:"NFPA 14 limits the maximum static or residual pressure at a hose connection to 175 psi (for 2 1/2 in. outlets); above this value the design must provide:", opts:["A larger standpipe diameter","A second fire department connection","A pressure-reducing or pressure-restricting device on the hose valve","An additional jockey pump"], correct:2, re:"Where pressure at a 2 1/2 in. hose connection exceeds 175 psi, NFPA 14 requires an approved pressure-regulating (reducing/restricting) device to protect firefighters and hose. Reference: NFPA 14 pressure regulation."},
  {id:444, block:5, sec:"Standpipe Design (NFPA 14)", q:"In a Class I system, hose connections in exit stairways are located:", opts:["Only at the top of the building","Only in the lobby","Only at the fire department connection","At the main floor landing of each exit stairway"], correct:3, re:"NFPA 14 requires Class I 2 1/2 in. connections at the main floor landing in exit stairways (with additional locations such as horizontal exits and exit passageways). Reference: NFPA 14 location of hose connections."},
  {id:445, block:5, sec:"Standpipe Design (NFPA 14)", q:"An 'automatic' standpipe system differs from a 'manual' standpipe system in that an automatic system:", opts:["Is attached to a water supply capable of meeting the demand without fire department pumping","Has no fire department connection","Uses only 1 1/2 in. hose","Cannot be hydraulically calculated"], correct:0, re:"An automatic standpipe is connected to a water supply (e.g., city main or fire pump) that meets system demand at all times; a manual system relies on the fire department pumping into the FDC to supply pressure/flow. Reference: NFPA 14 system types."},
  {id:446, block:5, sec:"Standpipe Design (NFPA 14)", q:"A combined (combination) sprinkler/standpipe system is one in which:", opts:["Two separate risers serve sprinklers and standpipes independently","A single riser supplies both the sprinkler system and the 2 1/2 in. hose connections","Only Class II hose is provided","No sprinklers are installed"], correct:1, re:"A combined system uses a single riser to serve both automatic sprinklers and standpipe hose connections; the design must satisfy both demands. Reference: NFPA 14 combined systems."},
  {id:447, block:5, sec:"Standpipe Design (NFPA 14)", q:"The fire department connection (FDC) for a standpipe system must be sized with at least how many 2 1/2 in. inlets per 250 gpm of standpipe demand?", opts:["Two inlets per 250 gpm","One inlet per 1,000 gpm","One inlet per 250 gpm","No relationship to demand"], correct:2, re:"NFPA 14 requires the FDC to provide one 2 1/2 in. inlet for each 250 gpm of the required standpipe system demand. Reference: NFPA 14 fire department connections."},
  {id:448, block:5, sec:"Standpipe Design (NFPA 14)", q:"In a tall building, when hydrostatic pressure at lower hose connections would exceed allowable limits, the standpipe system is commonly:", opts:["Reduced to Class II only","Converted to a manual dry system","Limited to 50 gpm per outlet","Divided into separate pressure zones (with separate risers and/or PRVs)"], correct:3, re:"Excess pressure in tall buildings is controlled by dividing the standpipe into pressure zones served by separate risers, or by applying pressure-regulating valves, keeping outlet pressures within limits. Reference: NFPA 14 high-rise/zoning practice."},
  {id:449, block:5, sec:"Standpipe Design (NFPA 14)", q:"For sizing standpipe risers, NFPA 14 historically required a minimum standpipe (riser) nominal diameter of:", opts:["4 in.","2 in.","3 in.","6 in."], correct:0, re:"Class I and Class III standpipe risers have a minimum nominal size; for hydraulically designed Class I/III systems NFPA 14 sets a minimum riser size (4 in. minimum was the long-standing baseline for these systems). Reference: NFPA 14 riser sizing."},
  {id:450, block:5, sec:"Standpipe Design (NFPA 14)", q:"A 'wet' standpipe versus a 'dry' standpipe differs in that a wet standpipe:", opts:["Is filled only when the fire department pumps into it","Contains water in the piping at all times","Has no hose valves","Is limited to Class II service"], correct:1, re:"A wet standpipe contains water at all times (typically automatic), giving immediate availability; a dry standpipe contains no water until supplied, common in unheated or manual configurations. Reference: NFPA 14 wet/dry standpipe definitions."},
  {id:451, block:5, sec:"Standpipe Design (NFPA 14)", q:"Hose valves on Class I standpipe systems are required to be:", opts:["1 in. quick-coupling","4 in. only","2 1/2 in. (with reducer permitted in some occupancies)","Threaded garden-hose type"], correct:2, re:"Class I hose valves are 2 1/2 in. connections; a 2 1/2 in. by 1 1/2 in. reducer with cap may be permitted in certain fully sprinklered occupancies. Reference: NFPA 14 hose connection sizing."},
  {id:452, block:5, sec:"NFPA 13 Design Documentation", q:"NFPA 13 working plans (shop drawings) must be drawn to an indicated scale and, among other items, show:", opts:["Only the building address","Only the electrical layout","Only the fire alarm panel location","The point of compass (north arrow), sprinkler locations, and pipe sizes"], correct:3, re:"NFPA 13 requires working plans to a scale showing the north point, full height cross-section, sprinkler types/locations, pipe sizes/lengths, and similar details. Reference: NFPA 13, Plans and Calculations (working plans)."},
  {id:453, block:5, sec:"NFPA 13 Design Documentation", q:"The hydraulic calculation package required by NFPA 13 must include which of the following?", opts:["A summary sheet, detailed worksheets, and a graph sheet","Only a single total flow value","Only the manufacturer's catalog","Only the building permit"], correct:0, re:"NFPA 13 requires hydraulic calculations to consist of a summary sheet, detailed worksheets (node-by-node), and a graph sheet plotting supply versus demand. Reference: NFPA 13 hydraulic calculation forms."},
  {id:454, block:5, sec:"NFPA 13 Design Documentation", q:"The 'design area' in a density/area sprinkler design represents:", opts:["The entire floor area of the building","The hydraulically most demanding area assumed to operate in a fire","Only the area directly under the riser","The area covered by the fire department connection"], correct:1, re:"The design area is the floor area over which sprinklers are assumed to operate simultaneously (the most hydraulically demanding area), used to compute the system demand. Reference: NFPA 13 density/area design."},
  {id:455, block:5, sec:"NFPA 13 Design Documentation", q:"For a Light Hazard occupancy using the density/area method, a commonly cited baseline design point is:", opts:["0.05 gpm/ft^2 over 1,000 ft^2","0.20 gpm/ft^2 over 1,500 ft^2","0.10 gpm/ft^2 over 1,500 ft^2","0.30 gpm/ft^2 over 2,500 ft^2"], correct:2, re:"Light Hazard baseline is approximately 0.10 gpm/ft^2 over a 1,500 ft^2 design area (per the density/area curves used in NFPA 13). Reference: NFPA 13 density/area curves for Light Hazard."},
  {id:456, block:5, sec:"NFPA 13 Design Documentation", q:"For Ordinary Hazard Group 2, a commonly cited baseline density/area design point is:", opts:["0.10 gpm/ft^2 over 1,500 ft^2","0.15 gpm/ft^2 over 1,500 ft^2","0.40 gpm/ft^2 over 3,000 ft^2","0.20 gpm/ft^2 over 1,500 ft^2"], correct:3, re:"Ordinary Hazard Group 2 baseline is approximately 0.20 gpm/ft^2 over 1,500 ft^2; Group 1 is about 0.15 gpm/ft^2 over 1,500 ft^2. Reference: NFPA 13 density/area curves."},
  {id:457, block:5, sec:"NFPA 13 Design Documentation", q:"On the density/area curves, increasing the assumed design AREA generally allows the required DENSITY to:", opts:["Decrease","Increase","Stay exactly the same","Become zero"], correct:0, re:"The density/area curves slope so that choosing a larger design area permits a lower density (and vice versa); the designer selects a point on the curve. Reference: NFPA 13 density/area design curves."},
  {id:458, block:5, sec:"NFPA 13 Design Documentation", q:"The hydraulic design information sign (placard) required by NFPA 13 at the riser must state:", opts:["The building owner's phone number","The design density, design area, and required flow/pressure at the base of the riser","The sprinkler manufacturer's warranty","The fire alarm zone list"], correct:1, re:"NFPA 13 requires a permanently marked hydraulic design information sign listing location of the design area, density, occupancy classification, and the required flow and pressure (demand) at the base of the riser, plus hose allowance. Reference: NFPA 13 identification/placard requirements."},
  {id:459, block:5, sec:"NFPA 13 Design Documentation", q:"When sizing pipe by the pipe schedule method (where permitted), the designer determines pipe sizes based on:", opts:["A hydraulic calculation at each node","The fire pump rating","The number of sprinklers served by each pipe and the hazard classification table","The standpipe demand"], correct:2, re:"The pipe schedule method assigns pipe sizes from tables based on the number of sprinklers supplied and hazard class; it is allowed only for limited existing/light and ordinary hazard situations under NFPA 13. Reference: NFPA 13 pipe schedule method."},
  {id:460, block:5, sec:"NFPA 13 Design Documentation", q:"NFPA 13 requires hydraulic calculations to extend to:", opts:["The most remote sprinkler only","The base of the riser only","The fire alarm control unit","The effective point of the water supply where characteristics are known"], correct:3, re:"Calculations must extend from the design area back to the effective point of supply where the supply characteristics are known, so demand can be compared to supply. Reference: NFPA 13 hydraulic calculation procedures."},
  {id:461, block:5, sec:"NFPA 13 Design Documentation", q:"At a hydraulic junction (where flows combine), NFPA 13 requires the pressures from the converging paths to balance within:", opts:["0.5 psi","2 psi","5 psi","10 psi"], correct:0, re:"At junction points, the calculated pressures from the merging branches must balance within 0.5 psi; the higher pressure governs and flows are adjusted accordingly. Reference: NFPA 13 hydraulic calculation balancing rule."},
  {id:462, block:5, sec:"NFPA 13 Design Documentation", q:"A 'hose stream allowance' is added to the sprinkler demand in hydraulic calculations to account for:", opts:["Leakage in the underground main","Water used by fire department hoses during a fire","The jockey pump flow","Backflow preventer friction"], correct:1, re:"The hose stream (inside/outside hose) allowance is added at the appropriate point to reserve flow for manual firefighting hoses operating simultaneously with sprinklers. Reference: NFPA 13 hose stream allowance and water supply duration tables."},
  {id:463, block:5, sec:"NFPA 13 Design Documentation", q:"The total water supply duration and hose allowance required for a given occupancy are taken from:", opts:["The fire pump nameplate","The standpipe FDC sign","NFPA 13 tables based on hazard classification","The electrician's load schedule"], correct:2, re:"NFPA 13 provides tables of required minimum operating (supply) duration and inside/outside hose allowance keyed to the hazard classification used in the density/area method. Reference: NFPA 13 water supply requirement tables."},
  {id:464, block:5, sec:"NFPA 13 Design Documentation", q:"On working plans, the relative ELEVATIONS of sprinklers, junction points, and supply/reference points must be shown because they:", opts:["Affect the aesthetic layout only","Determine the paint color","Are required only for dry systems","Are needed to compute elevation pressure in the hydraulic calculations"], correct:3, re:"Elevation data are required so the calculation can add/subtract elevation pressure (0.433 psi/ft) at each point; NFPA 13 requires relative elevations on the plans. Reference: NFPA 13 working plan content."},
  {id:465, block:5, sec:"NFPA 13 Design Documentation", q:"Which item is NOT typically required content on NFPA 13 working plans?", opts:["The detailed payroll of the installing contractor","Sprinkler temperature ratings and locations","Pipe sizes, lengths, and types of fittings","Point of connection to the water supply"], correct:0, re:"Working plans must show sprinkler types/ratings, pipe sizing and fittings, and the supply connection; the contractor's payroll is not a plan requirement. Reference: NFPA 13 working plan content list."},
  {id:466, block:5, sec:"NFPA 13 Design Documentation", q:"The 'point of design' (most demanding sprinkler) selected within the design area is generally the sprinkler that is:", opts:["Closest to the riser","Hydraulically most remote (requiring the most pressure)","Largest orifice regardless of location","At the lowest elevation"], correct:1, re:"The design begins at the hydraulically most remote/most demanding sprinkler in the design area and works back toward the supply, ensuring every sprinkler in the area meets minimum density. Reference: NFPA 13 hydraulic design procedure."},
  {id:467, block:5, sec:"NFPA 13 Design Documentation", q:"A sprinkler's K-factor is used in calculations to relate:", opts:["Pipe diameter to length","Temperature rating to color","Discharge flow (Q) to pressure (P) via Q = K x sqrt(P)","Elevation to friction loss"], correct:2, re:"Discharge from a sprinkler is Q = K x sqrt(P), where K is the listed discharge coefficient; it converts the calculated pressure at the sprinkler into a flow. Reference: NFPA 13 / sprinkler discharge characteristics."},
  {id:468, block:5, sec:"NFPA 13 Design Documentation", q:"The minimum operating pressure for a standard spray sprinkler under NFPA 13 is generally not less than:", opts:["3 psi","15 psi","30 psi","7 psi"], correct:3, re:"NFPA 13 requires a minimum operating pressure of 7 psi for standard spray sprinklers (some specialty/listed sprinklers have higher minimums per their listing). Reference: NFPA 13 minimum operating pressure."},
  {id:469, block:5, sec:"Plan Submittal & Approval", q:"In fire protection codes, 'AHJ' stands for:", opts:["Authority Having Jurisdiction","Approved Hydraulic Junction","Annual Hazard Judgment","Automatic Hose Junction"], correct:0, re:"AHJ means the Authority Having Jurisdiction: the organization, office, or individual responsible for enforcing code requirements and approving equipment, installations, and procedures. Reference: NFPA definitions (e.g., NFPA 13/14/20)."},
  {id:470, block:5, sec:"Plan Submittal & Approval", q:"Before installation begins, NFPA 13 requires that working plans be:", opts:["Filed only after the system is installed","Submitted to the AHJ for review and approval","Kept confidential from the AHJ","Submitted only to the sprinkler manufacturer"], correct:1, re:"NFPA 13 requires working plans (and calculations) to be submitted to and approved by the AHJ prior to installation. Reference: NFPA 13 plan submittal requirements."},
  {id:471, block:5, sec:"Plan Submittal & Approval", q:"If a designer wishes to use a method or arrangement not specifically addressed by the code, the typical path is to:", opts:["Proceed without notice","Ignore the code entirely","Submit it to the AHJ for review/approval as an equivalency or alternative means","Use it only on weekends"], correct:2, re:"Codes permit alternative materials/methods that the AHJ may approve when shown equivalent in quality, strength, safety, and performance. The proposal is submitted to the AHJ. Reference: NFPA equivalency provisions; model fire/building codes."},
  {id:472, block:5, sec:"Plan Submittal & Approval", q:"The term 'listed' in NFPA standards means the equipment or material is:", opts:["Merely advertised by a manufacturer","Painted red","Available in any hardware store","Included on a list published by an organization acceptable to the AHJ that performs evaluation"], correct:3, re:"'Listed' means published in a list by an organization (acceptable to the AHJ) concerned with product evaluation, indicating the equipment meets appropriate standards or has been tested for a specified use. Reference: NFPA definitions."},
  {id:473, block:5, sec:"Plan Submittal & Approval", q:"The term 'approved' as used throughout NFPA codes specifically means:", opts:["Acceptable to the Authority Having Jurisdiction","Approved by the equipment manufacturer","Listed by Underwriters Laboratories only","Permitted by the building owner"], correct:0, re:"'Approved' is defined in NFPA codes as acceptable to the Authority Having Jurisdiction. Reference: NFPA definitions (NFPA 13/14/20)."},
  {id:474, block:5, sec:"Plan Submittal & Approval", q:"Hydraulic calculations submitted with plans are typically required to be:", opts:["Handwritten only","Signed/sealed or prepared by a qualified designer and consistent with the working plans","Submitted without the supply test data","Limited to one page regardless of system size"], correct:1, re:"Calculations must be prepared by qualified personnel, agree with the working plans, and include the supporting water supply information; many AHJs require a designer's certification or PE seal. Reference: NFPA 13 plans/calculations; AHJ submittal rules."},
  {id:475, block:5, sec:"Plan Submittal & Approval", q:"A primary reason the AHJ reviews and approves fire sprinkler plans before construction is to:", opts:["Set the contractor's price","Choose the paint color of the pipe","Verify the design meets applicable code requirements before work proceeds","Select the building's furniture"], correct:2, re:"Plan review confirms the proposed design complies with the adopted codes/standards (NFPA 13/14/etc.) before installation, catching deficiencies early. Reference: model fire code plan review provisions; NFPA 13."},
  {id:476, block:5, sec:"Plan Submittal & Approval", q:"The 'occupancy/hazard classification' established on the plans is important to the AHJ review because it determines:", opts:["The paint specification","The number of parking spaces","The elevator capacity","The required design density, design area, and water supply duration"], correct:3, re:"Hazard classification (Light, Ordinary, Extra, or storage) drives the density/area design point and the water supply duration/hose allowance, so the AHJ verifies it carefully. Reference: NFPA 13 occupancy classification."},
  {id:477, block:5, sec:"Plan Submittal & Approval", q:"Which document set is normally submitted for fire sprinkler plan review?", opts:["Working (shop) drawings, hydraulic calculations, and the water supply (flow test) information","Only a floor plan","Only the manufacturer's price list","Only the certificate of occupancy"], correct:0, re:"A complete submittal includes working/shop drawings, the supporting hydraulic calculations, and the water supply/flow test data used in the design. Reference: NFPA 13 plans and calculations submittal."},
  {id:478, block:5, sec:"Plan Submittal & Approval", q:"When the adopted edition of an NFPA standard conflicts with a designer's preferred newer edition, the design must comply with:", opts:["Whichever edition the designer prefers","The edition adopted/enforced by the AHJ (the jurisdiction)","The oldest edition ever published","No edition at all"], correct:1, re:"The legally adopted edition referenced by the jurisdiction's code governs; the AHJ enforces that edition unless it formally permits another. Reference: model code adoption practice; NFPA scope/AHJ."},
  {id:479, block:5, sec:"Plan Submittal & Approval", q:"If a field condition requires deviating from approved plans during installation, the proper action is to:", opts:["Make the change quietly and not document it","Stop all work permanently","Obtain approval for the revision (revised plans) from the AHJ before or as required","Remove the sprinkler system"], correct:2, re:"Changes from approved plans generally require revised drawings/approval so the installed system still complies and the record reflects as-built conditions. Reference: NFPA 13/AHJ plan-revision practice."},
  {id:480, block:5, sec:"Plan Submittal & Approval", q:"'Shall' versus 'should' in NFPA standards: the word 'shall' indicates a requirement that is:", opts:["Optional/advisory","A recommendation only","Applicable to existing systems only","Mandatory"], correct:3, re:"In NFPA documents, 'shall' indicates a mandatory requirement; 'should' indicates a recommendation or advisory provision. Reference: NFPA Manual of Style; NFPA standards usage."},
  {id:481, block:5, sec:"Plan Submittal & Approval", q:"A water supply 'flow test' submitted with plans should typically be no older than:", opts:["12 months (per common AHJ/NFPA 20 practice)","1 month","5 years","There is no time limit"], correct:0, re:"Flow test data used for design are commonly required to be within 12 months (NFPA 20 requires within 12 months for pump sizing); many AHJs apply similar limits to sprinkler submittals to reflect current supply. Reference: NFPA 20; AHJ submittal practice."},
  {id:482, block:5, sec:"Plan Submittal & Approval", q:"The party responsible for ensuring the installed system matches the APPROVED plans is primarily the:", opts:["Building's tenants","Installing contractor (with AHJ verification at inspection)","Water utility","Furniture supplier"], correct:1, re:"The installing contractor installs per the approved plans and certifies the work; the AHJ verifies compliance at inspection/acceptance. Reference: NFPA 13 installation/acceptance responsibilities."},
  {id:483, block:5, sec:"Plan Submittal & Approval", q:"Where a building official adopts the International Fire Code or NFPA 1/101, the referenced sprinkler installation standard is generally:", opts:["NFPA 70 (National Electrical Code)","NFPA 72 (fire alarm)","NFPA 13 (and NFPA 13R/13D for residential)","NFPA 25 (inspection/testing)"], correct:2, re:"Sprinkler installation is governed by NFPA 13 (with NFPA 13R for low-rise residential and 13D for one- and two-family dwellings); NFPA 25 covers ITM and NFPA 72 covers fire alarm. Reference: model code references to NFPA 13."},
  {id:484, block:5, sec:"Plan Submittal & Approval", q:"An 'equivalency' clause in an NFPA standard allows the AHJ to accept an alternative provided it offers:", opts:["A lower level of safety to save cost","Faster installation regardless of performance","Only aesthetic improvement","Equivalent quality, strength, fire resistance, effectiveness, durability, and safety"], correct:3, re:"Equivalency provisions let the AHJ approve alternative materials/methods/devices that demonstrate equivalence in quality, strength, fire resistance, effectiveness, durability, and safety. Reference: NFPA equivalency clauses (e.g., NFPA 13)."},
  {id:485, block:5, sec:"Acceptance & Material/Test Certificate", q:"New aboveground sprinkler piping must be hydrostatically tested at not less than:", opts:["200 psi for 2 hours (or 50 psi above working pressure if that exceeds 150 psi)","100 psi for 1 hour","150 psi for 30 minutes","300 psi for 24 hours"], correct:0, re:"NFPA 13 requires a hydrostatic test at 200 psi for 2 hours, or 50 psi above the maximum system working pressure when that pressure exceeds 150 psi, held for 2 hours. Reference: NFPA 13 acceptance/hydrostatic testing."},
  {id:486, block:5, sec:"Acceptance & Material/Test Certificate", q:"During the 2-hour hydrostatic test of aboveground sprinkler piping, the acceptance criterion is essentially:", opts:["A 20 psi drop is acceptable","No leakage / no drop in gauge pressure (no visible leakage) over the 2 hours","A 50% pressure drop is acceptable","Any pressure reading is acceptable"], correct:1, re:"The test passes only if there is no visible leakage and no drop in gauge pressure over the 2-hour period (essentially zero loss). Reference: NFPA 13 hydrostatic test acceptance criteria."},
  {id:487, block:5, sec:"Acceptance & Material/Test Certificate", q:"The form documenting that a new sprinkler/standpipe system was installed and tested per the standard is the:", opts:["Building Energy Disclosure","Manufacturer's Warranty Card","Contractor's Material and Test Certificate","Elevator Inspection Tag"], correct:2, re:"The Contractor's Material and Test Certificate (for aboveground and for underground piping) records the materials installed and the tests performed and is required to be completed and signed at acceptance. Reference: NFPA 13/NFPA 24 certificate forms."},
  {id:488, block:5, sec:"Acceptance & Material/Test Certificate", q:"The Contractor's Material and Test Certificate is completed and signed by the:", opts:["Building's insurance broker","Water utility billing department","Architect of record only","Installing contractor (and signed for the property owner/AHJ as applicable)"], correct:3, re:"The installing contractor completes and signs the certificate, documenting the system was installed and tested in accordance with the standard; it is provided to the owner and AHJ. Reference: NFPA 13 acceptance documentation."},
  {id:489, block:5, sec:"Acceptance & Material/Test Certificate", q:"Underground supply piping (NFPA 24) must be FLUSHED before connection to aboveground piping primarily to:", opts:["Remove debris, rocks, and foreign material that could obstruct sprinklers","Cool the pipe","Add chlorine for taste","Increase the C-factor permanently"], correct:0, re:"Flushing removes construction debris and foreign material from the underground main so it cannot enter and plug sprinklers or valves; flushing flow rates are specified by pipe size. Reference: NFPA 24 flushing requirements; recorded on the underground certificate."},
  {id:490, block:5, sec:"Acceptance & Material/Test Certificate", q:"Underground fire service mains (NFPA 24) are hydrostatically tested at:", opts:["100 psi or 25 psi above working pressure","200 psi or 50 psi above the maximum system working pressure (whichever is greater), for 2 hours","300 psi for 8 hours","No hydrostatic test is required"], correct:1, re:"NFPA 24 requires underground mains be tested at 200 psi, or 50 psi above the maximum system working pressure when greater, for 2 hours, with leakage limited to the allowable amount. Reference: NFPA 24 hydrostatic test."},
  {id:491, block:5, sec:"Acceptance & Material/Test Certificate", q:"Unlike aboveground sprinkler piping (which allows essentially no leakage), buried/underground piping is permitted a small amount of leakage during its hydrostatic test because:", opts:["The pipe is weaker","Underground pipe is never tested","Allowance is made for minor seepage at joints in buried pipe, within a calculated limit","Leakage improves flow"], correct:2, re:"NFPA 24 permits a limited, calculated leakage allowance for underground joints during the 2-hour test, whereas aboveground sprinkler piping must show no leakage/no pressure drop. Reference: NFPA 24 allowable leakage formula."},
  {id:492, block:5, sec:"Acceptance & Material/Test Certificate", q:"A 'main drain test' performed at acceptance is used to verify:", opts:["The fire alarm sound level","The paint thickness","The elevator speed","That the water supply is unobstructed by comparing static and residual (flowing) pressures"], correct:3, re:"Opening the main drain and comparing static to flowing pressure verifies the supply control valves are open and the supply is unobstructed; the readings are recorded and used as a baseline. Reference: NFPA 13/NFPA 25 main drain test."},
  {id:493, block:5, sec:"Acceptance & Material/Test Certificate", q:"At acceptance of a waterflow alarm, the system is flow-tested to confirm the alarm activates within:", opts:["90 seconds of flow at the alarm-initiating rate","10 minutes of flow","1 hour of flow","No time requirement"], correct:0, re:"Waterflow alarm devices must initiate an alarm within 90 seconds of flow equal to or greater than the smallest sprinkler's flow; verified at acceptance. Reference: NFPA 13 waterflow alarm test."},
  {id:494, block:5, sec:"Acceptance & Material/Test Certificate", q:"The Contractor's Material and Test Certificate records which of the following?", opts:["Only the building's square footage","System type, materials used, test pressures/durations, flushing, and alarm test results","Only the owner's email address","Only the paint color"], correct:1, re:"The certificate documents the type of system, piping/component materials, hydrostatic test pressure and duration, flushing, alarm/operational tests, and signatures. Reference: NFPA 13/24 certificate content."},
  {id:495, block:5, sec:"Acceptance & Material/Test Certificate", q:"A dry-pipe sprinkler system, in addition to the hydrostatic test, also requires an acceptance test for:", opts:["Color uniformity","Elevator interface","An air pressure leakage test (e.g., not more than a specified pressure loss in 24 hours)","Carpet flammability"], correct:2, re:"Dry systems receive a low-pressure air test; NFPA 13 limits the pressure loss over 24 hours (commonly not more than 1.5 psi loss in 24 hours at a specified test pressure) and verifies trip/operation. Reference: NFPA 13 dry-system air test."},
  {id:496, block:5, sec:"Acceptance & Material/Test Certificate", q:"Backflow prevention assemblies installed in the fire service line must, after installation, be:", opts:["Painted black","Removed before acceptance","Left untested","Forward-flow tested at the system demand flow and the assembly tested for proper operation"], correct:3, re:"NFPA 13/24 require a forward-flow test through the backflow assembly at the system demand (to confirm it does not unduly restrict flow) plus the assembly's own operational test. Reference: NFPA 13/24 backflow forward-flow test."},
  {id:497, block:5, sec:"Acceptance & Material/Test Certificate", q:"For a fire pump, the field ACCEPTANCE test demonstrates the installed pump meets its rating by testing at:", opts:["Churn, 100% rated flow, and 150% rated flow, compared to the certified curve","Churn only","Rated flow only","200% of rated flow"], correct:0, re:"The pump acceptance test runs churn, 100%, and 150% points and compares results against the manufacturer's certified shop test curve to confirm performance. Reference: NFPA 20 field acceptance test."},
  {id:498, block:5, sec:"Acceptance & Material/Test Certificate", q:"At fire pump acceptance, the performance at each test point should generally be at least what percentage of the certified (shop) curve / nameplate values?", opts:["50%","95%","75%","140%"], correct:1, re:"Field test performance at each point should be not less than 95% of the pump's rated/certified (shop) curve values for acceptance. Reference: NFPA 20/NFPA 25 acceptance criteria."},
  {id:499, block:5, sec:"Acceptance & Material/Test Certificate", q:"Which test confirms an automatic standpipe system delivers the required pressure and flow at the most remote outlet?", opts:["A paint adhesion test","An elevator recall test","A flow test at the hydraulically most remote hose connection","A smoke detector sensitivity test"], correct:2, re:"A standpipe flow test at the hydraulically most remote 2 1/2 in. outlet verifies the required residual pressure (100 psi for Class I/III) at the required flow (500 gpm) is achieved. Reference: NFPA 14 acceptance flow test."},
  {id:500, block:5, sec:"Acceptance & Material/Test Certificate", q:"The completed Contractor's Material and Test Certificate is ultimately provided to the property owner and made available to the AHJ so that it can serve as:", opts:["A marketing brochure","A substitute for the working plans","A replacement for periodic NFPA 25 inspections","The permanent record that the system was installed and tested in accordance with the standard"], correct:3, re:"The certificate is the permanent acceptance record verifying compliant installation and successful testing; it is retained by the owner and provided to the AHJ, but does not replace ongoing NFPA 25 inspection, testing, and maintenance. Reference: NFPA 13/24 acceptance documentation; NFPA 25 ITM."}
];
